/** ============================================================
 * QAcademy — Teacher Assess WebApp (Phase 0 Skeleton) — FILE ONE
 * - Health check
 * - DB ping (sanity)
 * - teacher.verify (Auth verify + role gate + teachers.active)
 *
 * ============================================================ */

const BUILD = 'teacher-assess-v0.0-phase0-2026-02-13';

// === CONFIG: EDIT THESE ===
const DB_ID = '1e-kjc_1OuK-75Dx9jAMG1RhJvJ2U6F6Na4VXCYKDutI';

const AUTH_URL = 'https://script.google.com/macros/s/AKfycbxaChsaqn6Or1G-SHqsXla1DdgYdWXzXLfs9GVs_7xrxDeYwjT0OhvWlYUsJtpMU8so/exec';

// Tabs (must match exactly)
const SH_TEACHERS        = 'teachers';
const SH_TEACHER_QUIZZES = 'teacher_quizzes';
const SH_BANK_ITEMS      = 'teacher_bank_items';
const SH_QUIZ_ITEMS      = 'teacher_quiz_items';
const SH_ATTEMPTS        = 'teacher_attempts';
const SH_CLASSES       = 'teacher_classes';
const SH_CLASS_MEMBERS = 'teacher_class_members';
const SH_QUIZ_CLASSES  = 'teacher_quiz_classes';
const SH_LIBRARY_COURSES = 'library_courses';




// Role gate: MODERATOR and ADMIN are treated as "teacher/staff"
const TEACHER_ROLES = ['MODERATOR', 'ADMIN'];

// ---- Bank metadata + validation helpers ----
const DIFFICULTY_ALLOWED = ['Easy', 'Moderate', 'Hard'];

function _normalizeDifficulty_(v) {
  const s = String(v == null ? '' : v).trim();
  if (!s) return ''; // blank allowed
  const t = s.toLowerCase();

  if (t === 'easy') return 'Easy';
  if (t === 'moderate' || t === 'medium') return 'Moderate';
  if (t === 'hard' || t === 'difficult') return 'Hard';

  return null; // invalid non-blank
}

function _sortCaseInsensitive_(arr) {
  return (arr || []).slice().sort((a,b) =>
    String(a||'').toLowerCase().localeCompare(String(b||'').toLowerCase())
  );
}


/* ========================= * Router  ========================= */

function doGet(e) {
  const p = (e && e.parameter) || {};
  const action = String(p.action || 'health').trim().toLowerCase();

  if (action === 'health') {
    return _json({ ok: true, service: 'QAcademyTeacherAssess', build: BUILD, now: _iso(new Date()) });
  }

  if (action === 'db.ping') {
    return _handleDbPing_();
  }

  return _json({ ok: false, error: 'unknown_action' }, 400);
}

function doPost(e) {
  try {
    const p = (e && e.parameter) || {};
    let body = {};
    try { body = JSON.parse((e.postData && e.postData.contents) || '{}'); } catch (_) { body = {}; }

    const action = String(p.action || body.action || '').trim().toLowerCase();
    if (!action) return _json({ ok: false, error: 'missing_action' }, 400);

    // common fields
    const token = String(p.token || body.token || '').trim();

    if (action === 'teacher.verify') {
      if (!token) return _json({ ok: false, error: 'missing_token' }, 400);
      return _handleTeacherVerify_({ token });
    }


    if (action === 'teacher.request_access') {
      if (!token) return _json({ ok:false, error:'missing_token' }, 400);
      return _handleTeacherRequestAccess_({ token, body, p });
    }

    // ===== Teacher Admin (Approve/Disable) =====
    if (action === 'teacher.admin.requests.list') {
      if (!token) return _json({ ok:false, error:'missing_token' }, 400);
      return _handleTeacherAdminRequestsList_({ token, body, p });
    }

    if (action === 'teacher.admin.teacher.set') {
      if (!token) return _json({ ok:false, error:'missing_token' }, 400);
      return _handleTeacherAdminTeacherSet_({ token, body, p });
    }

    if (action === 'db.ping') {
      return _handleDbPing_();
    }

    // ===== Teacher Bank (Phase 1) =====
    if (action === 'bank.item.create') {
      return _handleBankItemCreate_({ token, body, p });
    }
if (action === 'bank.items.bulkcreate') {
  return _handleBankItemsBulkCreate_({ token, body, p });
}

    if (action === 'bank.items.list') {
      return _handleBankItemsList_({ token, body, p });
    }

    if (action === 'bank.item.get') {
  return _handleBankItemGet_({ token, body, p });
}


    if (action === 'bank.item.update') {
      return _handleBankItemUpdate_({ token, body, p });
    }

    if (action === 'bank.item.delete') {
      return _handleBankItemDelete_({ token, body, p });
    }

        if (action === 'bank.meta') {
      return _handleBankMeta_({ token, body, p });
    }
// ===== Alpha Library (Read-only) =====
if (action === 'library.courses.list') {
  return _handleLibraryCoursesList_({ token, body, p });
}
if (action === 'library.items.list') {
  return _handleLibraryItemsList_({ token, body, p });
}

    // ===== Teacher Quizzes (Phase 2) =====
    if (action === 'teacher.quiz.create') {
      return _handleTeacherQuizCreate_({ token, body, p });
    }

    if (action === 'teacher.quiz.update') {
      return _handleTeacherQuizUpdate_({ token, body, p });
    }

    if (action === 'teacher.quiz.get') {
      return _handleTeacherQuizGet_({ token, body, p });
    }

    if (action === 'teacher.quizzes.list') {
      return _handleTeacherQuizzesList_({ token, body, p });
    }

    if (action === 'teacher.quiz.access_code.regenerate') {
      return _handleTeacherQuizAccessCodeRegenerate_({ token, body, p });
    }

    if (action === 'teacher.quiz.archive') {
      return _handleTeacherQuizArchive_({ token, body, p });
    }

    if (action === 'teacher.quiz.publish') {
      return _handleTeacherQuizPublish_({ token, body, p });
    }

    if (action === 'teacher.quiz.items.list') {
      return _handleTeacherQuizItemsList_({ token, body, p });
    }
    if (action === 'teacher.quiz.clone') {
      return _handleTeacherQuizClone_({ token, body, p });
    }

    if (action === 'teacher.quiz.draft.preview') {
  return _handleTeacherQuizDraftPreview_({ token, body, p });
}
        // ===== Teacher Classes + Membership (Phase 3) =====
    if (action === 'teacher.class.create') {
      return _handleTeacherClassCreate_({ token, body, p });
    }
    if (action === 'teacher.classes.list') {
      return _handleTeacherClassesList_({ token, body, p });
    }
    if (action === 'teacher.class.get') {
  return _handleTeacherClassGet_({ token, body, p });
}

    if (action === 'teacher.class.update') {
      return _handleTeacherClassUpdate_({ token, body, p });
    }
    if (action === 'teacher.class.join_code.regenerate') {
      return _handleTeacherClassJoinCodeRegenerate_({ token, body, p });
    }
    if (action === 'teacher.class.members.list') {
      return _handleTeacherClassMembersList_({ token, body, p });
    }
    if (action === 'teacher.class.member.remove') {
      return _handleTeacherClassMemberRemove_({ token, body, p });
    }

    // ===== Teacher Quiz ↔ Class Linking (Phase 3) =====
    if (action === 'teacher.quiz.class.add') {
      return _handleTeacherQuizClassAdd_({ token, body, p });
    }
    if (action === 'teacher.quiz.class.remove') {
      return _handleTeacherQuizClassRemove_({ token, body, p });
    }
    if (action === 'teacher.quiz.classes.list') {
      return _handleTeacherQuizClassesList_({ token, body, p });
    }
    if (action === 'teacher.quiz.class.set') {
      return _handleTeacherQuizClassSet_({ token, body, p });
    }

    // ===== Candidate (Student) (Phase 3) =====
    if (action === 'candidate.class.join') {
      return _handleCandidateClassJoin_({ token, body, p });
    }
    if (action === 'candidate.classes.list') {
      return _handleCandidateClassesList_({ token, body, p });
    }
    if (action === 'candidate.quizzes.list') {
      return _handleCandidateQuizzesList_({ token, body, p });
    }
if (action === 'candidate.quiz.attempts.list') return _handleCandidateQuizAttemptsList_({ token, body, p });

    if (action === 'candidate.class.get') {
  return _handleCandidateClassGet_({ token, body, p });
}
if (action === 'candidate.class.profile.update') {
  return _handleCandidateClassProfileUpdate_({ token, body, p });
}

// ===== Teacher Attempts  (Phase 4) =====
 if (action === 'candidate.quiz.get') return _handleCandidateQuizGet_({ token, body, p });
 if (action === 'candidate.attempt.start') return _handleCandidateAttemptStart_({ token, body, p });
 if (action === 'candidate.attempt.get') return _handleCandidateAttemptGet_({ token, body, p });
 if (action === 'candidate.attempt.save') return _handleCandidateAttemptSave_({ token, body, p });
 if (action === 'candidate.attempt.submit') return _handleCandidateAttemptSubmit_({ token, body, p });

 // ===== Candidate Results/Review (NEW) =====
if (action === 'candidate.attempt.results.get') return _handleCandidateAttemptResultsGet_({ token, body, p });
if (action === 'candidate.attempt.review.get')  return _handleCandidateAttemptReviewGet_({ token, body, p });

 // optional teacher-side
 if (action === 'teacher.attempts.list') return _handleTeacherAttemptsList_({ token, body, p });
 if (action === 'teacher.attempt.get') return _handleTeacherAttemptGet_({ token, body, p });

if (action === 'teacher.quiz.release_results') {
  return _handleTeacherQuizReleaseResults_({ token, body, p });
}

// ===== Teacher Results / Reporting (File 3) =====
if (action === 'teacher.results.list')    return _handleTeacherResultsList_({ token, body, p });
if (action === 'teacher.results.summary') return _handleTeacherResultsSummary_({ token, body, p });
if (action === 'teacher.results.items')   return _handleTeacherResultsItems_({ token, body, p });
if (action === 'teacher.class.quizzes.list') {
  return _handleTeacherClassQuizzesList_({ token, body, p });
}

// Optional (premium later)
// if (action === 'teacher.results.export.csv') return _handleTeacherResultsExportCsv_({ token, body, p });

    return _json({ ok: false, error: 'unknown_action' }, 400);
  } catch (err) {
    return _json({ ok: false, error: String(err && (err.stack || err.message) || err) }, 500);
  }
}

/* ========================= Handlers  ========================= */

function _handleDbPing_() {
  const ss = SpreadsheetApp.openById(DB_ID);

  const tabs = [
    SH_TEACHERS,
    SH_TEACHER_QUIZZES,
    SH_BANK_ITEMS,
    SH_QUIZ_ITEMS,
    SH_ATTEMPTS,
    SH_CLASSES,
    SH_CLASS_MEMBERS,
    SH_QUIZ_CLASSES,
    SH_LIBRARY_COURSES
  ];


  const out = tabs.map(name => {
    const sh = ss.getSheetByName(name);
    if (!sh) return { tab: name, ok: false, error: 'missing_tab' };

    const lastRow = sh.getLastRow();
    const lastCol = sh.getLastColumn();
    const headers = (lastCol > 0)
      ? sh.getRange(1, 1, 1, lastCol).getValues()[0].map(x => String(x || '').trim())
      : [];

    return {
      tab: name,
      ok: true,
      rows: Math.max(0, lastRow - 1),
      cols: lastCol,
      header_preview: headers.slice(0, 12)
    };
  });

  return _json({
    ok: true,
    service: 'QAcademyTeacherAssess',
    build: BUILD,
    db_id: DB_ID,
    tabs: out
  });
}

function _handleTeacherVerify_({ token }) {
  // 1) Verify via central Auth
  const auth = _authVerify_(token);
  if (!auth.ok) {
    return _json({
      ok: false,
      error: 'auth_verify_failed',
      detail: auth.error || 'invalid_token'
    }, 401);
  }

  const user = auth.user || {};
  const roleUpper = String(user.role || '').trim().toUpperCase();
  const userId = String(user.user_id || '').trim();

  if (!userId) {
    return _json({ ok: false, error: 'auth_missing_user_id' }, 500);
  }

  // 2) Teacher approval gate (teachers.active must be TRUE)
  // IMPORTANT: we no longer rely on Auth roles for teacher access.
  const teacherRow = _getTeacherRowById_(userId);

  if (!teacherRow.found) {
    return _json({
      ok: false,
      error: 'teacher_not_registered',
      teacher_id: userId
    }, 403);
  }

  if (!teacherRow.active) {
    return _json({
      ok: false,
      error: 'teacher_not_approved',
      teacher_id: userId
    }, 403);
  }

  return _json({
    ok: true,
    teacher_ok: true,
    build: BUILD,
    teacher: {
      teacher_id: userId,
      role: roleUpper,
      plan_type: teacherRow.plan_type || 'FREE'
    },
    user: {
      user_id: userId,
      name: user.name || '',
      email: user.email || '',
      role: roleUpper
    }
  });
}


/**
 * teacher.request_access
 * - Any authenticated user can request teacher access.
 * - Upserts a row in TA DB -> teachers tab.
 * - Does NOT grant access. Admin must approve (active=TRUE, request_status=APPROVED).
 *
 * Input (POST):
 *  - token (required)
 *  - request_note (optional)
 *  - phone_number (optional)
 *  - organisation (optional)
 *
 * Output:
 *  - ok, teacher_id, request_status, active, message
 */
function _handleTeacherRequestAccess_({ token, body, p }) {
  // 1) Verify via central Auth
  const auth = _authVerify_(token);
  if (!auth.ok) {
    return _json({ ok:false, error:'auth_verify_failed', detail: auth.error || 'invalid_token' }, 401);
  }

  const user = auth.user || {};
  const teacherId = String(user.user_id || '').trim();
  const email = String(user.email || '').trim().toLowerCase();
  const displayName =
    String(user.name || '').trim() ||
    String(user.username || '').trim() ||
    'QAcademy User';

  if (!teacherId) return _json({ ok:false, error:'auth_missing_user_id' }, 500);
  if (!email) return _json({ ok:false, error:'missing_email' }, 400);

  // 2) Optional inputs (small caps to avoid huge cell values)
  const getAny = (k) => (p && (k in p)) ? p[k] : ((body && (k in body)) ? body[k] : undefined);

  let request_note = String(getAny('request_note') || '').trim();
  if (request_note.length > 600) request_note = request_note.slice(0, 600);

  let phone_number = String(getAny('phone_number') || '').trim();
  if (phone_number.length > 40) phone_number = phone_number.slice(0, 40);

  let organisation = String(getAny('organisation') || '').trim();
  if (organisation.length > 80) organisation = organisation.slice(0, 80);

  const nowIso = _iso(new Date());

  // 3) Upsert into teachers tab (lock to avoid double-click duplicates)
  const outcome = _withScriptLock_(() => {
    const ss = SpreadsheetApp.openById(DB_ID);
    const sh = ss.getSheetByName(SH_TEACHERS);
    if (!sh) return { ok:false, _http:500, error:'missing_teachers_tab', tab: SH_TEACHERS };

    const headers = _getHeaders_(sh);
    const required = ['teacher_id','active','plan_type','created_at','display_name','email','request_status','requested_at','updated_at','request_note','request_count','last_request_at','phone_number','organisation','role_requested'];

    for (let i = 0; i < required.length; i++) {
      if (headers.indexOf(required[i]) === -1) {
        return { ok:false, _http:500, error:'missing_header', header: required[i], tab: SH_TEACHERS };
      }
    }

    const rowIndex = _findTeacherRowIndexById_(sh, headers, teacherId);

    const cache = CacheService.getScriptCache();
    const cacheKey = 'teacherRow:' + teacherId;

    // helper: decide whether to email (anti-spam: once per 6h for repeat clicks)
    const shouldEmailAgain = (existingLastRequestAt) => {
      const lastMs = _parseIsoMs_(String(existingLastRequestAt || '').trim()) || 0;
      if (!lastMs) return true;
      return (Date.now() - lastMs) > (6 * 60 * 60 * 1000);
    };

    if (rowIndex > 0) {
      const existing = _readObjAtRow_(sh, headers, rowIndex);

      const isActive = _toBool_(existing.active);
      if (isActive) {
        try { cache.remove(cacheKey); } catch(_) {}
        return {
          ok: true,
          teacher_id: teacherId,
          active: true,
          request_status: String(existing.request_status || 'APPROVED').trim() || 'APPROVED',
          message: 'already_teacher',
          _send_request_received_email: false,
          _email_meta: {}
        };
      }

      const prevCount = parseInt(String(existing.request_count || '0').trim(), 10);
      const nextCount = (isNaN(prevCount) ? 0 : prevCount) + 1;

      const createdAt = String(existing.created_at || '').trim() || nowIso;

      const patch = {
        display_name: displayName,
        email: email,

        request_status: 'PENDING',
        created_at: createdAt,
        updated_at: nowIso,
        last_request_at: nowIso,
        request_count: String(nextCount),
        role_requested: String(existing.role_requested || '').trim() || 'TEACHER'
      };

      const requestedAt = String(existing.requested_at || '').trim();
      if (!requestedAt) patch.requested_at = nowIso;

      if (request_note) patch.request_note = request_note;
      if (phone_number) patch.phone_number = phone_number;
      if (organisation) patch.organisation = organisation;

      const pt = String(existing.plan_type || '').trim();
      if (!pt) patch.plan_type = 'FREE';

      _updateObjAtRow_(sh, headers, rowIndex, patch);

      try { cache.remove(cacheKey); } catch(_) {}

      const allowEmail = shouldEmailAgain(existing.last_request_at);

      return {
        ok: true,
        teacher_id: teacherId,
        active: false,
        request_status: 'PENDING',
        already_requested: true,
        request_count: String(nextCount),
        message: 'request_updated_pending_approval',
        _send_request_received_email: allowEmail,
        _email_meta: {
          request_count: String(nextCount),
          requested_at: String(existing.requested_at || nowIso).trim() || nowIso
        }
      };
    }

    // No row yet → create a new request row
    const obj = {
      teacher_id: teacherId,
      active: 'FALSE',
      plan_type: 'FREE',
      created_at: nowIso,
      display_name: displayName,
      email: email,

      request_status: 'PENDING',
      requested_at: nowIso,
      updated_at: nowIso,
      request_note: request_note || '',
      request_count: '1',
      last_request_at: nowIso,

      phone_number: phone_number || '',
      organisation: organisation || '',
      role_requested: 'TEACHER'
    };

    _appendObj_(sh, headers, obj);

    try { cache.remove(cacheKey); } catch(_) {}

    return {
      ok: true,
      teacher_id: teacherId,
      active: false,
      request_status: 'PENDING',
      already_requested: false,
      request_count: '1',
      message: 'request_created_pending_approval',
      _send_request_received_email: true,
      _email_meta: { request_count:'1', requested_at: nowIso }
    };
  });

  // If lock returned an error object, convert to JSON response now
  if (!outcome || outcome.ok === false) {
    const code = (outcome && outcome._http) ? outcome._http : 500;
    if (outcome) { delete outcome._http; delete outcome._send_request_received_email; delete outcome._email_meta; }
    return _json(outcome || { ok:false, error:'server_error' }, code);
  }

  // Email (best-effort, never blocks)
  try {
    if (outcome._send_request_received_email) {
      _taSendTeacherRequestReceivedEmail_(user, outcome._email_meta || {});
    }
  } catch(e) {
    Logger.log('TA request received email failed: ' + e);
  }

  // Strip internal fields before returning
  delete outcome._send_request_received_email;
  delete outcome._email_meta;

  return _json(outcome);
}
/**
 * Find teachers row by teacher_id.
 * Returns sheet row index (>=2) or -1.
 */
function _findTeacherRowIndexById_(sh, headers, teacherId) {
  const idxTeacherId = headers.indexOf('teacher_id');
  if (idxTeacherId === -1) throw new Error('Missing header: teacher_id');

  const lastRow = sh.getLastRow();
  if (lastRow < 2) return -1;

  const vals = sh.getRange(2, idxTeacherId + 1, lastRow - 1, 1).getValues();
  const want = String(teacherId || '').trim();

  for (let i = 0; i < vals.length; i++) {
    if (String(vals[i][0] || '').trim() === want) return i + 2;
  }
  return -1;
}


/* =========================
 * Teacher Admin (Approve/Disable + Requests)
 * =========================
 * These endpoints are ADMIN-only (based on Portal Auth user.role).
 *
 * - teacher.admin.requests.list
 * - teacher.admin.teacher.set
 */

// Only these Auth roles can approve teachers (keep strict)
const STAFF_APPROVER_ROLES = ['ADMIN'];

function _requireStaffApprover_({ token }) {
  const auth = _authVerify_(token);
  if (!auth.ok) {
    return { ok:false, code:401, payload:{ ok:false, error:'auth_verify_failed', detail:auth.error || '' } };
  }

  const user = auth.user || {};
  const userId = String(user.user_id || '').trim();
  if (!userId) {
    return { ok:false, code:500, payload:{ ok:false, error:'auth_missing_user_id' } };
  }

  const roleUpper = String(user.role || '').trim().toUpperCase();
  if (STAFF_APPROVER_ROLES.indexOf(roleUpper) === -1) {
    return { ok:false, code:403, payload:{ ok:false, error:'forbidden_not_admin', role: roleUpper } };
  }

  return { ok:true, user_id:userId, role:roleUpper, user };
}

function _getTeacherHeaders_(sh){
  return _getHeaders_(sh);
}

function _teacherObjSafe_(obj){
  // never trust sheet shapes; normalize safely
  obj = obj || {};
  return {
    teacher_id:    String(obj.teacher_id || '').trim(),
    active:        _toBool_(obj.active),
    plan_type:     String(obj.plan_type || '').trim() || 'FREE',
    created_at:    String(obj.created_at || '').trim(),
    display_name:  String(obj.display_name || '').trim(),
    email:         String(obj.email || '').trim(),
    requested_at:  String(obj.requested_at || '').trim(),
    updated_at:    String(obj.updated_at || '').trim(),
    request_count: String(obj.request_count || '').trim(),
    request_note:  String(obj.request_note || '').trim(),
    phone_number:  String(obj.phone_number || '').trim(),
    organisation:  String(obj.organisation || '').trim()
  };
}

/**
 * teacher.admin.requests.list
 * Default: pending_only = true (active == false)
 * Optional filters:
 *  - pending_only: "1"/"true" => only pending
 *  - q: search display_name/email/teacher_id
 *  - limit: default 200, max 500
 */
function _handleTeacherAdminRequestsList_({ token, body, p }) {
  const gate = _requireStaffApprover_({ token });
  if (!gate.ok) return _json(gate.payload, gate.code);

  const getS = (k)=> String(((p && p[k]) || (body && body[k]) || '')).trim();
  const pendingOnly = _toBool_(getS('pending_only') || 'true');
  const q = getS('q').toLowerCase();
  const limitRaw = parseInt(getS('limit') || '200', 10);
  const limit = (!isNaN(limitRaw) && limitRaw > 0) ? Math.min(limitRaw, 500) : 200;

  const ss = SpreadsheetApp.openById(DB_ID);
  const sh = ss.getSheetByName(SH_TEACHERS);
  if (!sh) return _json({ ok:false, error:'missing_tab', tab: SH_TEACHERS }, 500);

  const headers = _teacherObjSafe_({}); // just to keep eslint quiet
  const h = _getTeacherHeaders_(sh);

  const lastRow = sh.getLastRow();
  if (lastRow < 2) return _json({ ok:true, count:0, items:[] });

  const vals = sh.getRange(2, 1, lastRow - 1, sh.getLastColumn()).getValues();

  const out = [];
  for (let i=0;i<vals.length;i++){
    const obj = _rowToObj_(h, vals[i]);
    const t = _teacherObjSafe_(obj);

    if (!t.teacher_id) continue;

    if (pendingOnly && t.active) continue;

    if (q) {
      const hay = [t.display_name, t.email, t.teacher_id].join(' ').toLowerCase();
      if (hay.indexOf(q) === -1) continue;
    }

    out.push(t);
    if (out.length >= limit) break;
  }

  // newest updated/requested first (best effort)
  out.sort((a,b)=> String(b.updated_at||b.requested_at||'').localeCompare(String(a.updated_at||a.requested_at||'')));

  return _json({ ok:true, count: out.length, items: out });
}

/**
 * teacher.admin.teacher.set
 * Input:
 *  - teacher_id (required)
 *  - active: true/false (required)
 *  - plan_type (optional): FREE/PRO/etc (kept flexible)
 *  - note (optional): stored in request_note (append)
 */
function _handleTeacherAdminTeacherSet_({ token, body, p }) {
  const gate = _requireStaffApprover_({ token });
  if (!gate.ok) return _json(gate.payload, gate.code);

  const getAny = (k)=> (p && (k in p)) ? p[k] : ((body && (k in body)) ? body[k] : undefined);
  const getS = (k)=> String(getAny(k) == null ? '' : getAny(k)).trim();

  const teacher_id = getS('teacher_id');
  if (!teacher_id) return _json({ ok:false, error:'missing_teacher_id' }, 400);

  const activeRaw = getAny('active');
  if (activeRaw === undefined || activeRaw === null || String(activeRaw).trim() === '') {
  return _json({ ok:false, error:'missing_active' }, 400);
}
  const active = _toBool_(activeRaw);

  // allow flexible plan types
  const plan_type = String(getS('plan_type') || '').trim();
  const note = String(getS('note') || '').trim();

  const ss = SpreadsheetApp.openById(DB_ID);
  const sh = ss.getSheetByName(SH_TEACHERS);
  if (!sh) return _json({ ok:false, error:'missing_tab', tab: SH_TEACHERS }, 500);

  const h = _getTeacherHeaders_(sh);

  const rowIndex = _findRowIndexBy_(sh, h, 'teacher_id', teacher_id);
  if (rowIndex <= 0) return _json({ ok:false, error:'teacher_not_found' }, 404);

  const existing = _readObjAtRow_(sh, h, rowIndex);
  const wasActive = _toBool_(existing.active);
  const now = _iso(new Date());

  const patch = {
    active: active ? 'TRUE' : 'FALSE',
    updated_at: now
  };

  // Optional but recommended: keep request_status consistent if column exists
  if (h.indexOf('request_status') !== -1) {
    patch.request_status = active ? 'APPROVED' : 'DISABLED';
  }

  // plan_type if column exists and value provided
  if (plan_type && h.indexOf('plan_type') !== -1) patch.plan_type = plan_type;

  // request_note append (best effort if column exists)
  if (note && h.indexOf('request_note') !== -1) {
    const prev = String(existing.request_note || '').trim();
    patch.request_note = prev ? (prev + ' | ADMIN: ' + note) : ('ADMIN: ' + note);
  }

  _updateObjAtRow_(sh, h, rowIndex, patch);

  // Invalidate teacherRow cache so approvals take effect immediately
  try {
    CacheService.getScriptCache().remove('teacherRow:' + teacher_id);
  } catch(_) {}

  const updated = _readObjAtRow_(sh, h, rowIndex);

  // Email (best-effort) only on state transitions
  try {
    if (!wasActive && active) {
      _taSendTeacherApprovedEmail_(updated);
    } else if (wasActive && !active) {
      _taSendTeacherDisabledEmail_(updated);
    }
  } catch(e) {
    Logger.log('TA approve/disable email failed: ' + e);
  }

  return _json({ ok:true, teacher: _teacherObjSafe_(updated) });
}
