function _cacheKeyHash_(prefix, s) {
  const bytes = Utilities.computeDigest(
    Utilities.DigestAlgorithm.SHA_256,
    String(s || ''),
    Utilities.Charset.UTF_8
  );
  const hex = bytes.map(b => ('0' + ((b < 0 ? b + 256 : b).toString(16))).slice(-2)).join('');
  return String(prefix || 'k') + ':' + hex;
}

function _authVerify_(token) {
if (!AUTH_URL || AUTH_URL.indexOf('REPLACE_WITH') !== -1) {
  return { ok:false, error:'AUTH_URL_not_configured' };
}

// ---- Cache token verification (reduces AUTH_URL calls drastically)
const cache = CacheService.getScriptCache();
const ck = _cacheKeyHash_('auth', token);
const cached = cache.get(ck);
if (cached) {
  try {
    const cobj = JSON.parse(cached);
    if (cobj && cobj.ok) return { ok:true, user: cobj.user || null, raw: cobj.raw || null };
    if (cobj && cobj.fail) return { ok:false, error: cobj.error || 'invalid_token' };
  } catch (_) {}
}
  const payload = {
    action: 'verify',
    token: token
    // include: ''  // keep minimal
  };

  const res = UrlFetchApp.fetch(AUTH_URL, {
    method: 'post',
    payload: payload,
    muteHttpExceptions: true
  });

  const code = res.getResponseCode();
  const text = res.getContentText() || '';

  let obj = null;
  try { obj = JSON.parse(text); } catch (_) { obj = null; }

  if (code !== 200 || !obj || !obj.ok) {
    return {
      ok: false,
      error: (obj && (obj.error || obj.reason)) || ('auth_http_' + code)
    };
  }
cache.put(ck, JSON.stringify({ ok:true, user: obj.user || null, raw: obj }), 120); // 2 min
  return { ok: true, user: obj.user || null, raw: obj };
}

function _getTeacherRowById_(teacherId) {

    const cache = CacheService.getScriptCache();
  const ck = 'teacherRow:' + String(teacherId || '').trim();
  const cached = cache.get(ck);
  if (cached) {
    try { return JSON.parse(cached); } catch(_) {}
  }

  const ss = SpreadsheetApp.openById(DB_ID);
  const sh = ss.getSheetByName(SH_TEACHERS);
  if (!sh) return { found: false, error: 'missing_teachers_tab' };

  const headers = _getHeaders_(sh);
  const idxTeacherId = headers.indexOf('teacher_id');
  if (idxTeacherId === -1) return { found: false, error: 'missing_teacher_id_header' };

  const lastRow = sh.getLastRow();
  if (lastRow < 2) return { found: false };

  const values = sh.getRange(2, 1, lastRow - 1, sh.getLastColumn()).getValues();
  for (let i = 0; i < values.length; i++) {
    const row = values[i];
    const tId = String(row[idxTeacherId] || '').trim();
    if (tId === String(teacherId).trim()) {
      const obj = _rowToObj_(headers, row);

      const active = _toBool_(obj.active);
      const planType = String(obj.plan_type || '').trim();

      const res = {
        found: true,
        active: active,
        plan_type: planType
      };
      cache.put(ck, JSON.stringify(res), 600); // 10 minutes
      return res;
    }
  }

    const res = { found: false };
  cache.put(ck, JSON.stringify(res), 120); // 2 minutes
  return res;
}

function _getHeaders_(sh) {
  const lastCol = sh.getLastColumn();
  if (!lastCol) return [];
  return sh.getRange(1, 1, 1, lastCol).getValues()[0].map(x => String(x || '').trim());
}

function _rowToObj_(headers, row) {
  const o = {};
  for (let i = 0; i < headers.length; i++) {
    const k = String(headers[i] || '').trim();
    if (!k) continue;
    o[k] = row[i];
  }
  return o;
}

function _toBool_(v) {
  const s = String(v == null ? '' : v).trim().toLowerCase();
  if (s === 'true' || s === '1' || s === 'yes' || s === 'y') return true;
  if (s === 'false' || s === '0' || s === 'no' || s === 'n') return false;
  // Google Sheets checkbox TRUE/FALSE sometimes comes as boolean
  if (v === true) return true;
  if (v === false) return false;
  return false;
}

function _iso(d) {
  return Utilities.formatDate(d, 'Etc/UTC', "yyyy-MM-dd'T'HH:mm:ss'Z'");
}


