function _handleBankItemsBulkCreate_({ token, body, p }) {
  const gate = _requireTeacher_({ token });
  if (!gate.ok) return _json(gate.payload, gate.code);

  const teacher_id = gate.teacher_id;

  const items = (body && Array.isArray(body.items)) ? body.items : [];
  if (!items.length) return _json({ ok:false, error:'missing_items' }, 400);

  const CAP = 300;
  if (items.length > CAP) {
    return _json({ ok:false, error:'too_many_items', cap: CAP, received: items.length }, 400);
  }

  // Allowed fields from CSV/client
  const ALLOWED = [
    'stem',
    'option_a','fb_a',
    'option_b','fb_b',
    'option_c','fb_c',
    'option_d','fb_d',
    'option_e','fb_e',
    'option_f','fb_f',
    'correct',
    'rationale',
    'rationale_img',
    'subject',
    'topic',
    'difficulty',
    'marks'
  ];

  function _getStr_(o, k){
    return String((o && o[k] != null) ? o[k] : '').trim();
  }

  function _safeMarks_(raw){
    const s = String(raw == null ? '' : raw).trim();
    if (!s) return '1';
    const n = parseInt(s, 10);
    if (isNaN(n) || n <= 0) return '1';
    return String(n);
  }

  const now = _iso(new Date());
  const errors = [];
  const goodObjs = [];
  const createdIds = [];

  // Build + validate rows first (no sheet writes yet)
  for (let i = 0; i < items.length; i++) {
    const src = items[i] || {};
    const line = (src && src.line != null) ? src.line : '';

    // Build object with server-owned fields enforced
    const obj = {
      bank_item_id: _newId_('tbi'),
      teacher_id: teacher_id,
      status: 'ACTIVE',
      created_at: now,
      updated_at: now,

      // defaults for blanks (explicit)
      stem: '',
      option_a: '', fb_a: '',
      option_b: '', fb_b: '',
      option_c: '', fb_c: '',
      option_d: '', fb_d: '',
      option_e: '', fb_e: '',
      option_f: '', fb_f: '',
      correct: '',
      rationale: '',
      rationale_img: '',
      subject: '',
      topic: '',
      difficulty: '',
      marks: '1',

      // server-controlled provenance
      source_type: 'TEACHER',
      source_course_id: '',
      source_sheet_id: '',
      source_item_id: '',
      imported_at: ''
    };

    // copy allowed only
    ALLOWED.forEach(k => {
      obj[k] = _getStr_(src, k);
    });

    obj.correct = String(obj.correct || '').trim().toUpperCase();

    // normalize difficulty (blank allowed; invalid -> row error)
    const dNorm = _normalizeDifficulty_(obj.difficulty);
    if (dNorm === null) {
      errors.push({ index: i, line: line, error: 'invalid_difficulty' });
      continue;
    }
    obj.difficulty = dNorm; // '' or canonical

    // marks default to 1
    obj.marks = _safeMarks_(obj.marks);

    // required checks (stem, option_a, option_b)
    if (!String(obj.stem || '').trim()) {
      errors.push({ index: i, line: line, error: 'missing_stem' });
      continue;
    }
    if (!String(obj.option_a || '').trim()) {
      errors.push({ index: i, line: line, error: 'missing_option_a' });
      continue;
    }
    if (!String(obj.option_b || '').trim()) {
      errors.push({ index: i, line: line, error: 'missing_option_b' });
      continue;
    }

    // validate correct option mapping
    const v = _validateCorrect_(obj);
    if (!v.ok) {
      errors.push({ index: i, line: line, error: String(v.error || 'invalid_correct') });
      continue;
    }

    goodObjs.push(obj);
  }

  // If nothing valid, return with errors (no sheet writes)
  if (!goodObjs.length) {
    return _json({
      ok: true,
      created_count: 0,
      errors: errors,
      created_ids: []
    });
  }

  // Write in chunks using setValues for performance
  const ss = SpreadsheetApp.openById(DB_ID);
  const sh = ss.getSheetByName(SH_BANK_ITEMS);
  if (!sh) return _json({ ok:false, error:'bank_sheet_missing', tab: SH_BANK_ITEMS }, 500);

  const headers = _getHeaders_(sh);
  const CHUNK = 75;

  return _withScriptLock_(() => {
    try {
      let startRow = sh.getLastRow() + 1;
      let offset = 0;

      while (offset < goodObjs.length) {
        const batch = goodObjs.slice(offset, offset + CHUNK);

        const rows2d = batch.map(obj => {
          createdIds.push(obj.bank_item_id);
          return headers.map(h => (h in obj) ? obj[h] : '');
        });

        sh.getRange(startRow, 1, rows2d.length, headers.length).setValues(rows2d);
        startRow += rows2d.length;
        offset += batch.length;
      }

      return _json({
        ok: true,
        created_count: createdIds.length,
        errors: errors,
        created_ids: createdIds
      });

    } catch (err) {
      return _json({ ok:false, error: String(err && (err.stack || err.message) || err) }, 500);
    }
  });
}

