  const get = (k) => String((p && p[k]) || (body && body[k]) || '').trim();

  const bank_item_id = get('bank_item_id');
  if (!bank_item_id) return _json({ ok:false, error:'missing_bank_item_id' }, 400);

  const ss = SpreadsheetApp.openById(DB_ID);
  const sh = ss.getSheetByName(SH_BANK_ITEMS);
  const headers = _getHeaders_(sh);

  const rowIndex = _findRowIndexBy_(sh, headers, 'bank_item_id', bank_item_id);
  if (rowIndex <= 0) return _json({ ok:false, error:'not_found' }, 404);

  const existing = _readObjAtRow_(sh, headers, rowIndex);
  if (String(existing.teacher_id || '').trim() !== teacher_id) {
    return _json({ ok:false, error:'forbidden' }, 403);
  }

  return _withScriptLock_(() => {
    _updateObjAtRow_(sh, headers, rowIndex, {
      status: 'DELETED',
      updated_at: _iso(new Date())
    });
    return _json({ ok:true, deleted:true, bank_item_id });
  });  
}


function _handleBankMeta_({ token, body, p }) {
  const gate = _requireTeacher_({ token });
  if (!gate.ok) return _json(gate.payload, gate.code);

  const teacher_id = String(gate.teacher_id || '').trim();
  const getS = (k) => String(((p && p[k]) || (body && body[k]) || '')).trim();

  // include_deleted=1 will include DELETED rows in metadata
  const include_deleted = (getS('include_deleted') === '1');

  const ss = SpreadsheetApp.openById(DB_ID);
  const sh = ss.getSheetByName(SH_BANK_ITEMS);
  const headers = _getHeaders_(sh);

  // Required columns for metadata
  const idx = _indexMap_(headers, ['teacher_id','status','subject','topic','difficulty','source_type']);

  const lastRow = sh.getLastRow();
  if (lastRow < 2) {
    return _json({
      ok: true,
      meta: {
        subjects: [],
        topics: [],
        difficulties: DIFFICULTY_ALLOWED.slice(),
        source_types: ['TEACHER'],
        statuses: ['ACTIVE', 'DELETED', 'ALL']
      }
    });
  }

  const values = sh.getRange(2, 1, lastRow - 1, sh.getLastColumn()).getValues();

  // Use maps to de-duplicate case-insensitively
  const subjMap = {};   // lower -> display
  const topicMap = {};  // lower -> display
  const srcSet  = {};   // upper -> true
  const diffSet = {};   // canonical -> true

  for (let i = 0; i < values.length; i++) {
    const r = values[i];

    const tId = String(r[idx.teacher_id] || '').trim();
    if (tId !== teacher_id) continue;

    const st = String(r[idx.status] || '').trim().toUpperCase() || 'ACTIVE';
    if (!include_deleted && st === 'DELETED') continue;

    const subj = String(r[idx.subject] || '').trim();
    if (subj) subjMap[subj.toLowerCase()] = subj;

    const topic = String(r[idx.topic] || '').trim();
    if (topic) topicMap[topic.toLowerCase()] = topic;

    const src = String(r[idx.source_type] || '').trim();
    if (src) srcSet[src.toUpperCase()] = true;

    const dRaw = String(r[idx.difficulty] || '').trim();
    const dNorm = _normalizeDifficulty_(dRaw);
    if (dNorm) diffSet[dNorm] = true; // only canonical values
  }

  // Always expose canonical difficulties (even if no items yet)
  const difficulties = DIFFICULTY_ALLOWED.slice();

// Always expose all allowed source types (even if none exist yet)
let source_types = BANK_SOURCE_TYPES_ALLOWED.slice();

  const subjects = _sortCaseInsensitive_(Object.keys(subjMap).map(k => subjMap[k]));
  const topics   = _sortCaseInsensitive_(Object.keys(topicMap).map(k => topicMap[k]));

  return _json({
    ok: true,
    meta: {
      subjects,
      topics,
      difficulties,
      source_types,
      statuses: ['ACTIVE', 'DELETED', 'ALL']
    }
  });
}

/* =========================
 * Common gate: token -> auth -> teacher approved
 * ========================= */

function _requireTeacher_({ token }) {
  // Reuse existing phase-0 handler logic but return a structured gate
  const auth = _authVerify_(token);
  if (!auth.ok) return { ok:false, code:401, payload:{ ok:false, error:'auth_verify_failed', detail:auth.error||'' } };

  const user = auth.user || {};
  const roleUpper = String(user.role || '').trim().toUpperCase();
  const userId = String(user.user_id || '').trim();
  if (!userId) return { ok:false, code:500, payload:{ ok:false, error:'auth_missing_user_id' } };


  const teacherRow = _getTeacherRowById_(userId);
  if (!teacherRow.found) return { ok:false, code:403, payload:{ ok:false, error:'teacher_not_registered' } };
  if (!teacherRow.active) return { ok:false, code:403, payload:{ ok:false, error:'teacher_not_approved' } };

  return { ok:true, teacher_id:userId, role:roleUpper, plan_type:teacherRow.plan_type||'FREE', user:user };
}

/* =========================
 * Sheet utilities (small)
 * ========================= */
function _withScriptLock_(fn) {
  const lock = LockService.getScriptLock();
  lock.waitLock(15000);
  try { return fn(); }
  finally { try { lock.releaseLock(); } catch(_){} }
}

function _newId_(prefix) {
  // short-ish, unique enough for Sheets
  const u = Utilities.getUuid().replace(/-/g,'').slice(0, 12);
  return String(prefix || 'id') + '_' + u;
}

function _indexMap_(headers, keys) {
  const m = {};
  keys.forEach(k => m[k] = headers.indexOf(k));
  // Expose direct indices too
  Object.keys(m).forEach(k => {
    if (m[k] === -1) throw new Error('Missing header: ' + k);
  });
  return m;
}

function _appendObj_(sh, headers, obj) {
  const row = headers.map(h => (h in obj) ? obj[h] : '');
  sh.appendRow(row);
}

function _findRowIndexBy_(sh, headers, key, value) {
  const col = headers.indexOf(key);
  if (col === -1) throw new Error('Missing header: ' + key);
  const lastRow = sh.getLastRow();
  if (lastRow < 2) return -1;

  const vals = sh.getRange(2, col + 1, lastRow - 1, 1).getValues();
  const target = String(value || '').trim();
  for (let i = 0; i < vals.length; i++) {
    if (String(vals[i][0] || '').trim() === target) return i + 2; // sheet row
  }
  return -1;
}

function _readObjAtRow_(sh, headers, rowIndex) {
  const row = sh.getRange(rowIndex, 1, 1, headers.length).getValues()[0];
  return _rowToObj_(headers, row);
}

function _updateObjAtRow_(sh, headers, rowIndex, patch) {
  // patch only provided keys
  const row = sh.getRange(rowIndex, 1, 1, headers.length).getValues()[0];
  const obj = _rowToObj_(headers, row);

  Object.keys(patch || {}).forEach(k => { obj[k] = patch[k]; });

  const outRow = headers.map(h => (h in obj) ? obj[h] : '');
  sh.getRange(rowIndex, 1, 1, headers.length).setValues([outRow]);
}

function _validateCorrect_(obj) {
  const correct = String(obj.correct || '').trim().toUpperCase();
  const allowed = ['A','B','C','D','E','F'];
  if (!correct || allowed.indexOf(correct) === -1) {
    return { ok:false, error:'invalid_correct_must_be_A_to_F' };
  }

  const optMap = {
    A: String(obj.option_a || '').trim(),
    B: String(obj.option_b || '').trim(),
    C: String(obj.option_c || '').trim(),
    D: String(obj.option_d || '').trim(),
    E: String(obj.option_e || '').trim(),
    F: String(obj.option_f || '').trim()
  };

  // must have at least two non-empty options
  const nonEmpty = Object.keys(optMap).filter(k => !!optMap[k]);
  if (nonEmpty.length < 2) return { ok:false, error:'need_at_least_two_options' };

  // correct must point to a non-empty option
  if (!optMap[correct]) return { ok:false, error:'correct_option_is_empty' };

  return { ok:true };
}


/* =========================
 * Teacher Quizzes + Quiz Items (Snapshots) — Phase 2
