function _handleTeacherQuizCreate_({ token, body, p }) {
  const gate = _requireTeacher_({ token });
  if (!gate.ok) return _json(gate.payload, gate.code);

  const teacher_id = gate.teacher_id;
  const get = (k) => (p && (k in p)) ? p[k] : ((body && (k in body)) ? body[k] : undefined);

  const title = String(get('title') || '').trim();
  if (!title) return _json({ ok:false, error:'missing_title' }, 400);

  const subject = String(get('subject') || '').trim();

  // Collect explicit values from request first (these win)
  const explicit = {
    duration_minutes: _toIntDefault_(get('duration_minutes'), null),
    max_attempts: _toIntDefault_(get('max_attempts'), null),
    shuffle_questions: _toBoolDefault_(get('shuffle_questions'), null),
    shuffle_options: _toBoolDefault_(get('shuffle_options'), null),
    show_review: _toBoolDefault_(get('show_review'), null),
    show_results: _toBoolDefault_(
      get('show_results') !== undefined ? get('show_results') : get('show_result'),
      null
    )
  };

  // Handle preset – apply defaults only for fields NOT explicitly sent
  const presetRaw = get('preset');
  const preset = presetRaw !== undefined ? String(presetRaw || '').trim().toUpperCase() : '';
  const defaults = (preset && PRESET_DEFAULTS[preset]) ? PRESET_DEFAULTS[preset] : {};

  // Merge: explicit wins, fallback to preset default, then fallback to safe values
  const final = {
    duration_minutes: explicit.duration_minutes !== null ? explicit.duration_minutes :
                      (defaults.duration_minutes !== undefined ? defaults.duration_minutes : 0),
    max_attempts: explicit.max_attempts !== null ? explicit.max_attempts :
                  (defaults.max_attempts !== undefined ? defaults.max_attempts : 0),
    shuffle_questions: explicit.shuffle_questions !== null ? explicit.shuffle_questions :
                       (defaults.shuffle_questions !== undefined ? defaults.shuffle_questions : true),
    shuffle_options: explicit.shuffle_options !== null ? explicit.shuffle_options :
                     (defaults.shuffle_options !== undefined ? defaults.shuffle_options : true),
    show_review: explicit.show_review !== null ? explicit.show_review :
                 (defaults.show_review !== undefined ? defaults.show_review : true),
    show_results: explicit.show_results !== null ? explicit.show_results :
                  (defaults.show_results !== undefined ? defaults.show_results : true),

    // start from preset policy default (if any)
    results_release_policy: (defaults.results_release_policy || 'IMMEDIATE')
  };

  // allow teacher override of policy at CREATE time (if provided)
  const sentPolicy = String(get('results_release_policy') || '').trim().toUpperCase();
  if (sentPolicy) {
    if (!['IMMEDIATE','AFTER_CLOSE','MANUAL'].includes(sentPolicy)) {
      return _json({ ok:false, error:'invalid_results_release_policy', allowed:['IMMEDIATE','AFTER_CLOSE','MANUAL'] }, 400);
    }
    final.results_release_policy = sentPolicy;
  }

  const open_at = String(get('open_at') || '').trim();
  const close_at = String(get('close_at') || '').trim();
  const custom_fields_json = _normalizeCustomFieldsJson_(get('custom_fields_json'));

  // scheduled release timestamp (kept only for MANUAL)
  let results_released_at = String(get('results_released_at') || '').trim() || '';
  if (final.results_release_policy !== 'MANUAL') results_released_at = '';

  const ss = SpreadsheetApp.openById(DB_ID);
  const sh = ss.getSheetByName(SH_TEACHER_QUIZZES);
  const headers = _getHeaders_(sh);

  const now = _iso(new Date());
  const access_code = _generateUniqueAccessCode_(sh, headers);

  const obj = {
    teacher_quiz_id: _newId_('tq'),
    teacher_id: teacher_id,
    title: title,
    subject: subject,
    duration_minutes: String(final.duration_minutes),
    shuffle_questions: final.shuffle_questions ? 'TRUE' : 'FALSE',
    shuffle_options: final.shuffle_options ? 'TRUE' : 'FALSE',
    max_attempts: String(final.max_attempts),
    show_review: final.show_review ? 'TRUE' : 'FALSE',

    // show_results is canonical; show_result is a safe alias
    show_results: final.show_results ? 'TRUE' : 'FALSE',
    show_result:  final.show_results ? 'TRUE' : 'FALSE',

    open_at: open_at,
    close_at: close_at,
    status: 'DRAFT',
    access_code: access_code,
    custom_fields_json: custom_fields_json,
    draft_items_json: JSON.stringify({ items: [] }),
    created_at: now,
    updated_at: now,

    preset: preset || '',
    results_release_policy: final.results_release_policy || 'IMMEDIATE',
    results_released_at: results_released_at,
    results_released: 'FALSE',

// NEW (accept client values, then normalize)
grading_policy: String(get('grading_policy') || GRADING_POLICY_DEFAULT).trim().toUpperCase(),

grade_bands_json: (function(){
  const gb = get('grade_bands_json');
  // if frontend ever sends object
  if (gb && typeof gb === 'object') return JSON.stringify(gb);
  const s = String(gb || '').trim();
  return s || DEFAULT_GRADE_BANDS_JSON;
})(),
pass_threshold_pct: String(get('pass_threshold_pct') == null ? '' : get('pass_threshold_pct')).trim(),
score_display_policy: String(get('score_display_policy') || SCORE_DISPLAY_POLICY_DEFAULT).trim().toUpperCase()
  };

  // normalize before save (ensures canonical JSON + safe defaults)
  const gc = _normalizeGradingConfig_(obj);
  obj.grading_policy = gc.grading_policy;
  obj.grade_bands_json = gc.grade_bands_json;
  obj.pass_threshold_pct = String(gc.pass_threshold_pct);
  obj.score_display_policy = gc.score_display_policy;

  _appendObj_(sh, headers, obj);

  return _json({
    ok: true,
    teacher_quiz_id: obj.teacher_quiz_id,
    access_code: obj.access_code,
    preset: obj.preset
  });
}



function _handleTeacherQuizUpdate_({ token, body, p }) {
  const gate = _requireTeacher_({ token });
  if (!gate.ok) return _json(gate.payload, gate.code);

  const teacher_id = gate.teacher_id;
  const get = (k) => (p && (k in p)) ? p[k] : ((body && (k in body)) ? body[k] : undefined);

  const teacher_quiz_id = String(get('teacher_quiz_id') || '').trim();
  if (!teacher_quiz_id) return _json({ ok:false, error:'missing_teacher_quiz_id' }, 400);

  const ss = SpreadsheetApp.openById(DB_ID);
  const sh = ss.getSheetByName(SH_TEACHER_QUIZZES);
  const headers = _getHeaders_(sh);

  const rowIndex = _findRowIndexBy_(sh, headers, 'teacher_quiz_id', teacher_quiz_id);
  if (rowIndex <= 0) return _json({ ok:false, error:'not_found' }, 404);

  const existing = _readObjAtRow_(sh, headers, rowIndex);
  if (String(existing.teacher_id || '').trim() !== teacher_id) return _json({ ok:false, error:'forbidden' }, 403);

  const st = String(existing.status || '').trim().toUpperCase();
  if (st !== 'DRAFT') return _json({ ok:false, error:'not_draft' }, 400);

  // Support PATCH style if frontend sends { patch: { ... } }, otherwise use flat body
  const patchObj = (body && body.patch && typeof body.patch === 'object') ? body.patch : null;
  const src = patchObj || body || {};

  // Accept legacy show_result key
  if (!_hasOwn_(src, 'show_results') && _hasOwn_(src, 'show_result')) {
    src.show_results = src.show_result;
  }

  const patch = {};

  // preset handling
  const hasPresetKey = _hasOwn_(src, 'preset');
  const newPreset = hasPresetKey
    ? String(src.preset || '').trim().toUpperCase()
    : null;

  if (hasPresetKey && newPreset && !PRESET_DEFAULTS[newPreset]) {
    return _json({ ok:false, error:'invalid_preset', allowed:Object.keys(PRESET_DEFAULTS) }, 400);
  }

const oldPreset = String(existing.preset || '').trim().toUpperCase();
const presetChanged = hasPresetKey && (newPreset !== oldPreset);

if (presetChanged && newPreset && PRESET_DEFAULTS[newPreset]) {
  const defs = PRESET_DEFAULTS[newPreset];
  patch.duration_minutes        = defs.duration_minutes;
  patch.max_attempts            = defs.max_attempts;
  patch.shuffle_questions       = defs.shuffle_questions;
  patch.shuffle_options         = defs.shuffle_options;
  patch.show_review             = defs.show_review;
  patch.show_results            = defs.show_results;
  patch.show_result             = defs.show_results;
  patch.results_release_policy  = defs.results_release_policy;
}
if (hasPresetKey) patch.preset = newPreset || '';

  // explicit overrides win
  _maybeSet_(patch, src, 'title', v => String(v||'').trim());
  _maybeSet_(patch, src, 'subject', v => String(v||'').trim());

  _maybeSetNum_(patch, src, 'duration_minutes');
  _maybeSetBool_(patch, src, 'shuffle_questions');
  _maybeSetBool_(patch, src, 'shuffle_options');
  _maybeSetNum_(patch, src, 'max_attempts');
  _maybeSetBool_(patch, src, 'show_review');
  _maybeSetBool_(patch, src, 'show_results');

  if (_hasOwn_(patch, 'show_results')) {
    patch.show_result = patch.show_results;
  }

  _maybeSet_(patch, src, 'open_at', v => String(v||'').trim());
  _maybeSet_(patch, src, 'close_at', v => String(v||'').trim());

  if (_hasOwn_(src, 'custom_fields_json')) {
    patch.custom_fields_json = _normalizeCustomFieldsJson_(src.custom_fields_json);
  }
  if (_hasOwn_(src, 'draft_items_json')) {
    patch.draft_items_json = _normalizeDraftItemsJson_(src.draft_items_json);
  }

  if (hasPresetKey) patch.preset = newPreset || '';

  // results policy fields
  if (_hasOwn_(src, 'results_release_policy')) {
    const pol = String(src.results_release_policy || '').trim().toUpperCase();
    if (!['IMMEDIATE','AFTER_CLOSE','MANUAL'].includes(pol)) {
      return _json({ ok:false, error:'invalid_results_release_policy', allowed:['IMMEDIATE','AFTER_CLOSE','MANUAL'] }, 400);
    }
    patch.results_release_policy = pol;

    if (pol !== 'MANUAL') {
      patch.results_released = 'FALSE';
      patch.results_released_at = '';
    }
  }
  if (_hasOwn_(src, 'results_released')) {
    patch.results_released = _toBoolDefault_(src.results_released, false) ? 'TRUE' : 'FALSE';
  }
  if (_hasOwn_(src, 'results_released_at')) {
    patch.results_released_at = String(src.results_released_at || '').trim();
    const polNow = String(patch.results_release_policy || existing.results_release_policy || 'IMMEDIATE').trim().toUpperCase();
    if (polNow !== 'MANUAL') patch.results_released_at = '';
  }

  // ===== NEW (Grade Bands + Score Display) =====
const hasGradingKey =
  _hasOwn_(src, 'grading_policy') ||
  _hasOwn_(src, 'grade_bands_json') ||
  _hasOwn_(src, 'pass_threshold_pct') ||
  _hasOwn_(src, 'score_display_policy');

  if (hasGradingKey) {
    if (_hasOwn_(src, 'grading_policy')) {
      patch.grading_policy = String(src.grading_policy || '').trim().toUpperCase();
    }
    if (_hasOwn_(src, 'score_display_policy')) {
      patch.score_display_policy = String(src.score_display_policy || '').trim().toUpperCase();
    }
    if (_hasOwn_(src, 'grade_bands_json')) {
      const v = src.grade_bands_json;
      if (typeof v === 'string') patch.grade_bands_json = String(v || '').trim();
      else if (v && typeof v === 'object') patch.grade_bands_json = JSON.stringify(v);
      else patch.grade_bands_json = '';
    }
         if (_hasOwn_(src, 'pass_threshold_pct')) {
      patch.pass_threshold_pct = String(src.pass_threshold_pct == null ? '' : src.pass_threshold_pct).trim();
    }
    // normalize before saving (canonical + safe defaults)
    const merged = Object.assign({}, existing, patch);
    const gc = _normalizeGradingConfig_(merged);
    patch.grading_policy = gc.grading_policy;
    patch.grade_bands_json = gc.grade_bands_json;
    patch.score_display_policy = gc.score_display_policy;
    patch.pass_threshold_pct = String(gc.pass_threshold_pct);
  }

  if (Object.keys(patch).length === 0) {
    return _json({ ok:false, error:'no_fields_to_update' }, 400);
  }

  patch.updated_at = _iso(new Date());
  _updateObjAtRow_(sh, headers, rowIndex, patch);

  return _json({
    ok: true,
    teacher_quiz_id,
    updated_preset: hasPresetKey ? (patch.preset || '') : null
  });
}



