/**
 * teacher.quizzes.list — dashboard-grade
 * Filters:
 *  - status: DRAFT|PUBLISHED|ARCHIVED|ANY
 *  - subject: contains (case-insensitive)
 *  - mode: TIMED|PRACTICE|ANY
 *  - open_state: OPEN|UPCOMING|CLOSED|ANY
 *  - q: searches title + access_code + subject
 * Sort:
 *  - updated_at_desc (default), created_at_desc, open_at_asc, title_asc
 * Pagination:
 *  - cursor: offset integer, limit: 1..200
 * Extras:
 *  - include_counts: returns chips {draft,open,upcoming,closed,archived}
 */
function _handleTeacherQuizzesList_({ token, body, p }) {
  const gate = _requireTeacher_({ token });
  if (!gate.ok) return _json(gate.payload, gate.code);

  const teacher_id = gate.teacher_id;
  const getS = (k) => String(((p && p[k]) || (body && body[k]) || '')).trim();

  const status = (getS('status') || 'ANY').toUpperCase();
  const open_state = (getS('open_state') || 'ANY').toUpperCase();

  const subject = getS('subject').toLowerCase(); // contains
  const q = getS('q').toLowerCase();

  const sort = getS('sort') || 'updated_at_desc';

  const limitRaw = parseInt(getS('limit') || '30', 10);
  const limit = (!isNaN(limitRaw) && limitRaw > 0) ? Math.min(limitRaw, 200) : 30;

  const cursorRaw = parseInt(getS('cursor') || '0', 10);
  const cursor = (!isNaN(cursorRaw) && cursorRaw >= 0) ? cursorRaw : 0;

  const include_counts = _toBoolDefault_(getS('include_counts'), false);

  const nowMs = Date.now();

  const ss = SpreadsheetApp.openById(DB_ID);
  const sh = ss.getSheetByName(SH_TEACHER_QUIZZES);
  const headers = _getHeaders_(sh);

  const lastRow = sh.getLastRow();
  if (lastRow < 2) {
    return _json(include_counts
      ? { ok:true, count:0, items:[], next_cursor:'', counts:{draft:0,open:0,upcoming:0,closed:0,archived:0} }
      : { ok:true, count:0, items:[], next_cursor:'' }
    );
  }

  const values = sh.getRange(2, 1, lastRow - 1, sh.getLastColumn()).getValues();

  let all = [];
  for (let i = 0; i < values.length; i++) {
    const obj = _rowToObj_(headers, values[i]);
    if (String(obj.teacher_id || '').trim() !== teacher_id) continue;

    const os = _computeOpenState_(obj.open_at, obj.close_at, nowMs);
    obj.open_state = os;

    all.push(obj);
  }

  let counts = null;
  if (include_counts) counts = _computeQuizCounts_(all, nowMs);

  let items = all.slice();

  if (status !== 'ANY') items = items.filter(o => String(o.status || '').trim().toUpperCase() === status);
  if (open_state !== 'ANY') items = items.filter(o => String(o.open_state || '').trim().toUpperCase() === open_state);

  if (subject) {
    items = items.filter(o => String(o.subject || '').toLowerCase().includes(subject));
  }

  if (q) {
    items = items.filter(o => {
      const t = String(o.title || '').toLowerCase();
      const s = String(o.subject || '').toLowerCase();
      const c = String(o.access_code || '').toLowerCase();
      return t.includes(q) || s.includes(q) || c.includes(q);
    });
  }

  const pubIds = items
    .filter(o => String(o.status || '').trim().toUpperCase() === 'PUBLISHED')
    .map(o => String(o.teacher_quiz_id || '').trim())
    .filter(Boolean);

  const countMap = pubIds.length ? _countQuizItemsBulk_(pubIds) : {};

  let out = items.map(o => {
    const statusUpper = String(o.status || '').trim().toUpperCase();

    const shQ = _toBoolDefault_(o.shuffle_questions, true) ? 'TRUE' : 'FALSE';
    const shO = _toBoolDefault_(o.shuffle_options, true) ? 'TRUE' : 'FALSE';
    const showReview = _toBoolDefault_(o.show_review, true) ? 'TRUE' : 'FALSE';

    const showResRaw =
      (o.show_results !== undefined && o.show_results !== null && String(o.show_results).trim() !== '')
        ? o.show_results
        : o.show_result;
    const showResults = _toBoolDefault_(showResRaw, true) ? 'TRUE' : 'FALSE';

    let pol = String(o.results_release_policy || '').trim().toUpperCase();
    if (!pol) pol = 'IMMEDIATE';
    if (['IMMEDIATE','AFTER_CLOSE','MANUAL'].indexOf(pol) === -1) pol = 'IMMEDIATE';

    const released = _toBoolDefault_(o.results_released, false) ? 'TRUE' : 'FALSE';

    // ===== NEW: normalize grading config on read =====
    const gc = _normalizeGradingConfig_(o);

    return {
      teacher_quiz_id: String(o.teacher_quiz_id || '').trim(),
      title: String(o.title || '').trim(),
      subject: String(o.subject || '').trim(),
      status: String(o.status || '').trim(),

      duration_minutes: String(o.duration_minutes || '').trim(),
      open_at: String(o.open_at || '').trim(),
      close_at: String(o.close_at || '').trim(),
      open_state: String(o.open_state || '').trim(),
      access_code: String(o.access_code || '').trim(),
      created_at: String(o.created_at || '').trim(),
      updated_at: String(o.updated_at || '').trim(),

      preset: String(o.preset || '').trim(),
      max_attempts: String(o.max_attempts || '').trim() || '0',
      shuffle_questions: shQ,
      shuffle_options: shO,
      show_review: showReview,
      show_results: showResults,

      results_release_policy: pol,
      results_released: released,
      results_released_at: String(o.results_released_at || '').trim(),

      // ===== NEW (Grade Bands + Score Display) =====
      grading_policy: gc.grading_policy,
      grade_bands_json: gc.grade_bands_json,
      score_display_policy: gc.score_display_policy,
      pass_threshold_pct: String(gc.pass_threshold_pct),

      items_count: (statusUpper === 'PUBLISHED')
        ? (countMap[String(o.teacher_quiz_id || '').trim()] || 0)
        : 0
    };
  });

  out.sort(_makeQuizSorter_(sort));

  const sliced = out.slice(cursor, cursor + limit);
  const next_cursor = (cursor + limit < out.length) ? String(cursor + limit) : '';

  const res = { ok:true, count: out.length, items: sliced, next_cursor };
  if (include_counts) res.counts = counts;

  return _json(res);
}

/**
 * Publish: creates snapshots in teacher_quiz_items and flips quiz to PUBLISHED.
 * Input supports:
 *  - body.items: [ {bank_item_id, marks?}, {inline:{...}, marks?} ]
 *  - OR body.bank_item_ids: [ ... ] (simple ordered list)
 */
function _handleTeacherQuizPublish_({ token, body, p }) {
  const gate = _requireTeacher_({ token });
  if (!gate.ok) return _json(gate.payload, gate.code);

  const teacher_id = gate.teacher_id;
  const teacher_quiz_id = String(((p && p.teacher_quiz_id) || (body && body.teacher_quiz_id) || '')).trim();
  if (!teacher_quiz_id) return _json({ ok:false, error:'missing_teacher_quiz_id' }, 400);

  const ss = SpreadsheetApp.openById(DB_ID);

  // Load quiz and gate ownership + DRAFT
  const qSh = ss.getSheetByName(SH_TEACHER_QUIZZES);
  const qHeaders = _getHeaders_(qSh);
  const qRow = _findRowIndexBy_(qSh, qHeaders, 'teacher_quiz_id', teacher_quiz_id);
  if (qRow <= 0) return _json({ ok:false, error:'not_found' }, 404);

  const quiz = _readObjAtRow_(qSh, qHeaders, qRow);
  if (String(quiz.teacher_id || '').trim() !== teacher_id) return _json({ ok:false, error:'forbidden' }, 403);

  const qStatus = String(quiz.status || '').trim().toUpperCase();
  if (qStatus !== 'DRAFT') return _json({ ok:false, error:'not_draft' }, 400);

  // === Publish guard: AFTER_CLOSE requires close_at ===
  const pol = String(quiz.results_release_policy || '').trim().toUpperCase() || 'IMMEDIATE';
  const closeAt = String(quiz.close_at || '').trim();
  if (pol === 'AFTER_CLOSE') {
    if (!closeAt) return _json({ ok:false, error:'missing_close_at_for_after_close' }, 400);
    const ms = Date.parse(closeAt);
    if (isNaN(ms)) return _json({ ok:false, error:'invalid_close_at_for_after_close' }, 400);
  }

  // ✅ Source of truth: quiz.draft_items_json
  const draftStr = String(quiz.draft_items_json || '').trim();
  let draftRefs = _parseDraftItems_(draftStr);

  // Backward-compat fallback: if draft is empty, allow old payload (optional)
  if (!draftRefs.length) {
    let itemsLegacy = (body && Array.isArray(body.items)) ? body.items : null;

    if (!itemsLegacy) {
      const ids = (body && Array.isArray(body.bank_item_ids)) ? body.bank_item_ids : null;
      if (ids && ids.length) itemsLegacy = ids.map(x => ({ bank_item_id: String(x || '').trim() }));
    }

    if (itemsLegacy && itemsLegacy.length) {
      draftRefs = itemsLegacy
        .map(x => String((x && x.bank_item_id) || '').trim())
        .filter(Boolean);
    }
  }

  if (!draftRefs.length) return _json({ ok:false, error:'missing_items' }, 400);

  const quizSubject = String(quiz.subject || '').trim();

  const bankSh = ss.getSheetByName(SH_BANK_ITEMS);
  const bankHeaders = _getHeaders_(bankSh);

  const qiSh = ss.getSheetByName(SH_QUIZ_ITEMS);
  const qiHeaders = _getHeaders_(qiSh);

  const now = _iso(new Date());

  // ---- Build snapshot objects FIRST (no sheet writes yet) ----
  const libCache = {}; // course_id -> cached alpha map (inside _getLibraryItemCached_)
  const snapsToWrite = [];

  // helper to bail cleanly (so rollback path is always used)
  const bail = (code, payload) => {
    const e = new Error('__BAIL__');
    e._qa_bail = { code, payload };
    throw e;
  };

  try {
    for (let i = 0; i < draftRefs.length; i++) {
      const ref = String(draftRefs[i] || '').trim();
      if (!ref) continue;

      // If it contains ":" but isn't LIB:<course_id>:<item_id>, it's not a bank id.
// This prevents "LIB:..." from being misread as a bank_item_id.
if (ref.indexOf(':') !== -1 && !_isLibRef_(ref)) {
  bail(400, { ok:false, error:'invalid_ref_format', ref });
}

      // --- LIB refs ---
      if (_isLibRef_(ref)) {
        const parsed = _parseLibRef_(ref);
        if (!parsed.ok) bail(400, { ok:false, error:'invalid_library_ref', ref });

        const li = _getLibraryItemCached_(ss, libCache, parsed.course_id, parsed.item_id);
        if (!li.found) bail(404, {
          ok:false,
          error:'library_item_not_found',
          ref,
          course_id: parsed.course_id,
          item_id: parsed.item_id
        });

        const snap = _buildSnapshotFromLibraryItem_(quiz, li.item, quizSubject);

        snapsToWrite.push(Object.assign({}, snap, {
          quiz_item_id: _newId_('tqi'),
          teacher_quiz_id: teacher_quiz_id,
          position: String(i + 1),
          bank_item_id: ref,  // keep LIB ref in snapshots
          snapped_at: now
        }));

        continue;
      }

      // --- Teacher bank items ---
      const bank_item_id = ref;

      const found = _getBankItemById_(bankSh, bankHeaders, bank_item_id);
      if (!found.found) bail(404, { ok:false, error:'bank_item_not_found', bank_item_id });

      const bankObj = found.obj;

      // Ownership + status gate
      if (String(bankObj.teacher_id || '').trim() !== teacher_id) {
        bail(403, { ok:false, error:'forbidden_bank_item', bank_item_id });
      }

      const bst = String(bankObj.status || '').trim().toUpperCase();
      if (bst !== 'ACTIVE' && bst !== 'DRAFT') {
        bail(400, { ok:false, error:'bank_item_inactive', bank_item_id });
      }

      const snap = _buildSnapshotFromBank_(quiz, bankObj, null, quizSubject);

      snapsToWrite.push(Object.assign({}, snap, {
        quiz_item_id: _newId_('tqi'),
        teacher_quiz_id: teacher_quiz_id,
        position: String(i + 1),
        bank_item_id: bank_item_id,
        snapped_at: now
      }));
    }

    if (!snapsToWrite.length) bail(400, { ok:false, error:'missing_items' });

    // ---- Write snapshots atomically-ish ----
    return _withScriptLock_(() => {
      const appendedRows = [];
      let wroteCount = 0;

      try {
        // Clean old snapshots ONLY after validation/build succeeded
        _cleanupQuizSnapshots_(qiSh, qiHeaders, teacher_quiz_id);

        // Batch write for speed
        const startRow = qiSh.getLastRow() + 1;
        const rows2d = snapsToWrite.map(obj => qiHeaders.map(h => (h in obj) ? obj[h] : ''));

        qiSh.getRange(startRow, 1, rows2d.length, qiHeaders.length).setValues(rows2d);
        wroteCount = rows2d.length;

        // Flip quiz to PUBLISHED
        _updateObjAtRow_(qSh, qHeaders, qRow, {
          status: 'PUBLISHED',
          updated_at: now
        });

        return _json({ ok:true, teacher_quiz_id, status:'PUBLISHED', n: wroteCount });

      } catch (err2) {
        // best-effort rollback: delete the rows we just wrote
        try {
          if (wroteCount > 0) {
            // delete bottom-up
            for (let r = (qiSh.getLastRow()); r >= 2 && r >= (qiSh.getLastRow() - wroteCount + 1); r--) {
              qiSh.deleteRow(r);
            }
          }
        } catch (_) {}

        throw err2;
      }
    });

  } catch (err) {
    // handle bail payloads (and still hit catch)
    if (err && err._qa_bail) {
      return _json(err._qa_bail.payload, err._qa_bail.code);
    }

    if (String(err && (err.message || err) || '') === 'invalid_difficulty') {
      return _json({ ok:false, error:'invalid_difficulty', allowed: DIFFICULTY_ALLOWED }, 400);
    }

    return _json({ ok:false, error: String(err && (err.stack || err.message) || err) }, 500);
  }
}

function _handleTeacherQuizDraftPreview_({ token, body, p }) {
  const gate = _requireTeacher_({ token });
  if (!gate.ok) return _json(gate.payload, gate.code);

  const teacher_id = String(gate.teacher_id || '').trim();
  const get = (k) => (p && (k in p)) ? p[k] : ((body && (k in body)) ? body[k] : undefined);

  const teacher_quiz_id = String(get('teacher_quiz_id') || '').trim();
  if (!teacher_quiz_id) return _json({ ok:false, error:'missing_teacher_quiz_id' }, 400);

  const ss = SpreadsheetApp.openById(DB_ID);

  // ---- Load quiz (ownership gate)
  const qSh = ss.getSheetByName(SH_TEACHER_QUIZZES);
  const qHeaders = _getHeaders_(qSh);
  const qRow = _findRowIndexBy_(qSh, qHeaders, 'teacher_quiz_id', teacher_quiz_id);
  if (qRow <= 0) return _json({ ok:false, error:'not_found' }, 404);

  const quiz = _readObjAtRow_(qSh, qHeaders, qRow);
  if (String(quiz.teacher_id || '').trim() !== teacher_id) return _json({ ok:false, error:'forbidden' }, 403);

  const quiz_status = String(quiz.status || '').trim().toUpperCase() || '';
  const locked = (quiz_status && quiz_status !== 'DRAFT');

  const quizSubject = String(quiz.subject || '').trim();

  // ---- Parse draft refs
  const draftStr = String(quiz.draft_items_json || '').trim();
  const refs = _parseDraftItems_(draftStr);

  const missing = [];
  const slots = []; // ordered resolvable refs only

  for (let i = 0; i < refs.length; i++) {
    const ref = String(refs[i] || '').trim();
    if (!ref) continue;

    // If it contains ":" but is not LIB:<course_id>:<item_id>, it’s invalid.
    if (ref.indexOf(':') !== -1 && !_isLibRef_(ref)) {
      missing.push({ ref, reason: 'invalid_ref_format' });
      continue;
    }

    if (_isLibRef_(ref)) {
      const parsed = _parseLibRef_(ref);
      if (!parsed.ok) {
        missing.push({ ref, reason: 'invalid_library_ref' });
        continue;
      }
      slots.push({ ref, type: 'LIB', course_id: parsed.course_id, item_id: parsed.item_id });
      continue;
    }

    // bank id
    slots.push({ ref, type: 'BANK' });
  }

  // ---- Resolve BANK refs in one pass (fast path)
  const needBank = {};
  const needBankArr = [];
  for (let i = 0; i < slots.length; i++) {
    const s = slots[i];
    if (s.type !== 'BANK') continue;
    const id = String(s.ref || '').trim();
    if (!id || needBank[id]) continue;
    needBank[id] = true;
    needBankArr.push(id);
  }

  const bankById = {}; // id -> {found:true,obj} or {found:false,reason}
  if (needBankArr.length) {
    const bankSh = ss.getSheetByName(SH_BANK_ITEMS);
    if (!bankSh) {
      return _json({ ok:false, error:'bank_sheet_missing', tab: SH_BANK_ITEMS }, 500);
    }

    const bh = _getHeaders_(bankSh);

    const idxId = bh.indexOf('bank_item_id');
    const idxTeacher = bh.indexOf('teacher_id');
    const idxStatus = bh.indexOf('status');

    if (idxId === -1 || idxTeacher === -1 || idxStatus === -1) {
      return _json({ ok:false, error:'bank_headers_missing', required:['bank_item_id','teacher_id','status'] }, 500);
    }

    const lastRow = bankSh.getLastRow();
    if (lastRow >= 2) {
      const values = bankSh.getRange(2, 1, lastRow - 1, bankSh.getLastColumn()).getValues();

      for (let r = 0; r < values.length; r++) {
        const row = values[r];
        const id = String(row[idxId] || '').trim();
        if (!id || !needBank[id]) continue;

        // Build row object using your existing helper (keeps compatibility with your sheet headers)
        const obj = _rowToObj_(bh, row);

        // Ownership gate
        if (String(obj.teacher_id || '').trim() !== teacher_id) {
          bankById[id] = { found:false, reason:'forbidden_bank_item' };
          continue;
        }

        // Status gate (mirror publish: allow ACTIVE and DRAFT)
        const st = String(obj.status || '').trim().toUpperCase();
        if (st !== 'ACTIVE' && st !== 'DRAFT') {
          bankById[id] = { found:false, reason:'bank_item_inactive' };
          continue;
        }

        bankById[id] = { found:true, obj };
      }
    }

    // Mark any remaining not found
    for (let i = 0; i < needBankArr.length; i++) {
      const id = needBankArr[i];
      if (bankById[id]) continue;
      bankById[id] = { found:false, reason:'bank_item_not_found' };
    }
  }

  // ---- Resolve LIB refs (cached per course)
  const libCache = {}; // course_id -> byId map (built by _getLibraryItemCached_)

  // ---- Normalize output (ordered)
  const out = [];

  function _normStr_(v){ return String(v == null ? '' : v).trim(); }

  function _normalizeQuestion_(base) {
    // Keep payload compact + editor-ready
    return {
      ref: _normStr_(base.ref),
      source: _normStr_(base.source),
      readonly: !!base.readonly,
      lib: base.lib || null,
      display: base.display || { badge:'', id: _normStr_(base.ref) },

      stem: _normStr_(base.stem),

      subject: _normStr_(base.subject),
      topic: _normStr_(base.topic),
      difficulty: _normStr_(base.difficulty),
      marks: _normStr_(base.marks) || '1',

      option_a: _normStr_(base.option_a), fb_a: _normStr_(base.fb_a),
      option_b: _normStr_(base.option_b), fb_b: _normStr_(base.fb_b),
      option_c: _normStr_(base.option_c), fb_c: _normStr_(base.fb_c),
      option_d: _normStr_(base.option_d), fb_d: _normStr_(base.fb_d),
      option_e: _normStr_(base.option_e), fb_e: _normStr_(base.fb_e),
      option_f: _normStr_(base.option_f), fb_f: _normStr_(base.fb_f),

      correct: _normStr_(base.correct).toUpperCase(),
      rationale: _normStr_(base.rationale),
      rationale_img: _normStr_(base.rationale_img),

      created_at: _normStr_(base.created_at),
      updated_at: _normStr_(base.updated_at),
      source_type: _normStr_(base.source_type)
    };
  }

  for (let i = 0; i < slots.length; i++) {
    const s = slots[i];

    if (s.type === 'LIB') {
      const hit = _getLibraryItemCached_(ss, libCache, s.course_id, s.item_id);
      if (!hit.found) {
        missing.push({ ref: s.ref, reason:'library_item_not_found', course_id:s.course_id, item_id:s.item_id });
        continue;
      }

      const li = hit.item || {};

      // Prefer library item fields; subject falls back to quiz subject
      const subj = _normStr_(li.subject) || quizSubject;

      out.push(_normalizeQuestion_({
        ref: s.ref,
        source: 'LIB',
        readonly: true,
        lib: { course_id: s.course_id, item_id: s.item_id },
        display: { badge:'QAcademy Library', id: `${s.course_id} • ${s.item_id}` },

        stem: li.stem,

        subject: subj,
        topic: li.topic,
        difficulty: li.difficulty,
        marks: li.marks,

        option_a: li.option_a, fb_a: li.fb_a,
        option_b: li.option_b, fb_b: li.fb_b,
        option_c: li.option_c, fb_c: li.fb_c,
        option_d: li.option_d, fb_d: li.fb_d,
        option_e: li.option_e, fb_e: li.fb_e,
        option_f: li.option_f, fb_f: li.fb_f,

        correct: li.correct,
        rationale: li.rationale,
        rationale_img: li.rationale_img,

        created_at: '',
        updated_at: _normStr_(li.updated_at || ''),
        source_type: 'LIB'
      }));

      continue;
    }

    // BANK
    const id = String(s.ref || '').trim();
    const found = bankById[id];

    if (!found || !found.found) {
      missing.push({ ref: id, reason: (found && found.reason) ? found.reason : 'bank_item_not_found' });
      continue;
    }

    const b = found.obj || {};
    out.push(_normalizeQuestion_({
      ref: id,
      source: 'BANK',
      readonly: false,
      lib: null,
      display: { badge:'My Bank', id: id },

      stem: b.stem,

      subject: _normStr_(b.subject) || quizSubject,
      topic: b.topic,
      difficulty: b.difficulty,
      marks: b.marks,

      option_a: b.option_a, fb_a: b.fb_a,
      option_b: b.option_b, fb_b: b.fb_b,
      option_c: b.option_c, fb_c: b.fb_c,
      option_d: b.option_d, fb_d: b.fb_d,
      option_e: b.option_e, fb_e: b.fb_e,
      option_f: b.option_f, fb_f: b.fb_f,

      correct: b.correct,
