function _hasOwn_(obj, k) {
  return obj && Object.prototype.hasOwnProperty.call(obj, k);
}

function _toIntDefault_(v, def) {
  const n = parseInt(String(v == null ? '' : v).trim(), 10);
  return isNaN(n) ? def : n;
}

/**
 * Boolean parsing that DOES NOT force blank -> false.
 * - If value is missing/blank/unparseable => returns def.
 */
function _toBoolDefault_(v, def) {
  if (v === undefined || v === null || v === '') return !!def;

  if (v === true) return true;
  if (v === false) return false;

  const s = String(v).trim().toUpperCase();
  if (['TRUE','1','YES','Y'].includes(s)) return true;
  if (['FALSE','0','NO','N'].includes(s)) return false;

  return !!def;
}


/**
 * Minimal, flexible custom field schema:
 * - accepts object or JSON string
 * - ensures {fields:[]}, caps at 4, drops empty labels
 * - assigns stable keys f1..f4 if missing/duplicate
 * - stores as JSON string in the sheet
 */
function _normalizeCustomFieldsJson_(input) {
  let obj = null;

  if (input == null || input === '') {
    obj = { fields: [] };
  } else if (typeof input === 'string') {
    try { obj = JSON.parse(input); } catch (_) { obj = { fields: [] }; }
  } else if (typeof input === 'object') {
    obj = input;
  } else {
    obj = { fields: [] };
  }

  const fieldsIn = Array.isArray(obj.fields) ? obj.fields : [];
  const cleaned = [];

  for (let i = 0; i < fieldsIn.length && cleaned.length < 4; i++) {
    const f = fieldsIn[i] || {};
    const label = String(f.label || '').trim();
    if (!label) continue;

    const out = Object.assign({}, f);
    out.label = label;
    out.required = _toBoolDefault_(f.required, false);

    cleaned.push(out);
  }

  // Ensure stable unique keys
  const used = {};
  for (let i = 0; i < cleaned.length; i++) {
    let key = String(cleaned[i].key || '').trim();
    if (!key || used[key]) key = 'f' + (i + 1);
    while (used[key]) key = 'f' + (Math.floor(Math.random() * 9000) + 1000);
    cleaned[i].key = key;
    used[key] = true;
  }

  obj.fields = cleaned;

  return JSON.stringify(obj);
}

function _schemaToFields_(schemaJsonStr) {
  const schema = _parseJsonSafe_(schemaJsonStr, { fields: [] });
  const fields = Array.isArray(schema.fields) ? schema.fields : [];

  const out = [];
  const used = {};

  for (let i = 0; i < fields.length && out.length < 4; i++) {
    const f = fields[i] || {};
    const label = String(f.label || '').trim();
    if (!label) continue;

    let key = String(f.key || '').trim();
    if (!key) key = 'f' + (out.length + 1);
    if (used[key]) key = 'f' + (out.length + 1);
    used[key] = true;

    out.push({
      key: key,
      label: label,
      required: _toBoolDefault_(f.required, false),
      type: String(f.type || 'text').trim() || 'text',
      options: (f.options == null) ? null : f.options
    });
  }

  return out;
}

function _parseJsonSafe_(input, fallback) {
  if (input == null || input === '') return fallback;
  if (typeof input === 'string') {
    try { return JSON.parse(input); } catch (_) { return fallback; }
  }
  if (typeof input === 'object') return input;
  return fallback;
}


// ================================
// Grade Bands + Score Display
// ================================

const GRADING_POLICY_DEFAULT = 'BANDS_PCT';
const SCORE_DISPLAY_POLICY_DEFAULT = 'PCT_ONLY';

// Pass threshold (percent)
const PASS_THRESHOLD_DEFAULT = 50; // used if not provided and cannot be derived

function _parsePct_(v) {
  // returns number or null
  if (v === undefined || v === null) return null;
  const s = String(v).trim();
  if (!s) return null;
  const n = Number(s);
  if (!isFinite(n)) return null;
  // clamp 0..100 and round to 2dp (keeps stability if someone uses decimals)
  const c = Math.max(0, Math.min(100, n));
  return Math.round(c * 100) / 100;
}

function _derivePassThresholdFromBands_(bandsArr) {
  // bandsArr: [{min_pct,label}, ...] sorted asc
  // Prefer a band whose label includes "pass" (case-insensitive).
  const arr = Array.isArray(bandsArr) ? bandsArr : [];
  for (let i = 0; i < arr.length; i++) {
    const b = arr[i] || {};
    const label = String(b.label || '').trim().toLowerCase();
    if (label && label.indexOf('pass') !== -1) {
      const n = _parsePct_(b.min_pct);
      if (n != null) return n;
    }
  }
  // fallback: default 50
  return PASS_THRESHOLD_DEFAULT;
}

const GRADING_POLICY_ALLOWED = { 'BANDS_PCT': true };
const SCORE_DISPLAY_POLICY_ALLOWED = {
  'HIDE': true,
  'PCT_ONLY': true,
  'RAW_ONLY': true,
  'RAW_AND_PCT': true
};

const DEFAULT_GRADE_BANDS_OBJ = {
  bands: [
    { min_pct: 0,  label: 'Fail' },
    { min_pct: 50, label: 'Pass' },
    { min_pct: 65, label: 'Credit' },
    { min_pct: 75, label: 'Distinction' }
  ]
};

const DEFAULT_GRADE_BANDS_JSON = JSON.stringify(DEFAULT_GRADE_BANDS_OBJ);

/**
 * _normalizeGradingConfig_(quizObj)
 * - validates grading_policy + score_display_policy
 * - parses grade_bands_json safely
 * - cleans bands: {min_pct:number,label:string} only
 * - clamps min_pct to 0..100
 * - sorts ascending by min_pct
 * - ensures a min_pct:0 band exists
 * - falls back to defaults if parsing/validation fails
 *
 * Returns:
 *  {
 *    grading_policy,
 *    score_display_policy,
 *    grade_bands_json,   // canonical JSON string
 *    grade_bands         // parsed object {bands:[...]}
 *  }
 */
function _normalizeGradingConfig_(quizObj) {
  const rawGp = String((quizObj && quizObj.grading_policy) || '').trim().toUpperCase();
  const grading_policy = GRADING_POLICY_ALLOWED[rawGp] ? rawGp : GRADING_POLICY_DEFAULT;

  const rawSdp = String((quizObj && quizObj.score_display_policy) || '').trim().toUpperCase();
  const score_display_policy = SCORE_DISPLAY_POLICY_ALLOWED[rawSdp] ? rawSdp : SCORE_DISPLAY_POLICY_DEFAULT;

  // ---- parse grade_bands_json ----
  let parsed = null;
  const rawBands = (quizObj && quizObj.grade_bands_json);

  try {
    if (rawBands == null || rawBands === '') {
      parsed = null;
    } else if (typeof rawBands === 'string') {
      parsed = JSON.parse(rawBands);
    } else if (typeof rawBands === 'object') {
      parsed = rawBands;
    }
  } catch (_) {
    parsed = null;
  }

  // allow array shorthand
  if (Array.isArray(parsed)) parsed = { bands: parsed };

  const inBands = (parsed && Array.isArray(parsed.bands)) ? parsed.bands : null;

  // ---- clean bands ----
  let cleaned = [];
  if (inBands) {
    for (let i = 0; i < inBands.length; i++) {
      const b = inBands[i] || {};
      const label = String(b.label || '').trim();
      const n = Number(b.min_pct);

      if (!label) continue;
      if (!isFinite(n)) continue;

      const min = Math.max(0, Math.min(100, n));
      // Keep up to 2dp for stability if someone uses decimals
      const min2 = Math.round(min * 100) / 100;

      cleaned.push({ min_pct: min2, label });
    }
  }

  // if invalid/empty -> default bands
  if (!cleaned.length) {
    cleaned = (DEFAULT_GRADE_BANDS_OBJ.bands || []).map(x => ({ min_pct: x.min_pct, label: x.label }));
  }

  // sort asc
  cleaned.sort((a, b) => (a.min_pct - b.min_pct));

  // dedupe same min_pct (keep the last label for that threshold)
  const deduped = [];
  for (let i = 0; i < cleaned.length; i++) {
    const cur = cleaned[i];
    if (!deduped.length) {
      deduped.push(cur);
      continue;
    }
    const prev = deduped[deduped.length - 1];
    if (prev.min_pct === cur.min_pct) {
      // overwrite label
      prev.label = cur.label;
    } else {
      deduped.push(cur);
    }
  }

  // ensure min_pct:0 exists
  if (!deduped.length || deduped[0].min_pct !== 0) {
    deduped.unshift({ min_pct: 0, label: 'Fail' });
  } else {
    // if first is 0 but label somehow blank, fix it
    if (!String(deduped[0].label || '').trim()) deduped[0].label = 'Fail';
  }

  const grade_bands = { bands: deduped };
  const grade_bands_json = JSON.stringify(grade_bands);

  // ---- pass threshold ----
  // Accept explicit pass_threshold_pct on quiz, otherwise derive from bands, otherwise default.
  let pass_threshold_pct = _parsePct_(quizObj && quizObj.pass_threshold_pct);
  if (pass_threshold_pct == null) {
    pass_threshold_pct = _derivePassThresholdFromBands_(grade_bands.bands);
  }

  return {
    grading_policy,
    score_display_policy,
    grade_bands_json,
    grade_bands,
    pass_threshold_pct
  };
}
