/**
 * draft_items_json format: {"items":[ "tbi_x", "tbi_y", ... ]}
 * Accepts:
 * - stringified JSON of the above
 * - object {items:[...]}
 * - array ["tbi_x", ...]
 * Returns JSON string always.
 */
function _normalizeDraftItemsJson_(input) {
  let obj = null;

  if (input == null || input === '') {
    obj = { items: [] };
  } else if (typeof input === 'string') {
    try { obj = JSON.parse(input); } catch (_) { obj = null; }
    if (obj == null) {
      // allow raw comma-separated fallback
      const parts = String(input).split(',').map(s => s.trim()).filter(Boolean);
      obj = { items: parts };
    }
  } else if (Array.isArray(input)) {
    obj = { items: input };
  } else if (typeof input === 'object') {
    obj = input;
  } else {
    obj = { items: [] };
  }

  let items = [];

  // allow {items:[...]} only
  if (obj && Array.isArray(obj.items)) items = obj.items;

  // normalize to ordered unique string list
  const seen = {};
  const out = [];
  for (let i = 0; i < items.length; i++) {
    const v = items[i];

    // if someone accidentally sends objects, accept {bank_item_id}
    let id = '';
    if (typeof v === 'string') id = v;
    else if (v && typeof v === 'object') id = String(v.bank_item_id || '').trim();

    id = String(id || '').trim();
    if (!id) continue;
    if (seen[id]) continue;
    seen[id] = true;
    out.push(id);
  }

  return JSON.stringify({ items: out });
}

function _parseDraftBankIds_(draftJsonStr) {
