}

function _isLibRef_(ref) {
  return /^LIB:/i.test(String(ref || '').trim());
}

function _parseLibRef_(ref) {
  const s = String(ref || '').trim();
  const m = s.match(/^LIB:([^:]+):(.+)$/i);
  if (!m) return { ok:false };

  const course_id = String(m[1] || '').trim();
  const item_id   = String(m[2] || '').trim();

  if (!course_id || !item_id) return { ok:false };
  return { ok:true, course_id, item_id };
}

function _getLibraryItemCached_(ss, cache, course_id, item_id) {
  const cid = String(course_id || '').trim();
  const iid = String(item_id || '').trim();
  if (!cid || !iid) return { found:false };

  if (!cache[cid]) {
    const course = _libResolveCourse_(ss, cid);
    if (!course.found || !course.active) return { found:false };

    let alphaSS, alphaSh;
    try {
      alphaSS = SpreadsheetApp.openById(course.sheet_id);
      alphaSh = alphaSS.getSheetByName(course.tab_name || 'items');
    } catch (e) {
      return { found:false };
    }
    if (!alphaSh) return { found:false };

    const headers = _getHeaders_(alphaSh);
    const lastRow = alphaSh.getLastRow();
    const lastCol = alphaSh.getLastColumn();
    if (lastRow < 2 || lastCol < 1) return { found:false };

    const idxId = _idxAny_(headers, ['item_id','id','bank_item_id','question_id']);
    if (idxId === -1) return { found:false };

    // read all rows once for this course
    const values = alphaSh.getRange(2, 1, lastRow - 1, lastCol).getValues();

    // build byId map (store the row as object using the same extraction logic as items.list)
    const byId = {};
    for (let i=0; i<values.length; i++){
      const r = values[i];
      const rid = String(r[idxId] || '').trim();
      if (!rid) continue;

      // Minimal object build for snapshot use:
      // We'll reuse the same extraction rules as items.list by calling a tiny extractor.
      const obj = _libExtractItemFromRow_(headers, r, course.course_id);
      if (obj && obj.item_id) byId[obj.item_id] = obj;
    }

    cache[cid] = { byId: byId };
  }

  const hit = cache[cid].byId[iid];
  return hit ? { found:true, item: hit } : { found:false };
}

function _libExtractItemFromRow_(headers, r, course_id) {
  const idxId = _idxAny_(headers, ['item_id','id','bank_item_id','question_id']);
  if (idxId === -1) return null;

  const idxStem = _idxAny_(headers, ['stem','question','question_text','q','title']);
  const idxSubject = _idxAny_(headers, ['subject']);
  const idxTopic = _idxAny_(headers, ['topic']);
  const idxDifficulty = _idxAny_(headers, ['difficulty']);
  const idxMarks = _idxAny_(headers, ['marks','score']);

  const idxCorrect = _idxAny_(headers, ['correct','answer','key']);
  const idxRationale = _idxAny_(headers, ['rationale','explanation']);
  const idxRationaleImg = _idxAny_(headers, ['rationale_img','explanation_img','rationale_image']);

  const idxOptA = _idxAny_(headers, ['option_a','a']);
  const idxOptB = _idxAny_(headers, ['option_b','b']);
  const idxOptC = _idxAny_(headers, ['option_c','c']);
  const idxOptD = _idxAny_(headers, ['option_d','d']);
  const idxOptE = _idxAny_(headers, ['option_e','e']);
  const idxOptF = _idxAny_(headers, ['option_f','f']);

  const idxFbA = _idxAny_(headers, ['fb_a','feedback_a']);
  const idxFbB = _idxAny_(headers, ['fb_b','feedback_b']);
  const idxFbC = _idxAny_(headers, ['fb_c','feedback_c']);
  const idxFbD = _idxAny_(headers, ['fb_d','feedback_d']);
  const idxFbE = _idxAny_(headers, ['fb_e','feedback_e']);
  const idxFbF = _idxAny_(headers, ['fb_f','feedback_f']);

  const item_id = String(r[idxId] || '').trim();
  if (!item_id) return null;

  const option_a = (idxOptA !== -1) ? String(r[idxOptA] || '').trim() : '';
  const option_b = (idxOptB !== -1) ? String(r[idxOptB] || '').trim() : '';
  const option_c = (idxOptC !== -1) ? String(r[idxOptC] || '').trim() : '';
  const option_d = (idxOptD !== -1) ? String(r[idxOptD] || '').trim() : '';
  const option_e = (idxOptE !== -1) ? String(r[idxOptE] || '').trim() : '';
  const option_f = (idxOptF !== -1) ? String(r[idxOptF] || '').trim() : '';

  const correctRaw = (idxCorrect !== -1) ? String(r[idxCorrect] || '').trim() : '';
  const correct = _libNormalizeCorrect_(correctRaw, { option_a, option_b, option_c, option_d, option_e, option_f });

  const diffRaw = (idxDifficulty !== -1) ? String(r[idxDifficulty] || '').trim() : '';
  const diff = diffRaw ? (_normalizeDifficulty_(diffRaw) || String(diffRaw||'').trim()) : '';

  return {
    course_id: String(course_id || '').trim(),
    item_id: item_id,

    stem: (idxStem !== -1) ? String(r[idxStem] || '').trim() : '',
    subject: (idxSubject !== -1) ? String(r[idxSubject] || '').trim() : '',
    topic: (idxTopic !== -1) ? String(r[idxTopic] || '').trim() : '',
    difficulty: diff,
    marks: (idxMarks !== -1) ? String(r[idxMarks] || '').trim() : '1',

    option_a, option_b, option_c, option_d, option_e, option_f,
    fb_a: (idxFbA !== -1) ? String(r[idxFbA] || '').trim() : '',
    fb_b: (idxFbB !== -1) ? String(r[idxFbB] || '').trim() : '',
    fb_c: (idxFbC !== -1) ? String(r[idxFbC] || '').trim() : '',
    fb_d: (idxFbD !== -1) ? String(r[idxFbD] || '').trim() : '',
    fb_e: (idxFbE !== -1) ? String(r[idxFbE] || '').trim() : '',
    fb_f: (idxFbF !== -1) ? String(r[idxFbF] || '').trim() : '',

    correct,
    rationale: (idxRationale !== -1) ? String(r[idxRationale] || '').trim() : '',
    rationale_img: (idxRationaleImg !== -1) ? String(r[idxRationaleImg] || '').trim() : ''
  };
}

