/**
 * Validates + normalizes candidate-provided member fields against the teacher-defined schema.
 * - schemaJsonStr comes from teacher_classes.custom_fields_json
 * - memberInput can be:
 *    - object: {f1:"...", f2:"..."} OR {fields:{f1:"..."}}
 *    - JSON string of either shape above
 * Output stored in sheet is ALWAYS JSON string: {"fields":{...}}
 */
function _validateMemberFieldsJson_(schemaJsonStr, memberInput) {
  const schema = _parseJsonSafe_(schemaJsonStr, { fields: [] });
  const fields = Array.isArray(schema.fields) ? schema.fields : [];

  // Build allowed keys + required map (cap 4)
  const allowed = [];
  const req = {};
  const label = {};

  for (let i = 0; i < fields.length && allowed.length < 4; i++) {
    const f = fields[i] || {};
    const k = String(f.key || '').trim();
    if (!k) continue;
    allowed.push(k);
    req[k] = _toBoolDefault_(f.required, false);
    label[k] = String(f.label || '').trim() || k;
  }

  // Parse input (accept {fields:{...}} or direct object)
  let raw = _parseJsonSafe_(memberInput, {});
  if (raw && typeof raw === 'object' && !Array.isArray(raw) && raw.fields && typeof raw.fields === 'object' && !Array.isArray(raw.fields)) {
    raw = raw.fields;
  }
  if (!raw || typeof raw !== 'object' || Array.isArray(raw)) raw = {};

  // Keep only allowed keys
  const out = {};
  for (let i = 0; i < allowed.length; i++) {
    const k = allowed[i];
    if (Object.prototype.hasOwnProperty.call(raw, k)) {
      out[k] = String(raw[k] == null ? '' : raw[k]).trim();
    }
  }

  // Required checks
  const missing = [];
  for (let i = 0; i < allowed.length; i++) {
    const k = allowed[i];
    if (req[k] && !out[k]) missing.push({ key: k, label: label[k] });
  }

  if (missing.length) {
    return {
      ok: false,
      error: 'missing_member_fields',
      missing: missing,
      expected: allowed.map(k => ({ key: k, label: label[k], required: !!req[k] }))
    };
  }

  return { ok: true, json: JSON.stringify({ fields: out }), fields: out };
}



function _generateAccessCode_() {
  let out = '';
  for (let i = 0; i < ACCESS_CODE_LEN; i++) {
    out += ACCESS_CODE_CHARS.charAt(Math.floor(Math.random() * ACCESS_CODE_CHARS.length));
  }
  return out;
}

function _generateUniqueAccessCode_(quizSheet, quizHeaders) {
  const idx = quizHeaders.indexOf('access_code');
  if (idx === -1) return _generateAccessCode_();

  const lastRow = quizSheet.getLastRow();
  const existing = {};
  if (lastRow >= 2) {
    const vals = quizSheet.getRange(2, idx + 1, lastRow - 1, 1).getValues();
    for (let i = 0; i < vals.length; i++) {
      const c = String(vals[i][0] || '').trim().toUpperCase();
      if (c) existing[c] = true;
    }
  }

  for (let t = 0; t < 20; t++) {
    const code = _generateAccessCode_();
    if (!existing[code]) return code;
  }
  // ultra-rare fallback
  return _generateAccessCode_() + _generateAccessCode_().slice(0, 2);
}

function _parseIsoMs_(s) {
  const v = String(s || '').trim();
  if (!v) return null;
  const ms = Date.parse(v);
  return isNaN(ms) ? null : ms;
}

function _computeOpenState_(open_at, close_at, nowMs) {
  const o = _parseIsoMs_(open_at);
  const c = _parseIsoMs_(close_at);

  if (o != null && o > nowMs) return 'UPCOMING';
  if (c != null && nowMs > c) return 'CLOSED';

  // Default OPEN (including both blank)
  if ((o == null || o <= nowMs) && (c == null || nowMs <= c)) return 'OPEN';

  return 'OPEN';
}

function _computeQuizCounts_(quizzes, nowMs) {
  const counts = { draft:0, open:0, upcoming:0, closed:0, archived:0 };

  for (let i = 0; i < quizzes.length; i++) {
    const q = quizzes[i] || {};
    const st = String(q.status || '').trim().toUpperCase();
    if (st === 'DRAFT') counts.draft++;
    if (st === 'ARCHIVED') counts.archived++;

    const os = _computeOpenState_(q.open_at, q.close_at, nowMs);
    if (os === 'OPEN') counts.open++;
    else if (os === 'UPCOMING') counts.upcoming++;
    else if (os === 'CLOSED') counts.closed++;
  }
  return counts;
}

function _makeQuizSorter_(sortKey) {
  const s = String(sortKey || '').trim();

  if (s === 'created_at_desc') {
    return (a,b) => (_parseIsoMs_(b.created_at)||0) - (_parseIsoMs_(a.created_at)||0);
  }
  if (s === 'open_at_asc') {
    return (a,b) => {
      const aa = _parseIsoMs_(a.open_at);
      const bb = _parseIsoMs_(b.open_at);
      if (aa == null && bb == null) return 0;
      if (aa == null) return 1;
      if (bb == null) return -1;
      return aa - bb;
    };
  }
  if (s === 'title_asc') {
    return (a,b) => String(a.title||'').localeCompare(String(b.title||''), undefined, { sensitivity:'base' });
  }

  // default updated_at_desc
  return (a,b) => (_parseIsoMs_(b.updated_at)||0) - (_parseIsoMs_(a.updated_at)||0);
}

function _countQuizItems_(teacher_quiz_id) {
  const ss = SpreadsheetApp.openById(DB_ID);
  const sh = ss.getSheetByName(SH_QUIZ_ITEMS);
  const headers = _getHeaders_(sh);

  const idx = headers.indexOf('teacher_quiz_id');
  if (idx === -1) throw new Error('Missing header: teacher_quiz_id');

  const lastRow = sh.getLastRow();
  if (lastRow < 2) return 0;

  const vals = sh.getRange(2, idx + 1, lastRow - 1, 1).getValues();
  let n = 0;
  for (let i = 0; i < vals.length; i++) {
    if (String(vals[i][0] || '').trim() === teacher_quiz_id) n++;
  }
  return n;
}

function _countQuizItemsBulk_(teacherQuizIds) {
  const set = {};
  for (let i = 0; i < teacherQuizIds.length; i++) set[String(teacherQuizIds[i]||'').trim()] = 0;

  const ss = SpreadsheetApp.openById(DB_ID);
  const sh = ss.getSheetByName(SH_QUIZ_ITEMS);
  const headers = _getHeaders_(sh);

  const idx = headers.indexOf('teacher_quiz_id');
  if (idx === -1) throw new Error('Missing header: teacher_quiz_id');

  const lastRow = sh.getLastRow();
  if (lastRow < 2) return set;

  const vals = sh.getRange(2, idx + 1, lastRow - 1, 1).getValues();
  for (let i = 0; i < vals.length; i++) {
    const id = String(vals[i][0] || '').trim();
    if (id in set) set[id] = (set[id] || 0) + 1;
  }
  return set;
}

function _cleanupQuizSnapshots_(qiSh, qiHeaders, teacher_quiz_id) {
  const idxQuiz = qiHeaders.indexOf('teacher_quiz_id');
  if (idxQuiz === -1) return;

  const lastRow = qiSh.getLastRow();
  if (lastRow < 2) return;

  const vals = qiSh.getRange(2, idxQuiz + 1, lastRow - 1, 1).getValues();

  const toDelete = [];
  for (let i = 0; i < vals.length; i++) {
    if (String(vals[i][0] || '').trim() === String(teacher_quiz_id).trim()) {
      toDelete.push(i + 2);
    }
  }

  toDelete.sort((a,b)=>b-a).forEach(r => { if (r > 1) qiSh.deleteRow(r); });
}

