/**
 * Inline normalization: minimal required fields only.
 * Requires: stem, option_a, option_b, correct points to non-empty option.
 * Subject fallback: quiz subject if inline subject blank.
 */
function _normalizeInlineItem_(inline, quizSubject) {
  const o = inline || {};
  const out = {};

  out.stem = String(o.stem || '').trim();
  out.option_a = String(o.option_a || '').trim();
  out.option_b = String(o.option_b || '').trim();
  out.option_c = String(o.option_c || '').trim();
  out.option_d = String(o.option_d || '').trim();
  out.option_e = String(o.option_e || '').trim();
  out.option_f = String(o.option_f || '').trim();

  out.fb_a = String(o.fb_a || '').trim();
  out.fb_b = String(o.fb_b || '').trim();
  out.fb_c = String(o.fb_c || '').trim();
  out.fb_d = String(o.fb_d || '').trim();
  out.fb_e = String(o.fb_e || '').trim();
  out.fb_f = String(o.fb_f || '').trim();

  out.correct = String(o.correct || '').trim().toUpperCase();

  out.rationale = String(o.rationale || '').trim();
  out.rationale_img = String(o.rationale_img || '').trim();

  out.subject = String(o.subject || '').trim() || String(quizSubject || '').trim();
  out.topic = String(o.topic || '').trim();
  const dNorm = _normalizeDifficulty_(String(o.difficulty || '').trim());
  if (dNorm === null) throw new Error('invalid_difficulty');
  out.difficulty = dNorm;

  out.marks = String(o.marks || '').trim(); // optional

  if (!out.stem) throw new Error('inline_missing_stem');
  if (!out.option_a || !out.option_b) throw new Error('inline_need_at_least_A_and_B');

  const v = _validateCorrect_(out);
  if (!v.ok) throw new Error(v.error);

  return out;
}

