/** Update helpers that only set when key is present */
function _maybeSet_(patch, src, key, fn) {
  if (!_hasOwn_(src, key)) return;
  patch[key] = fn(src[key]);
}
function _maybeSetNum_(patch, src, key) {
  if (!_hasOwn_(src, key)) return;
  const v = String(src[key] == null ? '' : src[key]).trim();
  if (!v) return; // ignore blank numeric updates
  const n = parseInt(v, 10);
  if (isNaN(n)) return;
  patch[key] = String(n);
}
function _maybeSetBool_(patch, src, key) {
  if (!_hasOwn_(src, key)) return;

  const v = src[key];
  const s = String(v).trim().toUpperCase();

  const b =
    v === true ||
    s === 'TRUE' ||
    s === '1' ||
    s === 'YES' ||
    s === 'Y';

  patch[key] = b ? 'TRUE' : 'FALSE';
}


/* =========================
 * teacher.quiz.clone
 * =========================
 * Creates a NEW quiz (DRAFT) copied from an existing quiz.
 *
 * Request:
 *  {
 *    action: "teacher.quiz.clone",
 *    token: "...",
 *    teacher_quiz_id: "tq_source",
 *    new_title: "Optional new title",
 *    copy_schedule: false,      // default false: open_at/close_at cleared
 *    archive_source: false      // default false
 *  }
 *
 * Response:
 *  {
 *    ok:true,
 *    source_teacher_quiz_id:"tq_source",
 *    teacher_quiz_id:"tq_new",
 *    access_code:"NEWCODE",
 *    items:[ {bank_item_id:"tbi_x", marks:1}, ... ]  // only if source is PUBLISHED and snapshots exist
 *  }
 *
 * IMPORTANT:
 * - We do NOT auto-publish the clone.
 * - Frontend should call teacher.quiz.publish with the returned items (after edits/reorder).
 */
function _handleTeacherQuizClone_({ token, body, p }) {
  const gate = _requireTeacher_({ token });
  if (!gate.ok) return _json(gate.payload, gate.code);

  const teacher_id = gate.teacher_id;

  const getS = (k) => String(((p && p[k]) || (body && body[k]) || '')).trim();
  const getAny = (k) => (p && (k in p)) ? p[k] : ((body && (k in body)) ? body[k] : undefined);

  const sourceId = getS('teacher_quiz_id');
  if (!sourceId) return _json({ ok:false, error:'missing_teacher_quiz_id' }, 400);

  const copySchedule = _toBoolDefault_(getAny('copy_schedule'), false);
  const archiveSource = _toBoolDefault_(getAny('archive_source'), false);

  const ss = SpreadsheetApp.openById(DB_ID);

  // --- Load source quiz
  const qSh = ss.getSheetByName(SH_TEACHER_QUIZZES);
  const qHeaders = _getHeaders_(qSh);

  const srcRow = _findRowIndexBy_(qSh, qHeaders, 'teacher_quiz_id', sourceId);
  if (srcRow <= 0) return _json({ ok:false, error:'not_found' }, 404);

  const src = _readObjAtRow_(qSh, qHeaders, srcRow);
  if (String(src.teacher_id || '').trim() !== teacher_id) return _json({ ok:false, error:'forbidden' }, 403);

  const srcStatus = String(src.status || '').trim().toUpperCase();

  // --- Create new quiz row (DRAFT)
  const now = _iso(new Date());
  const newId = _newId_('tq');
  const newCode = _generateUniqueAccessCode_(qSh, qHeaders);

  const requestedTitle = String(getAny('new_title') || '').trim();
  const title = requestedTitle || (String(src.title || '').trim() + ' (Copy)');

  const preset = String(src.preset || '').trim().toUpperCase();
  const policy = String(src.results_release_policy || '').trim().toUpperCase() || 'IMMEDIATE';

  const showRes = String(src.show_results || '').trim().toUpperCase() || 'TRUE';

  const obj = {
    teacher_quiz_id: newId,
    teacher_id: teacher_id,

    title: title,
    subject: String(src.subject || '').trim(),

    duration_minutes: String(src.duration_minutes || '').trim(),

    shuffle_questions: String(src.shuffle_questions || '').trim() || 'TRUE',
    shuffle_options: String(src.shuffle_options || '').trim() || 'TRUE',
    max_attempts: String(src.max_attempts || '').trim() || '0',
    show_review: String(src.show_review || '').trim() || 'TRUE',

    // ✅ FIX #7: clone preserves show_results/preset/policy (core preset behavior)
    show_results: showRes,
    show_result:  showRes,

    preset: preset || '',
    results_release_policy: policy,

    // clone is a fresh draft — release flags should reset
    results_released: 'FALSE',
    results_released_at: '',

    open_at: copySchedule ? String(src.open_at || '').trim() : '',
    close_at: copySchedule ? String(src.close_at || '').trim() : '',

    status: 'DRAFT',
    access_code: newCode,

    custom_fields_json: String(src.custom_fields_json || '').trim() || JSON.stringify({ fields: [] }),
    draft_items_json: JSON.stringify({ items: [] }),

        // ---- grading config clone ----
    grading_policy: String(src.grading_policy || GRADING_POLICY_DEFAULT).trim().toUpperCase(),
    grade_bands_json: String(src.grade_bands_json || DEFAULT_GRADE_BANDS_JSON).trim(),
    pass_threshold_pct: String(src.pass_threshold_pct || '').trim(),
    score_display_policy: String(src.score_display_policy || SCORE_DISPLAY_POLICY_DEFAULT).trim().toUpperCase(),
    created_at: now,
    updated_at: now
  };
  const gc = _normalizeGradingConfig_(obj);
  obj.grading_policy = gc.grading_policy;
  obj.grade_bands_json = gc.grade_bands_json;
  obj.pass_threshold_pct = String(gc.pass_threshold_pct);
  obj.score_display_policy = gc.score_display_policy;
  _appendObj_(qSh, qHeaders, obj);

  // --- If source is PUBLISHED, return items derived from snapshots
  let items = [];
  if (srcStatus === 'PUBLISHED') {
    items = _extractPublishItemsFromSnapshots_(ss, sourceId);
  }

  // Save cloned items into draft_items_json
  if (items && items.length) {
    const ids = items.map(x => String(x.bank_item_id || '').trim()).filter(Boolean);
    const draftStr = _normalizeDraftItemsJson_({ items: ids });

    const newRow = _findRowIndexBy_(qSh, qHeaders, 'teacher_quiz_id', newId);
    if (newRow > 0) {
      _updateObjAtRow_(qSh, qHeaders, newRow, { draft_items_json: draftStr, updated_at: now });
    }
  }

  // --- Optional: archive source
  if (archiveSource) {
    _updateObjAtRow_(qSh, qHeaders, srcRow, {
      status: 'ARCHIVED',
      updated_at: now
    });
  }

  return _json({
    ok: true,
    source_teacher_quiz_id: sourceId,
    teacher_quiz_id: newId,
    access_code: newCode,
    items: items
  });
}
/**
 * Reads teacher_quiz_items snapshots for a published quiz and returns
 * ordered {bank_item_id, marks} list.
 *
 * Assumes teacher_quiz_items has at least:
 * - teacher_quiz_id
 * - position
 * - bank_item_id
 * - snap_marks
 */
function _extractPublishItemsFromSnapshots_(ss, sourceQuizId) {
  const qiSh = ss.getSheetByName(SH_QUIZ_ITEMS);
  const headers = _getHeaders_(qiSh);

  const idxQuiz = headers.indexOf('teacher_quiz_id');
  const idxPos  = headers.indexOf('position');
  const idxBank = headers.indexOf('bank_item_id');

  // snap_marks is expected; if missing, we default marks to 1
  const idxMarks = headers.indexOf('snap_marks');

  if (idxQuiz === -1 || idxPos === -1 || idxBank === -1) {
    // If headings differ, fail soft: return empty list (clone still works)
    return [];
  }

  const lastRow = qiSh.getLastRow();
  if (lastRow < 2) return [];

  const values = qiSh.getRange(2, 1, lastRow - 1, qiSh.getLastColumn()).getValues();

  let rows = [];
  for (let i = 0; i < values.length; i++) {
    const r = values[i];
    if (String(r[idxQuiz] || '').trim() !== String(sourceQuizId).trim()) continue;

    const pos = _toIntDefault_(r[idxPos], 0);
    const bankId = String(r[idxBank] || '').trim();
    if (!bankId) continue;

    let marks = 1;
    if (idxMarks !== -1) {
      const m = _toIntDefault_(r[idxMarks], 1);
      marks = (m > 0) ? m : 1;
    }

    rows.push({ pos, bank_item_id: bankId, marks });
  }

  rows.sort((a,b) => a.pos - b.pos);

  // return in publish-ready shape
  return rows.map(x => ({ bank_item_id: x.bank_item_id, marks: x.marks }));
}

