function _handleTeacherClassesList_({ token, body, p }) {
  const gate = _requireTeacher_({ token });
  if (!gate.ok) return _json(gate.payload, gate.code);

  const teacher_id = gate.teacher_id;
  const getS = (k) => String(((p && p[k]) || (body && body[k]) || '')).trim();

  const status = (getS('status') || 'ANY').toUpperCase(); // ACTIVE|ARCHIVED|ANY
  const q = getS('q').toLowerCase(); // title contains
  const include_counts = _toBoolDefault_(getS('include_counts'), false);

  const ss = SpreadsheetApp.openById(DB_ID);
  const sh = ss.getSheetByName(SH_CLASSES);
  const headers = _getHeaders_(sh);

  const lastRow = sh.getLastRow();
  if (lastRow < 2) return _json({ ok:true, count:0, items:[] });

  const values = sh.getRange(2, 1, lastRow - 1, sh.getLastColumn()).getValues();

  let classes = [];
  for (let i = 0; i < values.length; i++) {
    const obj = _rowToObj_(headers, values[i]);
    if (String(obj.teacher_id || '').trim() !== teacher_id) continue;

    const st = String(obj.status || '').trim().toUpperCase() || 'ACTIVE';
    if (status !== 'ANY' && st !== status) continue;

    const title = String(obj.title || '').trim();
    if (q && !title.toLowerCase().includes(q)) continue;

    classes.push({
      class_id: String(obj.class_id || '').trim(),
      title: title,
      status: st,
      join_code: String(obj.join_code || '').trim(), // teacher can see this
      created_at: String(obj.created_at || '').trim(),
      updated_at: String(obj.updated_at || '').trim()
    });
  }

  classes.sort((a,b)=> (_parseIsoMs_(b.updated_at)||0) - (_parseIsoMs_(a.updated_at)||0));

  // Optional counts (member_count + quiz_count)
  if (include_counts && classes.length) {
    const classIds = classes.map(x => x.class_id);
