  if (memLast < 2) return _json({ ok:true, count:0, items:[] });

  const memVals = memSh.getRange(2, 1, memLast - 1, memSh.getLastColumn()).getValues();

  const midx = _indexMap_(memHeaders, [
    'class_id','user_id','status','member_fields_json','updated_at'
  ]);

  const membershipByClass = {}; // class_id -> { member_fields_json, member_fields }
  let classIds = [];

  for (let i = 0; i < memVals.length; i++) {
    const r = memVals[i];

    if (String(r[midx.user_id] || '').trim() !== user_id) continue;

    const st = String(r[midx.status] || '').trim().toUpperCase() || 'ACTIVE';
    if (st !== 'ACTIVE') continue;

    const cid = String(r[midx.class_id] || '').trim();
    if (!cid) continue;

    const mfJson = String(r[midx.member_fields_json] || '').trim();
    const mfObj = _parseJsonSafe_(mfJson, { fields:{} });
    const mf = (mfObj && mfObj.fields && typeof mfObj.fields === 'object') ? mfObj.fields : {};

    membershipByClass[cid] = { member_fields_json: mfJson, member_fields: mf };
    classIds.push(cid);
  }

  classIds = _uniq_(classIds);
  if (!classIds.length) return _json({ ok:true, count:0, items:[] });

  // ---- load classes
  const clsSh = ss.getSheetByName(SH_CLASSES);
  const clsHeaders = _getHeaders_(clsSh);
  const clsLast = clsSh.getLastRow();
  const clsVals = (clsLast >= 2) ? clsSh.getRange(2, 1, clsLast - 1, clsSh.getLastColumn()).getValues() : [];

  const idxClassId = clsHeaders.indexOf('class_id');
  const idxTitle = clsHeaders.indexOf('title');
  const idxTeacher = clsHeaders.indexOf('teacher_id');
  const idxStatus = clsHeaders.indexOf('status');
  const idxUpdated = clsHeaders.indexOf('updated_at');
  const idxSchema = clsHeaders.indexOf('custom_fields_json'); // may be -1 in older sheets

  const classMap = {};     // class_id -> class obj
  const teacherIds = [];   // gather for public info

  for (let i = 0; i < clsVals.length; i++) {
    const r = clsVals[i];
    const cid = (idxClassId !== -1) ? String(r[idxClassId] || '').trim() : '';
    if (!cid) continue;

    // only classes the user belongs to
    if (!(cid in membershipByClass)) continue;

    const tid = (idxTeacher !== -1) ? String(r[idxTeacher] || '').trim() : '';
    if (tid) teacherIds.push(tid);

    classMap[cid] = {
      class_id: cid,
      title: (idxTitle !== -1) ? String(r[idxTitle] || '').trim() : '',
      teacher_id: tid, // internal only, not returned
      status: (idxStatus !== -1) ? (String(r[idxStatus] || '').trim().toUpperCase() || 'ACTIVE') : 'ACTIVE',
      updated_at: (idxUpdated !== -1) ? String(r[idxUpdated] || '').trim() : '',
      custom_fields_json: (idxSchema !== -1) ? String(r[idxSchema] || '').trim() : ''
    };
  }

  // ---- teacher public map (best effort)
  const teacherPublic = _getTeacherPublicMap_(_uniq_(teacherIds));

  // ---- quiz counts by class
  const quizCounts = _countPublishedQuizzesByClass_(ss, classIds);

  // ---- build output (NO teacher_id exposed)
  let out = [];

  for (let i = 0; i < classIds.length; i++) {
    const cid = classIds[i];
    const cls = classMap[cid];
    if (!cls) continue;

    const mem = membershipByClass[cid] || { member_fields_json:'', member_fields:{} };

    const schemaStr = String(cls.custom_fields_json || '').trim() || JSON.stringify({ fields: [] });
    const vf = _validateMemberFieldsJson_(schemaStr, { fields: mem.member_fields });
    const missing_keys = vf.ok ? [] : (vf.missing || []).map(x => String(x.key || '').trim()).filter(Boolean);

    const tid = String(cls.teacher_id || '').trim();
    const tpub = teacherPublic[tid] || { teacher_name:'', teacher_email:'' };

    out.push({
      class_id: cid,
      title: cls.title,
      status: cls.status,
      updated_at: cls.updated_at,

      teacher_name: tpub.teacher_name,
      teacher_email: tpub.teacher_email,

      quiz_counts: quizCounts[cid] || { published_total:0, open:0, upcoming:0, closed:0 },

      member_profile: {
        profile_complete: missing_keys.length === 0,
        missing_keys: missing_keys
      }
    });
  }

  out.sort((a,b)=> (_parseIsoMs_(b.updated_at)||0) - (_parseIsoMs_(a.updated_at)||0));

  return _json({ ok:true, count: out.length, items: out });
}


/**
 * candidate.quizzes.list
 * Lists PUBLISHED quizzes linked to a class (via teacher_quiz_classes).
 * Does NOT return access_code.
 */
function _handleCandidateQuizzesList_({ token, body, p }) {
  const gate = _requireUser_({ token });
  if (!gate.ok) return _json(gate.payload, gate.code);
  const user_id = gate.user_id;

  const getS = (k) => String(((p && p[k]) || (body && body[k]) || '')).trim();
  const class_id = getS('class_id');
  if (!class_id) return _json({ ok:false, error:'missing_class_id' }, 400);

  const ss = SpreadsheetApp.openById(DB_ID);

  // membership gate
  if (!_isMemberActive_(ss, class_id, user_id)) {
    return _json({ ok:false, error:'forbidden_not_class_member' }, 403);
  }

  // gather quiz ids from mappings (ACTIVE links)
  const mapSh = ss.getSheetByName(SH_QUIZ_CLASSES);
  const mapHeaders = _getHeaders_(mapSh);
  const mapLast = mapSh.getLastRow();
  const mapVals = (mapLast >= 2) ? mapSh.getRange(2, 1, mapLast - 1, mapSh.getLastColumn()).getValues() : [];
  const midx = _indexMap_(mapHeaders, ['teacher_quiz_id','class_id','status']);

  let quizIds = [];
  for (let i = 0; i < mapVals.length; i++) {
    const r = mapVals[i];
    if (String(r[midx.class_id] || '').trim() !== class_id) continue;

    const st = String(r[midx.status] || '').trim().toUpperCase() || 'ACTIVE';
    if (st !== 'ACTIVE') continue;

    const qid = String(r[midx.teacher_quiz_id] || '').trim();
    if (qid) quizIds.push(qid);
  }
  quizIds = _uniq_(quizIds);
  if (!quizIds.length) return _json({ ok:true, count:0, items:[] });

  // load quizzes
  const qSh = ss.getSheetByName(SH_TEACHER_QUIZZES);
  const qHeaders = _getHeaders_(qSh);
  const qLast = qSh.getLastRow();
  const qVals = (qLast >= 2) ? qSh.getRange(2, 1, qLast - 1, qSh.getLastColumn()).getValues() : [];

  const nowMs = Date.now();

  const qMap = {};
  for (let i = 0; i < qVals.length; i++) {
    const o = _rowToObj_(qHeaders, qVals[i]);
    const qid = String(o.teacher_quiz_id || '').trim();
    if (!qid) continue;
    qMap[qid] = o;
  }

  // one-pass attempt counts for this class+user across all quizzes
const attemptSumMap = _summarizeUserAttemptsForClassQuizzes_(ss, class_id, user_id, quizIds);

  let out = [];
  for (let i = 0; i < quizIds.length; i++) {
    const qid = quizIds[i];
    const q = qMap[qid];
    if (!q) continue;

    const st = String(q.status || '').trim().toUpperCase();
    if (st !== 'PUBLISHED') continue; // only published visible to students

    const open_state = _computeOpenState_(q.open_at, q.close_at, nowMs);

const sum = attemptSumMap[qid] || {
  attempts_used: 0,
  in_progress_attempt_id: '',
  latest_attempt_id: '',
  latest_ended_attempt_id: ''
};

const max = _toIntDefault_(q.max_attempts, 0);
const used = _toIntDefault_(sum.attempts_used, 0);
const hasInProgress = !!String(sum.in_progress_attempt_id || '').trim();

let can_start = (open_state === 'OPEN') && !hasInProgress;
if (max > 0 && used >= max) can_start = false;

let start_lock_reason = 'OK';
if (open_state === 'UPCOMING') start_lock_reason = 'UPCOMING';
else if (open_state === 'CLOSED') start_lock_reason = 'CLOSED';
else if (hasInProgress) start_lock_reason = 'IN_PROGRESS';
else if (max > 0 && used >= max) start_lock_reason = 'MAX_ATTEMPTS';

const policy = _normalizeResultsPolicy_(q.results_release_policy);
const gate = _computeResultsGatePolicy_(q, nowMs);
const statusPack = _computeResultsStatusForDashboard_(q, sum, nowMs);

out.push({
  teacher_quiz_id: qid,
  title: String(q.title || '').trim(),
  subject: String(q.subject || '').trim(),

  mode: String(q.mode || 'TIMED').trim().toUpperCase(),
  duration_minutes: String(q.duration_minutes || '').trim(),

  shuffle_questions: _toBoolDefault_(q.shuffle_questions, true),
  shuffle_options: _toBoolDefault_(q.shuffle_options, true),

  max_attempts: String(max),
  attempts_used: String(used),
  attempts_remaining: (max > 0) ? String(Math.max(max - used, 0)) : '',

  // NEW: ids for dashboard buttons
  in_progress_attempt_id: String(sum.in_progress_attempt_id || '').trim(),
  latest_attempt_id: String(sum.latest_attempt_id || '').trim(),
  latest_ended_attempt_id: String(sum.latest_ended_attempt_id || '').trim(),

  can_start: !!can_start,
  start_lock_reason,

  show_review: _toBoolDefault_(q.show_review, true),
  show_results: _getShowResultsBool_(q),

  preset: String(q.preset || '').trim().toUpperCase(),
  results_release_policy: policy,
  results_released: _toBoolDefault_(q.results_released, false),
  results_released_at: String(q.results_released_at || '').trim(),

  // keep old gate fields (still useful)
  results_gate_now: !!gate.met,
  results_gate_reason: String(gate.reason || ''),
  results_available_at: String(gate.available_at || ''),

  // NEW: dashboard-ready status
  results_status: String(statusPack.results_status || 'HIDDEN'),
  results_status_reason: String(statusPack.results_gate_reason || ''),
  results_status_available_at: String(statusPack.results_available_at || ''),

  open_at: String(q.open_at || '').trim(),
  close_at: String(q.close_at || '').trim(),
  open_state,

  updated_at: String(q.updated_at || '').trim(),
  created_at: String(q.created_at || '').trim()
});
  }

  // newest updated first
  out.sort((a,b)=> (_parseIsoMs_(b.updated_at)||0) - (_parseIsoMs_(a.updated_at)||0));

  return _json({ ok:true, count: out.length, items: out });
}

function _handleCandidateClassGet_({ token, body, p }) {
  const gate = _requireUser_({ token });
  if (!gate.ok) return _json(gate.payload, gate.code);

  const user_id = gate.user_id;

  const getS = (k) => String(((p && p[k]) || (body && body[k]) || '')).trim();
  const class_id = getS('class_id');
