  const mfObj = _parseJsonSafe_(mfJson, { fields:{} });
  const member_fields = (mfObj && mfObj.fields && typeof mfObj.fields === 'object') ? mfObj.fields : {};

  // compute profile completeness + missing keys
  const vf = _validateMemberFieldsJson_(schemaStr, { fields: member_fields });
  const missing_keys = vf.ok ? [] : (vf.missing || []).map(x => String(x.key || '').trim()).filter(Boolean);

