      teacher_email: tpub.teacher_email,
      status: String(clsObj.status || '').trim(),
      updated_at: String(clsObj.updated_at || '').trim()
    },
    fields: fields,
    member_fields_json: mfJson,
    member_fields: member_fields,
    member_profile: {
      profile_complete: missing_keys.length === 0,
      missing_keys: missing_keys
    },
