function _handleCandidateClassProfileUpdate_({ token, body, p }) {
  const gate = _requireUser_({ token });
  if (!gate.ok) return _json(gate.payload, gate.code);

  const user_id = gate.user_id;
  const user = gate.user || {};

  const getAny = (k) => (p && (k in p)) ? p[k] : ((body && (k in body)) ? body[k] : undefined);
  const getS = (k) => String(((p && p[k]) || (body && body[k]) || '')).trim();

  const class_id = getS('class_id');
  if (!class_id) return _json({ ok:false, error:'missing_class_id' }, 400);

  const ss = SpreadsheetApp.openById(DB_ID);

  // membership gate
  const mem = _getMembershipByClassUser_(ss, class_id, user_id);
  if (!mem.found || String(mem.status || '').toUpperCase() !== 'ACTIVE') {
    return _json({ ok:false, error:'forbidden_not_class_member' }, 403);
  }

  // load class schema
  const cls = _getClassById_(class_id);
  if (!cls.found) return _json({ ok:false, error:'class_not_found' }, 404);

  const schemaStr = String((cls.obj && cls.obj.custom_fields_json) || '').trim() || JSON.stringify({ fields: [] });

  // accept member_fields_json or member_fields
  const memberInput =
    (_hasOwn_(body || {}, 'member_fields_json') || (p && _hasOwn_(p,'member_fields_json')))
      ? getAny('member_fields_json')
      : ((_hasOwn_(body || {}, 'member_fields') || (p && _hasOwn_(p,'member_fields')))
          ? getAny('member_fields')
          : undefined);

  const vf = _validateMemberFieldsJson_(schemaStr, memberInput);
  if (!vf.ok) {
    const missing_keys = (vf.missing || []).map(x => String(x.key || '').trim()).filter(Boolean);
    return _json({
      ok:false,
      error:'missing_member_fields',
      missing_keys: missing_keys,
      fields: _schemaToFields_(schemaStr)
    }, 400);
  }

