/* =========================
 * Phase 3 helpers
 * ========================= */

function _requireUser_({ token }) {
  const auth = _authVerify_(token);
  if (!auth.ok) return { ok:false, code:401, payload:{ ok:false, error:'auth_verify_failed', detail:auth.error||'' } };

  const user = auth.user || {};
  const userId = String(user.user_id || '').trim();
  if (!userId) return { ok:false, code:500, payload:{ ok:false, error:'auth_missing_user_id' } };

  return { ok:true, user_id: userId, user: user };
}

// ================================
// Attempt summary (for dashboard)
// ================================
function _summarizeUserAttemptsForClassQuizzes_(ss, class_id, user_id, quizIds) {
  const out = {};
  (quizIds || []).forEach(qid => {
    const k = String(qid || '').trim();
    if (!k) return;
    out[k] = {
      attempts_used: 0,
      in_progress_attempt_id: '',
      in_progress_ms: -1,
      latest_attempt_id: '',
      latest_ms: -1,
      latest_ended_attempt_id: '',
      latest_ended_ms: -1
    };
  });

  const quizSet = {};
  Object.keys(out).forEach(k => quizSet[k] = true);
  if (!Object.keys(quizSet).length) return out;

  const sh = ss.getSheetByName(SH_ATTEMPTS);
  if (!sh) return out;

  const headers = _getHeaders_(sh);
  const idxAttempt = headers.indexOf('attempt_id');
  const idxQuiz = headers.indexOf('teacher_quiz_id');
  const idxClass = headers.indexOf('class_id');
  const idxUser = headers.indexOf('user_id');
  const idxStatus = headers.indexOf('status');

  // time columns (best-effort)
  const idxSub = headers.indexOf('submitted_at');
  const idxUpd = headers.indexOf('updated_at');
  const idxStart = headers.indexOf('started_at');

  if (idxAttempt === -1 || idxQuiz === -1 || idxClass === -1 || idxUser === -1 || idxStatus === -1) return out;

  const lastRow = sh.getLastRow();
  if (lastRow < 2) return out;

  const values = sh.getRange(2, 1, lastRow - 1, sh.getLastColumn()).getValues();

  const wantClass = String(class_id || '').trim();
  const wantUser = String(user_id || '').trim();

  for (let i = 0; i < values.length; i++) {
    const r = values[i];

    if (String(r[idxClass] || '').trim() !== wantClass) continue;
    if (String(r[idxUser] || '').trim() !== wantUser) continue;

    const qid = String(r[idxQuiz] || '').trim();
    if (!quizSet[qid]) continue;

    const st = String(r[idxStatus] || '').trim().toUpperCase();
    if (st === 'ABANDONED') continue;

    const attempt_id = String(r[idxAttempt] || '').trim();
    if (!attempt_id) continue;

    // best timestamp
    const ts =
      (idxSub !== -1 ? String(r[idxSub] || '').trim() : '') ||
      (idxUpd !== -1 ? String(r[idxUpd] || '').trim() : '') ||
      (idxStart !== -1 ? String(r[idxStart] || '').trim() : '');

    const ms = _parseIsoMs_(ts) || 0;

    const s = out[qid];
    s.attempts_used++;

    if (ms > s.latest_ms) {
      s.latest_ms = ms;
      s.latest_attempt_id = attempt_id;
    }

    if (st === 'IN_PROGRESS') {
      if (ms > s.in_progress_ms) {
        s.in_progress_ms = ms;
        s.in_progress_attempt_id = attempt_id;
      }
    } else {
      // treat any non-IN_PROGRESS (except ABANDONED) as ended
      if (ms > s.latest_ended_ms) {
        s.latest_ended_ms = ms;
        s.latest_ended_attempt_id = attempt_id;
      }
    }
  }

  // strip internal ms fields
  Object.keys(out).forEach(k => {
    delete out[k].in_progress_ms;
    delete out[k].latest_ms;
    delete out[k].latest_ended_ms;
  });

  return out;
}

function _computeResultsStatusForDashboard_(quizObj, sum, nowMs) {
  const used = _toIntDefault_(sum.attempts_used, 0);
  const hasEnded = !!String(sum.latest_ended_attempt_id || '').trim();

  if (used <= 0) {
    return { results_status: 'HIDDEN', results_gate_reason: 'no_attempts', results_available_at: '' };
  }

  // attempt exists but none ended yet
  if (!hasEnded) {
    return { results_status: 'PENDING', results_gate_reason: 'no_ended_attempt', results_available_at: '' };
  }

  const gate = _computeResultsGatePolicy_(quizObj, nowMs);
  if (!gate.met) {
    return {
      results_status: 'PENDING',
      results_gate_reason: String(gate.reason || ''),
      results_available_at: String(gate.available_at || '')
    };
  }

  const showRes = _getShowResultsBool_(quizObj);
  const showRev = _toBoolDefault_(quizObj.show_review, false);

  if (!showRes && !showRev) {
    return { results_status: 'HIDDEN', results_gate_reason: 'teacher_hidden', results_available_at: '' };
  }

  return { results_status: 'AVAILABLE', results_gate_reason: '', results_available_at: '' };
}

// ================================
// Results policy helpers (shared)
// ================================
function _normalizeResultsPolicy_(v) {
  let s = String(v || '').trim().toUpperCase();
  if (!s) s = 'IMMEDIATE';
  if (['IMMEDIATE', 'AFTER_CLOSE', 'MANUAL'].indexOf(s) === -1) s = 'IMMEDIATE';
  return s;
}

function _getShowResultsBool_(quizRowObj) {
  // Canonical: show_results
  if (quizRowObj && quizRowObj.show_results !== undefined) {
    return _toBoolDefault_(quizRowObj.show_results, true);
  }
  // Legacy fallback: show_result
  if (quizRowObj && quizRowObj.show_result !== undefined) {
    return _toBoolDefault_(quizRowObj.show_result, true);
  }
  return true; // default back-compat
}

/**
 * Policy gate: whether results are allowed to be shown NOW (time/release based).
 * (Still requires an ended attempt to actually display anything.)
 */
function _computeResultsGatePolicy_(quizObj, nowMs) {
  const pol = _normalizeResultsPolicy_(quizObj && quizObj.results_release_policy);

  if (pol === 'IMMEDIATE') {
    return { met: true, reason: 'IMMEDIATE', available_at: '' };
  }

  if (pol === 'AFTER_CLOSE') {
    const closeAt = String((quizObj && quizObj.close_at) || '').trim();
    if (!closeAt) return { met: false, reason: 'MISSING_CLOSE_AT', available_at: '' };

    const cMs = _parseIsoMs_(closeAt);
    if (cMs == null) return { met: false, reason: 'INVALID_CLOSE_AT', available_at: closeAt };

    if (nowMs >= cMs) return { met: true, reason: 'AFTER_CLOSE', available_at: closeAt };
    return { met: false, reason: 'AFTER_CLOSE_WAIT', available_at: closeAt };
  }

  // MANUAL
  const released = _toBoolDefault_(quizObj && quizObj.results_released, false);
  const relAt = String((quizObj && quizObj.results_released_at) || '').trim();
  if (released) return { met: true, reason: 'MANUAL_RELEASED', available_at: relAt };

  const rMs = _parseIsoMs_(relAt);
  if (rMs != null && nowMs >= rMs) return { met: true, reason: 'MANUAL_RELEASED', available_at: relAt };

  return { met: false, reason: 'MANUAL_WAIT', available_at: relAt };
}

/**
 * One-pass attempt counting for a user within a class across multiple quizzes.
 * Uses same rule as runner: counts all attempts except ABANDONED.
 */
function _countUserAttemptsMap_(ss, class_id, user_id, quizIds) {
  const out = {};
  (quizIds || []).forEach(qid => { out[String(qid || '').trim()] = 0; });

  if (!quizIds || !quizIds.length) return out;

  const sh = ss.getSheetByName(SH_ATTEMPTS);
  if (!sh) return out;

  const headers = _getHeaders_(sh);
  const idxQuiz = headers.indexOf('teacher_quiz_id');
  const idxCls  = headers.indexOf('class_id');
  const idxUser = headers.indexOf('user_id');
  const idxSt   = headers.indexOf('status');

  if (idxQuiz === -1 || idxCls === -1 || idxUser === -1 || idxSt === -1) return out;

  const lastRow = sh.getLastRow();
  if (lastRow < 2) return out;

  const want = {};
  Object.keys(out).forEach(k => { want[k] = true; });

  const values = sh.getRange(2, 1, lastRow - 1, sh.getLastColumn()).getValues();
  for (let i = 0; i < values.length; i++) {
    const r = values[i];

    if (String(r[idxCls] || '').trim() !== String(class_id).trim()) continue;
    if (String(r[idxUser] || '').trim() !== String(user_id).trim()) continue;

    const qid = String(r[idxQuiz] || '').trim();
    if (!want[qid]) continue;

