/**
 * Best-effort teacher public info lookup.
 * Returns map: { [teacher_id]: { teacher_name, teacher_email } }
 * If columns don't exist, values are ''.
 */
function _getTeacherPublicMap_(teacherIds) {
  const out = {};
  (teacherIds || []).forEach(id => {
    const tid = String(id || '').trim();
    if (tid) out[tid] = { teacher_name:'', teacher_email:'' };
  });

  const ss = SpreadsheetApp.openById(DB_ID);
  const sh = ss.getSheetByName(SH_TEACHERS);
  if (!sh) return out;

  const headers = _getHeaders_(sh);
  const idxId = headers.indexOf('teacher_id');
  if (idxId === -1) return out;

  // best-effort columns
  const idxName =
    (headers.indexOf('display_name') !== -1) ? headers.indexOf('display_name')
    : (headers.indexOf('name') !== -1) ? headers.indexOf('name')
    : -1;

  const idxEmail = headers.indexOf('email');

  const lastRow = sh.getLastRow();
  if (lastRow < 2) return out;

  const want = {};
  Object.keys(out).forEach(k => want[k] = true);

  const vals = sh.getRange(2, 1, lastRow - 1, sh.getLastColumn()).getValues();

  for (let i=0;i<vals.length;i++){
    const r = vals[i];
    const tid = String(r[idxId] || '').trim();
    if (!tid || !want[tid]) continue;

    out[tid] = {
      teacher_name: (idxName !== -1) ? String(r[idxName] || '').trim() : '',
      teacher_email: (idxEmail !== -1) ? String(r[idxEmail] || '').trim() : ''
    };
  }

  return out;
}

/**
 * Counts only PUBLISHED quizzes linked to each class.
 * Returns map: { [class_id]: { published_total, open, upcoming, closed } }
 */
function _countPublishedQuizzesByClass_(ss, classIds) {
  const out = {};
  (classIds || []).forEach(cid => {
    const c = String(cid || '').trim();
    if (c) out[c] = { published_total:0, open:0, upcoming:0, closed:0 };
  });
  if (!classIds || !classIds.length) return out;

  // map class -> quizIds (ACTIVE links only)
  const mapSh = ss.getSheetByName(SH_QUIZ_CLASSES);
  const mapHeaders = _getHeaders_(mapSh);
  const mapLast = mapSh.getLastRow();
  const mapVals = (mapLast >= 2) ? mapSh.getRange(2, 1, mapLast - 1, mapSh.getLastColumn()).getValues() : [];
  const midx = _indexMap_(mapHeaders, ['teacher_quiz_id','class_id','status']);

  const want = {};
  Object.keys(out).forEach(cid => want[cid] = true);

  const classToQuiz = {};
  const quizSet = {};

  for (let i=0;i<mapVals.length;i++){
    const r = mapVals[i];
    const cid = String(r[midx.class_id] || '').trim();
    if (!want[cid]) continue;

    const st = String(r[midx.status] || '').trim().toUpperCase() || 'ACTIVE';
    if (st !== 'ACTIVE') continue;

    const qid = String(r[midx.teacher_quiz_id] || '').trim();
    if (!qid) continue;

    if (!classToQuiz[cid]) classToQuiz[cid] = [];
    classToQuiz[cid].push(qid);
    quizSet[qid] = true;
  }

  const quizIds = Object.keys(quizSet);
  if (!quizIds.length) return out;

  // load quizzes
  const qSh = ss.getSheetByName(SH_TEACHER_QUIZZES);
  const qHeaders = _getHeaders_(qSh);
  const qLast = qSh.getLastRow();
  const qVals = (qLast >= 2) ? qSh.getRange(2, 1, qLast - 1, qSh.getLastColumn()).getValues() : [];

  const qMap = {};
  for (let i=0;i<qVals.length;i++){
    const o = _rowToObj_(qHeaders, qVals[i]);
    const qid = String(o.teacher_quiz_id || '').trim();
    if (qid && quizSet[qid]) qMap[qid] = o;
  }

  const nowMs = Date.now();

  // accumulate
  Object.keys(classToQuiz).forEach(cid => {
    const arr = classToQuiz[cid] || [];
    for (let i=0;i<arr.length;i++){
      const q = qMap[arr[i]];
      if (!q) continue;

      const st = String(q.status || '').trim().toUpperCase();
      if (st !== 'PUBLISHED') continue;

      out[cid].published_total++;
      const os = _computeOpenState_(q.open_at, q.close_at, nowMs);
      if (os === 'OPEN') out[cid].open++;
      else if (os === 'UPCOMING') out[cid].upcoming++;
      else if (os === 'CLOSED') out[cid].closed++;
    }
  });

  return out;
}


function _generateClassJoinCode_() {
  // reuse the same character set as quiz codes for simplicity
  let out = '';
  for (let i = 0; i < CLASS_JOIN_CODE_LEN; i++) {
