}

function _generateUniqueClassJoinCode_(classSheet, classHeaders) {
  const idx = classHeaders.indexOf('join_code');
  if (idx === -1) return _generateClassJoinCode_();

  const lastRow = classSheet.getLastRow();
  const existing = {};
  if (lastRow >= 2) {
    const vals = classSheet.getRange(2, idx + 1, lastRow - 1, 1).getValues();
    for (let i = 0; i < vals.length; i++) {
      const c = String(vals[i][0] || '').trim().toUpperCase();
      if (c) existing[c] = true;
    }
  }

  for (let t = 0; t < 30; t++) {
    const code = _generateClassJoinCode_();
    if (!existing[code]) return code;
  }
  return _generateClassJoinCode_() + _generateClassJoinCode_().slice(0, 2);
}

