    const values = sh.getRange(2, 1, lastRow - 1, sh.getLastColumn()).getValues();
    const wantQuiz = String(teacher_quiz_id || '').trim();

    for (let i = 0; i < values.length; i++) {
      const r = values[i];
      if (String(r[idxQuiz] || '').trim() !== wantQuiz) continue;

      const obj = _rowToObj_(headers, r);

      // Ensure quiz_item_id exists (runner relies on it)
      if (!String(obj.quiz_item_id || '').trim()) continue;

      out.push(obj);
    }

    // Sort by numeric position if present, else keep stable order
    out.sort((a, b) => {
      const ap = (idxPos !== -1) ? _toIntDefault_(a.position, 0) : 0;
      const bp = (idxPos !== -1) ? _toIntDefault_(b.position, 0) : 0;
      return ap - bp;
    });

    return out;
  } catch (e) {
    return out;
  }
}


