function _uniq_(arr) {
  const seen = {};
  const out = [];
  for (let i = 0; i < (arr || []).length; i++) {
    const v = String(arr[i] || '').trim();
    if (!v || seen[v]) continue;
    seen[v] = true;
    out.push(v);
  }
  return out;
}

