function _handleTeacherQuizReleaseResults_({ token, body, p }) {
  const gate = _requireTeacher_({ token });
  if (!gate.ok) return _json(gate.payload, gate.code);
  const teacher_id = gate.teacher_id;
  const get = (k) => (p && (k in p)) ? p[k] : ((body && (k in body)) ? body[k] : undefined);
  const teacher_quiz_id = String(get('teacher_quiz_id') || '').trim();
  if (!teacher_quiz_id) return _json({ ok:false, error:'missing_teacher_quiz_id' }, 400);

  const ss = SpreadsheetApp.openById(DB_ID);
  const sh = ss.getSheetByName(SH_TEACHER_QUIZZES);
  const headers = _getHeaders_(sh);
  const rowIndex = _findRowIndexBy_(sh, headers, 'teacher_quiz_id', teacher_quiz_id);
  if (rowIndex <= 0) return _json({ ok:false, error:'not_found' }, 404);

  const quiz = _readObjAtRow_(sh, headers, rowIndex);
  if (String(quiz.teacher_id || '').trim() !== teacher_id) return _json({ ok:false, error:'forbidden' }, 403);

  const status = String(quiz.status || '').trim().toUpperCase();
  if (status !== 'PUBLISHED') return _json({ ok:false, error:'only_published_quizzes_can_be_released' }, 400);

  const policy = String(quiz.results_release_policy || '').trim().toUpperCase();
  if (policy !== 'MANUAL') return _json({ ok:false, error:'release_button_only_for_manual_policy' }, 400);

  const now = _iso(new Date());
  _updateObjAtRow_(sh, headers, rowIndex, {
    results_released: 'TRUE',
    results_released_at: now,
    updated_at: now
  });

  return _json({ ok:true, teacher_quiz_id, released_at: now });
}

