function _handleLibraryItemsList_({ token, body, p }) {
  const gate = _requireTeacher_({ token });
  if (!gate.ok) return _json(gate.payload, gate.code);

  const getS = (k) => String(((p && p[k]) || (body && body[k]) || '')).trim();

  const course_id = getS('course_id');
  if (!course_id) return _json({ ok:false, error:'missing_course_id' }, 400);

  const q = getS('q').toLowerCase();
  const topic = getS('topic');
  const difficultyRaw = getS('difficulty');

  // normalize difficulty filter using your existing helper
  const wantDifficulty = difficultyRaw ? _normalizeDifficulty_(difficultyRaw) : '';
  if (difficultyRaw && wantDifficulty === null) {
    return _json({ ok:false, error:'invalid_difficulty', allowed: DIFFICULTY_ALLOWED }, 400);
  }

  const limitRaw = parseInt(getS('limit') || '200', 10);
  const limit = (!isNaN(limitRaw) && limitRaw > 0) ? Math.min(limitRaw, 1000) : 200;

  // resolve course_id -> sheet_id/tab_name via library_courses
  const ss = SpreadsheetApp.openById(DB_ID);
  const course = _libResolveCourse_(ss, course_id);
  if (!course.found) return _json({ ok:false, error:'course_not_found', course_id }, 404);
  if (!course.active) return _json({ ok:false, error:'course_not_active', course_id }, 400);

  let alphaSS, alphaSh;
  try {
    alphaSS = SpreadsheetApp.openById(course.sheet_id);
    alphaSh = alphaSS.getSheetByName(course.tab_name || 'items');
  } catch (e) {
    return _json({ ok:false, error:'alpha_sheet_open_failed', course_id }, 500);
  }
  if (!alphaSh) {
    return _json({ ok:false, error:'alpha_tab_missing', course_id, tab_name: course.tab_name || 'items' }, 500);
  }

  const headers = _getHeaders_(alphaSh);
  const lastRow = alphaSh.getLastRow();
  const lastCol = alphaSh.getLastColumn();
  if (lastRow < 2 || lastCol < 1) return _json({ ok:true, course_id, count:0, items:[] });

  // soft indices (Alpha sheets may vary)
  const idxId = _idxAny_(headers, ['item_id','id','bank_item_id','question_id']);
  if (idxId === -1) return _json({ ok:false, error:'alpha_missing_item_id_column', course_id }, 500);

  const idxStem = _idxAny_(headers, ['stem','question','question_text','q','title']);
  const idxSubject = _idxAny_(headers, ['subject']);
  const idxTopic = _idxAny_(headers, ['topic']);
  const idxDifficulty = _idxAny_(headers, ['difficulty']);
  const idxMarks = _idxAny_(headers, ['marks','score']);

  const idxCorrect = _idxAny_(headers, ['correct','answer','key']);
  const idxRationale = _idxAny_(headers, ['rationale','explanation']);
  const idxRationaleImg = _idxAny_(headers, ['rationale_img','explanation_img','rationale_image']);

  const idxOptA = _idxAny_(headers, ['option_a','a']);
  const idxOptB = _idxAny_(headers, ['option_b','b']);
  const idxOptC = _idxAny_(headers, ['option_c','c']);
  const idxOptD = _idxAny_(headers, ['option_d','d']);
  const idxOptE = _idxAny_(headers, ['option_e','e']);
  const idxOptF = _idxAny_(headers, ['option_f','f']);

  const idxFbA = _idxAny_(headers, ['fb_a','feedback_a']);
  const idxFbB = _idxAny_(headers, ['fb_b','feedback_b']);
  const idxFbC = _idxAny_(headers, ['fb_c','feedback_c']);
  const idxFbD = _idxAny_(headers, ['fb_d','feedback_d']);
  const idxFbE = _idxAny_(headers, ['fb_e','feedback_e']);
  const idxFbF = _idxAny_(headers, ['fb_f','feedback_f']);

  const idxUpdated = _idxAny_(headers, ['updated_at','updated']);
  const idxStatus = _idxAny_(headers, ['status','visibility']);

  const values = alphaSh.getRange(2, 1, lastRow - 1, lastCol).getValues();

  const tokens = q ? q.split(/\s+/).filter(Boolean) : [];

  const out = [];
  for (let i=0; i<values.length; i++){
    const r = values[i];

    const item_id = String(r[idxId] || '').trim();
    if (!item_id) continue;

    // Optional status/visibility filter: if sheet has something like "hidden", skip it
    if (idxStatus !== -1) {
      const st = String(r[idxStatus] || '').trim().toLowerCase();
      if (st === 'hidden' || st === 'deleted' || st === 'inactive') continue;
    }

    const stem = (idxStem !== -1) ? String(r[idxStem] || '').trim() : '';
    const subj = (idxSubject !== -1) ? String(r[idxSubject] || '').trim() : '';
    const top = (idxTopic !== -1) ? String(r[idxTopic] || '').trim() : '';
    const diffRaw = (idxDifficulty !== -1) ? String(r[idxDifficulty] || '').trim() : '';
    const diff = diffRaw ? (_normalizeDifficulty_(diffRaw) || String(diffRaw||'').trim()) : '';

    if (topic && top !== topic) continue;
    if (wantDifficulty && diff !== wantDifficulty) continue;

    if (tokens.length) {
      const hay = [
        stem,
        (idxRationale !== -1) ? String(r[idxRationale]||'') : '',
        subj, top, diff,
        (idxOptA !== -1) ? String(r[idxOptA]||'') : '',
        (idxOptB !== -1) ? String(r[idxOptB]||'') : '',
        (idxOptC !== -1) ? String(r[idxOptC]||'') : '',
        (idxOptD !== -1) ? String(r[idxOptD]||'') : '',
        (idxOptE !== -1) ? String(r[idxOptE]||'') : '',
        (idxOptF !== -1) ? String(r[idxOptF]||'') : ''
      ].join(' ').toLowerCase();

      const ok = tokens.every(t => hay.indexOf(t) !== -1);
      if (!ok) continue;
    }

    const marks = (idxMarks !== -1) ? String(r[idxMarks] || '').trim() : '';
    const updated_at = (idxUpdated !== -1) ? String(r[idxUpdated] || '').trim() : '';

    const correctRaw = (idxCorrect !== -1) ? String(r[idxCorrect] || '').trim() : '';
    const option_a = (idxOptA !== -1) ? String(r[idxOptA] || '').trim() : '';
    const option_b = (idxOptB !== -1) ? String(r[idxOptB] || '').trim() : '';
    const option_c = (idxOptC !== -1) ? String(r[idxOptC] || '').trim() : '';
    const option_d = (idxOptD !== -1) ? String(r[idxOptD] || '').trim() : '';
    const option_e = (idxOptE !== -1) ? String(r[idxOptE] || '').trim() : '';
    const option_f = (idxOptF !== -1) ? String(r[idxOptF] || '').trim() : '';

    const correct = _libNormalizeCorrect_(correctRaw, { option_a, option_b, option_c, option_d, option_e, option_f });

    out.push({
      course_id: course.course_id,
      item_id,

      stem,
      subject: subj,
      topic: top,
      difficulty: diff,
      marks: marks || '1',
      updated_at,

      option_a, option_b, option_c, option_d, option_e, option_f,
      fb_a: (idxFbA !== -1) ? String(r[idxFbA] || '').trim() : '',
      fb_b: (idxFbB !== -1) ? String(r[idxFbB] || '').trim() : '',
      fb_c: (idxFbC !== -1) ? String(r[idxFbC] || '').trim() : '',
      fb_d: (idxFbD !== -1) ? String(r[idxFbD] || '').trim() : '',
      fb_e: (idxFbE !== -1) ? String(r[idxFbE] || '').trim() : '',
      fb_f: (idxFbF !== -1) ? String(r[idxFbF] || '').trim() : '',

      correct,
      rationale: (idxRationale !== -1) ? String(r[idxRationale] || '').trim() : '',
      rationale_img: (idxRationaleImg !== -1) ? String(r[idxRationaleImg] || '').trim() : ''
    });

    if (out.length >= limit) break;
  }

  // sort newest-ish (updated_at if present, else stable)
  out.sort((a,b)=> String(b.updated_at||'').localeCompare(String(a.updated_at||'')));

  return _json({ ok:true, course_id: course.course_id, count: out.length, items: out });
}

/* ---------- helpers ---------- */

function _idxAny_(headers, names) {
  const map = {};
  for (let i=0;i<headers.length;i++){
    map[String(headers[i]||'').trim().toLowerCase()] = i;
  }
  for (let j=0;j<(names||[]).length;j++){
    const k = String(names[j]||'').trim().toLowerCase();
    if (k && (k in map)) return map[k];
  }
  return -1;
}

function _libResolveCourse_(ss, course_id) {
  const sh = ss.getSheetByName(SH_LIBRARY_COURSES);
  if (!sh) return { found:false };

  const headers = _getHeaders_(sh);
  const idx = _indexMap_(headers, ['course_id','title','program_scope','status','sheet_id','tab_name']);

  const lastRow = sh.getLastRow();
  if (lastRow < 2) return { found:false };

  const values = sh.getRange(2, 1, lastRow - 1, sh.getLastColumn()).getValues();
  const want = String(course_id||'').trim().toUpperCase();

  for (let i=0; i<values.length; i++){
    const r = values[i];
    const cid = String(r[idx.course_id]||'').trim().toUpperCase();
    if (!cid || cid !== want) continue;

    const status = String(r[idx.status]||'').trim().toLowerCase();
    const sheet_id = String(r[idx.sheet_id]||'').trim();
    const tab_name = String(r[idx.tab_name]||'').trim() || 'items';

    return {
      found:true,
      active: (status === 'active'),
      course_id: String(r[idx.course_id]||'').trim(),
      title: String(r[idx.title]||'').trim(),
      program_scope: String(r[idx.program_scope]||'').trim(),
      sheet_id,
      tab_name
    };
  }

  return { found:false };
}

function _libNormalizeCorrect_(raw, opts) {
  const s = String(raw||'').trim();
  if (!s) return '';

  const up = s.toUpperCase();
  if (['A','B','C','D','E','F'].indexOf(up) !== -1) return up;

  // numeric 1-6
  const n = parseInt(s, 10);
  if (!isNaN(n) && n >= 1 && n <= 6) return ['A','B','C','D','E','F'][n-1];

  // match by option text
  const map = {
    A: String((opts && opts.option_a)||'').trim(),
    B: String((opts && opts.option_b)||'').trim(),
    C: String((opts && opts.option_c)||'').trim(),
    D: String((opts && opts.option_d)||'').trim(),
    E: String((opts && opts.option_e)||'').trim(),
    F: String((opts && opts.option_f)||'').trim()
  };
  const needle = s.trim().toLowerCase();
  for (const k in map){
    if (!map[k]) continue;
    if (map[k].trim().toLowerCase() === needle) return k;
  }

  return up; // last resort
}

/* =========================
 * JSON response (CORS-friendly)
 * ========================= */

function _json(obj, statusCode) {
  const out = ContentService
    .createTextOutput(JSON.stringify(obj))
    .setMimeType(ContentService.MimeType.JSON);

  // Best-effort headers (Apps Script supports setHeader on TextOutput)
  try {
    out.setHeader('Access-Control-Allow-Origin', '*');
    out.setHeader('Access-Control-Allow-Methods', 'GET,POST,OPTIONS');
    out.setHeader('Access-Control-Allow-Headers', 'Content-Type');
    if (statusCode) out.setHeader('X-Status-Code', String(statusCode));
  } catch (_) {}

  return out;
}

