}

/* =========================
 * Candidate: attempt.start
 * - Resumes IN_PROGRESS if exists (unless force_new=1)
 * - Creates new attempt (per-student shuffle)
 * ========================= */
function _handleCandidateAttemptStart_({ token, body, p }) {
  const gate = _requireUser_({ token });
  if (!gate.ok) return _json(gate.payload, gate.code);

  const user_id = gate.user_id;
  const getS = (k) => String(((p && p[k]) || (body && body[k]) || '')).trim();

  const class_id = getS('class_id');
  const teacher_quiz_id = getS('teacher_quiz_id');
  const force_new = getS('force_new') === '1';

  // Canonical: candidate_fields_json
  const candidate_fields_json = getS('candidate_fields_json') || '';

  if (!class_id || !teacher_quiz_id) {
    return _json({ ok: false, error: 'missing_class_id_or_teacher_quiz_id' }, 400);
  }

  if (candidate_fields_json) {
    const parsed = _parseJsonSafe_(candidate_fields_json, null);
    if (!parsed || typeof parsed !== 'object') {
      return _json({ ok: false, error: 'invalid_candidate_fields_json' }, 400);
    }
  }

  const ss = SpreadsheetApp.openById(DB_ID);

  if (!_isMemberActive_(ss, class_id, user_id)) {
    return _json({ ok: false, error: 'forbidden_not_class_member' }, 403);
  }
  if (!_isQuizLinkedToClassActive_(ss, teacher_quiz_id, class_id)) {
    return _json({ ok: false, error: 'forbidden_quiz_not_linked_to_class' }, 403);
  }

  const q = _getTeacherQuizById_(teacher_quiz_id);
  if (!q.found) return _json({ ok: false, error: 'quiz_not_found' }, 404);

  const quiz = q.obj;
  if (String(quiz.status || '').toUpperCase() !== 'PUBLISHED') {
    return _json({ ok: false, error: 'quiz_not_published' }, 400);
  }

  const nowMs = Date.now();
  if (_computeOpenState_(quiz.open_at, quiz.close_at, nowMs) !== 'OPEN') {
    return _json({ ok: false, error: 'quiz_not_open' }, 403);
  }

  // Resume if allowed
  if (!force_new) {
    const found = _findInProgressAttempt_(ss, teacher_quiz_id, class_id, user_id);
    if (found.found) {
      // ensure timeout + time patch + due_at recompute
      const patchedExpiry = _maybeExpireAttempt_(ss, found.attempt, quiz, nowMs, found.rowIndex);
let attempt = patchedExpiry.attempt;
      if (String(attempt.status || '').toUpperCase() === 'IN_PROGRESS') {
        // Apply elapsed-time patch on resume (prevents “free extra time”)
        const timePatch = _ta_activeTimePatch_(attempt, nowMs);
        if (timePatch.changed) {
          _attemptUpdateByRow_(ss, found.rowIndex, timePatch.patch);
          const fresh = _attemptGetById_(ss, attempt.attempt_id);
          attempt = fresh.found ? fresh.obj : attempt;
        }

        // For timed attempts, refresh due_at from remaining time
        const durationSec = _toIntDefault_(attempt.duration_minutes, 0) * 60;
        const takenSec = _toIntDefault_(attempt.time_taken_s, 0);

        if (durationSec > 0) {
          if (takenSec >= durationSec) {
            // exhausted -> timeout right now
            const grade = _gradeAttempt_(ss, attempt);
            const nowIso = _iso(new Date(nowMs));

            const headers = _attemptHeaders_(_attemptSheet_(ss));
            const patch = Object.assign({
              status: 'TIMED_OUT',
              submitted_at: nowIso,
              updated_at: nowIso,
              time_taken_s: String(takenSec)
            }, _setScorePatch_(headers, grade.score));

            _attemptUpdateByRow_(ss, found.rowIndex, patch);
            const fresh2 = _attemptGetById_(ss, attempt.attempt_id);
            const a2 = fresh2.found ? fresh2.obj : attempt;
            const payload = _buildAttemptPayload_(ss, a2);
            const meta = _candidateResultsMetaPack_(quiz, nowMs);

            return _json({
              ok: true,
              resumed: true,
              ...payload,
              ended: true,
              status: 'TIMED_OUT',
              results: meta,
              next: 'RESULTS'
            });
          }

          const remainingSec = Math.max(durationSec - takenSec, 0);
          const newDueIso = _iso(new Date(nowMs + remainingSec * 1000));

          _attemptUpdateByRow_(ss, found.rowIndex, {
            due_at: newDueIso,
            updated_at: _iso(new Date(nowMs))
          });

          const refreshed = _attemptGetById_(ss, attempt.attempt_id);
          return _json({
            ok: true,
            resumed: true,
            ..._buildAttemptPayload_(ss, refreshed.found ? refreshed.obj : attempt),
            ended: false,
            status: 'IN_PROGRESS'
          });
        }
      }

      // If _maybeTimeoutAttempt_ flipped to TIMED_OUT, return ended meta (runner-safe)
      const payload = _buildAttemptPayload_(ss, attempt);
      const stU = String(attempt.status || '').toUpperCase();
      if (stU !== 'IN_PROGRESS') {
        const meta = _candidateResultsMetaPack_(quiz, nowMs);
        return _json({ ok: true, resumed: true, ...payload, ended: true, status: stU, results: meta, next: 'RESULTS' });
      }

      return _json({ ok: true, resumed: true, ...payload, ended: false, status: 'IN_PROGRESS' });
    }
  }

  // Max attempts enforcement (exclude ABANDONED)
  const max = _toIntDefault_(quiz.max_attempts, 0);
  const used = _countUserAttempts_(ss, teacher_quiz_id, class_id, user_id);
  if (max > 0 && used >= max) {
    return _json({ ok: false, error: 'max_attempts_reached', max: String(max), used: String(used) }, 403);
  }

  // Load published snapshot items
  const itemsSrc = _getQuizItemsSnapshots_(ss, teacher_quiz_id);
  if (!itemsSrc.length) {
    return _json({ ok: false, error: 'quiz_has_no_items' }, 400);
  }

  // Shuffle questions if enabled
  const shuffleQ = _toBoolDefault_(quiz.shuffle_questions, true);
  const ordered = shuffleQ ? _ta_shuffle_(itemsSrc) : itemsSrc.slice();

  // Attempt items with option maps
  const attemptItems = ordered.map((it, idx) => ({
    quiz_item_id: it.quiz_item_id,
    position: idx + 1,
    marks: _toIntDefault_(it.snap_marks, 1),
    opt_map: _buildOptionMap_(it, _toBoolDefault_(quiz.shuffle_options, true))
  }));

  const attempt_id = _newId_('ta');
  const attempt_no = used + 1;

  const mode = String(quiz.mode || 'TIMED').toUpperCase();
  const duration = _toIntDefault_(quiz.duration_minutes, 0);

  const nowIso = _iso(new Date(nowMs));
let due_at = '';
if (mode === 'TIMED' && duration > 0) {
  let dueMs = nowMs + duration * 60000;
  const closeMs = _parseIsoMs_(String(quiz.close_at || '').trim());
  if (closeMs != null && closeMs < dueMs) dueMs = closeMs; // cap to quiz close
  due_at = _iso(new Date(dueMs));
}

  const row = {
    user_id,
    attempt_id,
    started_at: nowIso,
    submitted_at: '',
    updated_at: nowIso,

    items_json: JSON.stringify(attemptItems),
    due_at,
    class_id,
    attempt_no: String(attempt_no),

    teacher_id: String(quiz.teacher_id || '').trim(),
    teacher_quiz_id: String(quiz.teacher_quiz_id || '').trim(),

    mode,
    duration_minutes: String(duration),
    status: 'IN_PROGRESS',

    score_raw: '',
    score_total: '',
    score_pct: '',
    time_taken_s: '0',

    // canonical
    candidate_fields_json,

    // legacy fallback (keep blank; append helper will mirror if needed)
    custom_fields_json: '',

    answers_json: '{}',
    flags_json: '{}',
    score_json: ''
  };

  _attemptAppend_(ss, row);

  return _json({
    ok: true,
    created: true,
    ..._buildAttemptPayload_(ss, row, itemsSrc),
    ended: false,
    status: 'IN_PROGRESS'
  });
}

/* =========================
 * Candidate: attempt.get
 * - if attempt_id provided: loads that attempt
 * - else: current in-progress, else latest ended
 * NOTE: Runner-safe payload only (no score/review).
 * ========================= */
function _handleCandidateAttemptGet_({ token, body, p }) {
  const gate = _requireUser_({ token });
  if (!gate.ok) return _json(gate.payload, gate.code);

  const user_id = gate.user_id;
  const getS = (k) => String(((p && p[k]) || (body && body[k]) || '')).trim();

  const class_id = getS('class_id');
  const teacher_quiz_id = getS('teacher_quiz_id');
  if (!class_id || !teacher_quiz_id) {
    return _json({ ok: false, error: 'missing_class_id_or_teacher_quiz_id' }, 400);
  }

  const ss = SpreadsheetApp.openById(DB_ID);

  if (!_isMemberActive_(ss, class_id, user_id)) {
    return _json({ ok: false, error: 'forbidden_not_class_member' }, 403);
  }
  if (!_isQuizLinkedToClassActive_(ss, teacher_quiz_id, class_id)) {
    return _json({ ok: false, error: 'forbidden_quiz_not_linked_to_class' }, 403);
  }

  const attempt_id = getS('attempt_id'); // optional
  const nowMs = Date.now();

  // helper for ended attempts (runner-safe)
  function _attachEndedMeta_(resp, quizObj, nowMsLocal) {
    const meta = _candidateResultsMetaPack_(quizObj, nowMsLocal);
    resp.results = meta;
    resp.next = 'RESULTS';
    return resp;
  }

  // load quiz once (used only if ended)
  const q0 = _getTeacherQuizById_(teacher_quiz_id);
  const quiz0 = q0.found ? (q0.obj || {}) : {};

  // 0) specific attempt
  if (attempt_id) {
    const foundA = _attemptGetById_(ss, attempt_id);
    if (!foundA.found) return _json({ ok: false, error: 'attempt_not_found' }, 404);

    let a = foundA.obj;

    if (String(a.user_id || '').trim() !== user_id) return _json({ ok: false, error: 'forbidden' }, 403);
    if (String(a.class_id || '').trim() !== String(class_id).trim()) return _json({ ok: false, error: 'forbidden' }, 403);
    if (String(a.teacher_quiz_id || '').trim() !== String(teacher_quiz_id).trim()) return _json({ ok: false, error: 'forbidden' }, 403);

    const patchedExpiry = _maybeExpireAttempt_(ss, a, quiz0, nowMs, foundA.rowIndex);
a = patchedExpiry.attempt;

    // apply elapsed patch + due refresh for timed IN_PROGRESS
    if (String(a.status || '').toUpperCase() === 'IN_PROGRESS') {
      const timePatch = _ta_activeTimePatch_(a, nowMs);
      if (timePatch.changed) {
        _attemptUpdateByRow_(ss, foundA.rowIndex, timePatch.patch);
        const fresh = _attemptGetById_(ss, a.attempt_id);
        a = fresh.found ? fresh.obj : a;
      }

      const durationSec = _toIntDefault_(a.duration_minutes, 0) * 60;
      const takenSec = _toIntDefault_(a.time_taken_s, 0);
      if (durationSec > 0) {
        if (takenSec >= durationSec) {
          const grade = _gradeAttempt_(ss, a);
          const headers = _attemptHeaders_(_attemptSheet_(ss));
          const nowIso = _iso(new Date(nowMs));
          const patch = Object.assign({
            status: 'TIMED_OUT',
            submitted_at: nowIso,
            updated_at: nowIso,
            time_taken_s: String(takenSec)
          }, _setScorePatch_(headers, grade.score));

          _attemptUpdateByRow_(ss, foundA.rowIndex, patch);
          const fresh2 = _attemptGetById_(ss, a.attempt_id);
          const a2 = fresh2.found ? fresh2.obj : a;
          const payload2 = _buildAttemptPayload_(ss, a2);

          const stU2 = String(a2.status || '').toUpperCase();
          let res2 = { ok: true, ...payload2, ended: (stU2 !== 'IN_PROGRESS'), status: stU2 };
          if (stU2 !== 'IN_PROGRESS') res2 = _attachEndedMeta_(res2, quiz0, nowMs);
          return _json(res2);
        }

        const remainingSec = Math.max(durationSec - takenSec, 0);
        const newDueIso = _iso(new Date(nowMs + remainingSec * 1000));
        _attemptUpdateByRow_(ss, foundA.rowIndex, { due_at: newDueIso, updated_at: _iso(new Date(nowMs)) });

        const fresh3 = _attemptGetById_(ss, a.attempt_id);
        a = fresh3.found ? fresh3.obj : a;
      }
    }

    const payload = _buildAttemptPayload_(ss, a);
    const stU = String(a.status || '').toUpperCase();
    let res = { ok: true, ...payload, ended: (stU !== 'IN_PROGRESS'), status: stU };
    if (stU !== 'IN_PROGRESS') res = _attachEndedMeta_(res, quiz0, nowMs);
    return _json(res);
  }

  // 1) in-progress attempt
  const found = _findInProgressAttempt_(ss, teacher_quiz_id, class_id, user_id);
  if (found.found) {
let attempt = _maybeExpireAttempt_(ss, found.attempt, quiz0, nowMs, found.rowIndex).attempt;
    if (String(attempt.status || '').toUpperCase() === 'IN_PROGRESS') {
      const timePatch = _ta_activeTimePatch_(attempt, nowMs);
      if (timePatch.changed) {
        _attemptUpdateByRow_(ss, found.rowIndex, timePatch.patch);
        const fresh = _attemptGetById_(ss, attempt.attempt_id);
        attempt = fresh.found ? fresh.obj : attempt;
      }

      const durationSec = _toIntDefault_(attempt.duration_minutes, 0) * 60;
      const takenSec = _toIntDefault_(attempt.time_taken_s, 0);

      if (durationSec > 0) {
        if (takenSec >= durationSec) {
          const grade = _gradeAttempt_(ss, attempt);
          const headers = _attemptHeaders_(_attemptSheet_(ss));
          const nowIso = _iso(new Date(nowMs));
          const patch = Object.assign({
            status: 'TIMED_OUT',
            submitted_at: nowIso,
            updated_at: nowIso,
            time_taken_s: String(takenSec)
          }, _setScorePatch_(headers, grade.score));

          _attemptUpdateByRow_(ss, found.rowIndex, patch);

          const fresh2 = _attemptGetById_(ss, attempt.attempt_id);
          const a2 = fresh2.found ? fresh2.obj : attempt;
          const payload2 = _buildAttemptPayload_(ss, a2);

          const stU2 = String(a2.status || '').toUpperCase();
          let res2 = { ok: true, ...payload2, ended: (stU2 !== 'IN_PROGRESS'), status: stU2 };
          if (stU2 !== 'IN_PROGRESS') res2 = _attachEndedMeta_(res2, quiz0, nowMs);
          return _json(res2);
        }

        const remainingSec = Math.max(durationSec - takenSec, 0);
        let newDueMs = nowMs + remainingSec * 1000;
const closeMs = _parseIsoMs_(String(quiz.close_at || '').trim());
if (closeMs != null && closeMs < newDueMs) newDueMs = closeMs;

const newDueIso = _iso(new Date(newDueMs));
_attemptUpdateByRow_(ss, found.rowIndex, { due_at: newDueIso, updated_at: _iso(new Date(nowMs)) });

        const refreshed = _attemptGetById_(ss, attempt.attempt_id);
        attempt = refreshed.found ? refreshed.obj : attempt;
      }
    }

    const payload = _buildAttemptPayload_(ss, attempt);
    const stU = String(attempt.status || '').toUpperCase();
    let res = { ok: true, ...payload, ended: (stU !== 'IN_PROGRESS'), status: stU };
    if (stU !== 'IN_PROGRESS') res = _attachEndedMeta_(res, quiz0, nowMs);
    return _json(res);
  }

  // 2) latest ended attempt
  const ended = _findLatestEndedAttempt_(ss, teacher_quiz_id, class_id, user_id);
  if (!ended.found) return _json({ ok: true, attempt: null });

  const payload = _buildAttemptPayload_(ss, ended.attempt);
  const stU = String((ended.attempt && ended.attempt.status) || '').toUpperCase();
  let res = { ok: true, ...payload, ended: true, status: stU || 'SUBMITTED' };
  res = _attachEndedMeta_(res, quiz0, nowMs);
  return _json(res);
}

/* =========================
 * Candidate: quiz.attempts.list
 * ========================= */
function _handleCandidateQuizAttemptsList_({ token, body, p }) {
  const gate = _requireUser_({ token });
  if (!gate.ok) return _json(gate.payload, gate.code);

  const user_id = gate.user_id;
  const getS = (k) => String(((p && p[k]) || (body && body[k]) || '')).trim();

  const class_id = getS('class_id');
  const teacher_quiz_id = getS('teacher_quiz_id');
  if (!class_id || !teacher_quiz_id) {
    return _json({ ok:false, error:'missing_class_id_or_teacher_quiz_id' }, 400);
  }

  const limit = Math.min(Math.max(_toIntDefault_(getS('limit'), 30), 1), 200);
  const ss = SpreadsheetApp.openById(DB_ID);

  if (!_isMemberActive_(ss, class_id, user_id)) {
    return _json({ ok:false, error:'forbidden_not_class_member' }, 403);
  }
  if (!_isQuizLinkedToClassActive_(ss, teacher_quiz_id, class_id)) {
    return _json({ ok:false, error:'forbidden_quiz_not_linked_to_class' }, 403);
  }

  const q = _getTeacherQuizById_(teacher_quiz_id);
  if (!q.found) return _json({ ok:false, error:'quiz_not_found' }, 404);

  const quiz = q.obj;
  if (String(quiz.status || '').trim().toUpperCase() !== 'PUBLISHED') {
    return _json({ ok:false, error:'quiz_not_published' }, 400);
  }

  const nowMs = Date.now();
  const policy = _normalizeResultsPolicy_(quiz.results_release_policy);
  const gateRes = _computeResultsGatePolicy_(quiz, nowMs);

  const showResults = _getShowResultsBool_(quiz);
  const showReview  = _toBoolDefault_(quiz.show_review, false);

  const anyOutput = (showResults || showReview);
  const score_visible = !!(gateRes.met && showResults);
  const review_visible = !!(gateRes.met && showReview);

  const results_status =
    !gateRes.met ? 'PENDING' :
    !anyOutput  ? 'HIDDEN'  :
                 'AVAILABLE';

  const sh = ss.getSheetByName(SH_ATTEMPTS);
  const headers = _getHeaders_(sh);

  const idx = _indexMap_(headers, [
    'attempt_id','teacher_quiz_id','class_id','user_id','attempt_no','status',
    'started_at','due_at','submitted_at','updated_at','time_taken_s','score_json'
  ]);

  const lastRow = sh.getLastRow();
  if (lastRow < 2) {
    return _json({
      ok:true,
      quiz: {
        teacher_quiz_id: String(quiz.teacher_quiz_id||'').trim(),
        title: String(quiz.title||'').trim(),
        preset: String(quiz.preset||'').trim().toUpperCase(),
        results_release_policy: policy,
        results_gate_now: !!gateRes.met,
        results_gate_reason: String(gateRes.reason||''),
        results_available_at: String(gateRes.available_at||''),
        score_visible,
        review_visible,
        results_status
      },
      count: 0,
      items: []
    });
  }

  const values = sh.getRange(2, 1, lastRow - 1, sh.getLastColumn()).getValues();
  let out = [];

  for (let i = 0; i < values.length; i++) {
    const r = values[i];

    if (String(r[idx.teacher_quiz_id] || '').trim() !== String(teacher_quiz_id).trim()) continue;
    if (String(r[idx.class_id] || '').trim() !== String(class_id).trim()) continue;
    if (String(r[idx.user_id] || '').trim() !== String(user_id).trim()) continue;

    const st = String(r[idx.status] || '').trim().toUpperCase();
    if (st === 'ABANDONED') continue;

    const attempt_id = String(r[idx.attempt_id] || '').trim();
    const attempt_no = _toIntDefault_(r[idx.attempt_no], 0);

    let score_summary = null;
    if (score_visible) {
      try {
        const sj = JSON.parse(String(r[idx.score_json] || '') || 'null');
        if (sj && typeof sj === 'object') {
          score_summary = {
            score_marks: sj.score_marks ?? null,
            total_marks: sj.total_marks ?? null,
            percent: sj.percent ?? null
          };
        }
      } catch (_) {}
    }

    out.push({
      attempt_id,
      attempt_no: String(attempt_no || ''),
      status: st,
      started_at: String(r[idx.started_at] || '').trim(),
      due_at: String(r[idx.due_at] || '').trim(),
      submitted_at: String(r[idx.submitted_at] || '').trim(),
      updated_at: String(r[idx.updated_at] || '').trim(),
      time_taken_s: String(r[idx.time_taken_s] || '').trim(),
      can_resume: (st === 'IN_PROGRESS'),
      score_summary
    });
  }

  out.sort((a,b) => {
    const an = _toIntDefault_(a.attempt_no, 0);
    const bn = _toIntDefault_(b.attempt_no, 0);
    if (bn !== an) return bn - an;
    const am = _parseIsoMs_(a.submitted_at) || _parseIsoMs_(a.updated_at) || 0;
    const bm = _parseIsoMs_(b.submitted_at) || _parseIsoMs_(b.updated_at) || 0;
    return bm - am;
  });

  if (out.length > limit) out = out.slice(0, limit);

  return _json({
    ok:true,
    quiz: {
      teacher_quiz_id: String(quiz.teacher_quiz_id||'').trim(),
      title: String(quiz.title||'').trim(),
      preset: String(quiz.preset||'').trim().toUpperCase(),
      results_release_policy: policy,
      results_gate_now: !!gateRes.met,
      results_gate_reason: String(gateRes.reason||''),
      results_available_at: String(gateRes.available_at||''),
      score_visible,
      review_visible,
      results_status
    },
    count: out.length,
    items: out
  });
}

