  const attempt = found.obj;
  if (String(attempt.user_id || '').trim() !== user_id) {
    return _json({ ok: false, error: 'forbidden' }, 403);
  }

let cur = found.obj;

// load quiz once (needed for close_at + results meta)
const q = _getTeacherQuizById_(String(cur.teacher_quiz_id || '').trim());
if (!q.found) return _json({ ok: false, error: 'quiz_not_found' }, 404);
const quiz = q.obj;

const nowMs = Date.now();

// expire attempt if due_at OR close_at has passed
cur = _maybeExpireAttempt_(ss, cur, quiz, nowMs, found.rowIndex).attempt;

// if expiry ended it, return ended meta immediately
if (String(cur.status || '').toUpperCase() !== 'IN_PROGRESS') {
  const metaX = _candidateResultsMetaPack_(quiz, nowMs);
  return _json({
    ok: true,
    attempt: cur,
    ended: true,
    status: String(cur.status || '').toUpperCase(),
    results: metaX,
    next: 'RESULTS'
  });
}


  const timePatch = _ta_activeTimePatch_(cur, nowMs);

  if (timePatch.changed) {
    _attemptUpdateByRow_(ss, found.rowIndex, Object.assign({ updated_at: _iso(new Date(nowMs)) }, timePatch.patch));
    const fresh0 = _attemptGetById_(ss, attempt_id);
    cur = fresh0.found ? fresh0.obj : cur;
  }

  const grade = _gradeAttempt_(ss, cur);
  const nowIso = _iso(new Date(nowMs));
  const statusOut = grade.timed_out ? 'TIMED_OUT' : 'SUBMITTED';

  const headers = _attemptHeaders_(_attemptSheet_(ss));
  const patch = Object.assign({
    status: statusOut,
    submitted_at: nowIso,
    updated_at: nowIso,
    time_taken_s: String(_toIntDefault_(cur.time_taken_s, 0))
  }, _setScorePatch_(headers, grade.score));

  _attemptUpdateByRow_(ss, found.rowIndex, patch);

  const fresh = _attemptGetById_(ss, attempt_id);
  const finalAttempt = fresh.found ? fresh.obj : cur;

  // Runner-safe “what next?” info only
  const meta = _candidateResultsMetaPack_(quiz, nowMs);

  const res = {
    ok: true,
    attempt: finalAttempt,
    ended: true,
    status: statusOut,
    results: meta,
    next: 'RESULTS'
  };

  // Preserve a user-friendly message in the submit response
  if (meta.results_pending) res.message = meta.message || 'Submitted.';
  else res.message = 'Submitted.';

  return _json(res);
