  }

  const found = _attemptGetById_(ss, attempt_id);
  if (!found.found) return _json({ ok:false, error:'attempt_not_found' }, 404);

  const a = found.obj;

  if (String(a.user_id || '').trim() !== user_id) return _json({ ok:false, error:'forbidden' }, 403);
  if (String(a.class_id || '').trim() !== String(class_id).trim()) return _json({ ok:false, error:'forbidden' }, 403);
  if (String(a.teacher_quiz_id || '').trim() !== String(teacher_quiz_id).trim()) return _json({ ok:false, error:'forbidden' }, 403);

  const stU = String(a.status || '').trim().toUpperCase();
  if (stU === 'IN_PROGRESS') return _json({ ok:false, error:'attempt_not_submitted' }, 400);

  const q = _getTeacherQuizById_(teacher_quiz_id);
  if (!q.found) return _json({ ok:false, error:'quiz_not_found' }, 404);
  const quiz = q.obj;

  const nowMs = Date.now();
  const policy = _normalizeResultsPolicy_(quiz.results_release_policy);
  const gateRes = _computeResultsGatePolicy_(quiz, nowMs);

  const showResults = _getShowResultsBool_(quiz);
  const showReview  = _toBoolDefault_(quiz.show_review, false);
  const anyOutput = (showResults || showReview);

  // normalize grading config (safe defaults even if sheet has blanks/invalid JSON)
  const gc = _normalizeGradingConfig_(quiz);
  const pass_threshold_pct = _passThresholdStrict_(quiz);

  // ensure score_json exists for ended attempts (even if hidden)
  const ensured = _ensureAttemptScored_(ss, a, found.rowIndex);
  const scoreObj = ensured.score; // {total_marks, score_marks, percent}

  // ===== bundle quiz_meta + attempt_meta + my_details (shared helper) =====
const a2 = ensured.attempt || a;
const bundle = _buildCandidateAttemptBundle_(ss, quiz, a2, class_id, user_id);

const quiz_meta = bundle.quiz_meta;
const attempt_meta = bundle.attempt_meta;
const my_details = bundle.my_details;

  const res = {
    ok: true,
    quiz_meta,
    attempt_meta,
    my_details,
    attempt_id,
    status: stU,
    results_release_policy: policy,
    gate_met: !!gateRes.met,
    gate_reason: String(gateRes.reason || ''),
    available_at: String(gateRes.available_at || ''),
    show_results: !!showResults,
    show_review: !!showReview,
    can_review_now: !!(gateRes.met && showReview),

    results_pending: false,
    message: '',
    score: null,

    score_display_policy: gc.score_display_policy,
    display_score: null,
    grade_label: null,
    pass_threshold_pct: String(pass_threshold_pct),
    pass_status: null,
    passed: null
  };

  // Gate not met => no label, no score
  if (!gateRes.met) {
    res.results_pending = true;
    res.message = _candidateResultsPendingMessage_(policy, gateRes, quiz);
    return _json(res);
  }

  // Teacher hidden BOTH results + review
  if (!anyOutput) {
    res.results_pending = true;
    res.message = "Results and review are hidden for this quiz.";
    return _json(res);
  }

  // show_results=false => no label, no score (review may still be allowed)
  if (!showResults) {
    res.score = null;
    res.display_score = null;
    res.grade_label = null;
    res.message = "Results hidden (review may be available).";
    return _json(res);
  }

  // showResults === true, but score display policy may still hide numeric score
  const sdp = String(gc.score_display_policy || 'PCT_ONLY').trim().toUpperCase();

  const pct = (scoreObj && scoreObj.percent != null) ? Number(scoreObj.percent) : null;
  const raw = (scoreObj && scoreObj.score_marks != null) ? Number(scoreObj.score_marks) : null;
  const total = (scoreObj && scoreObj.total_marks != null) ? Number(scoreObj.total_marks) : null;

  // PASS/FAIL is based ONLY on pass_threshold_pct (not bands)
if (pct != null && isFinite(pct)) {
  res.pass_status = (pct >= pass_threshold_pct) ? 'PASS' : 'FAIL';
  res.passed = (res.pass_status === 'PASS');
}

  // Grade label is allowed when gate_met=true AND show_results=true (even if numeric is hidden)
  if (pct != null && isFinite(pct)) {
    res.grade_label = _gradeLabelFromBands_(gc.grade_bands, pct);
  } else {
    res.grade_label = '';
  }

  // ===== FIX: HIDE returns grade_label but NO numeric score anywhere =====
  if (sdp === 'HIDE') {
    res.display_score = null;
    res.score = null; // avoid numeric leaks to older frontends
    res.message = "Results available.";
    return _json(res);
  }

  // Non-HIDE: keep backward-compatible full score object
  res.score = scoreObj || null;

  // compute display_score based on policy
  if (sdp === 'PCT_ONLY') {
    res.display_score = { percent: (pct == null || !isFinite(pct)) ? null : pct };
  } else if (sdp === 'RAW_ONLY') {
    res.display_score = {
      score_marks: (raw == null || !isFinite(raw)) ? null : raw,
      total_marks: (total == null || !isFinite(total)) ? null : total
    };
  } else { // RAW_AND_PCT (and any future-safe fallback)
    res.display_score = {
      score_marks: (raw == null || !isFinite(raw)) ? null : raw,
      total_marks: (total == null || !isFinite(total)) ? null : total,
      percent: (pct == null || !isFinite(pct)) ? null : pct
    };
  }

  res.message = "Results available.";
  return _json(res);
}

/* =========================
 * Candidate bundle helper (Results-style)
 * - quiz_meta
 * - attempt_meta
 * - my_details (class profile + attempt submitted fields)
 * Safe to call even if attemptObj is null.
 * ========================= */
function _buildCandidateAttemptBundle_(ss, quizObj, attemptObj, class_id, user_id) {
  const quiz = quizObj || {};
  const attempt = attemptObj || {};

  function _norm_(v){ return String(v == null ? '' : v).trim(); }

  function _fieldsMapFromAnyJson_(jsonStr) {
    const raw = _parseJsonSafe_(jsonStr, {});
    if (raw && typeof raw === 'object' && !Array.isArray(raw)) {
      if (raw.fields && typeof raw.fields === 'object' && !Array.isArray(raw.fields)) return raw.fields;
      return raw;
    }
    return {};
  }

  function _entriesFromSchema_(schemaFields, valuesMap) {
    const fields = Array.isArray(schemaFields) ? schemaFields : [];
    const vals = (valuesMap && typeof valuesMap === 'object' && !Array.isArray(valuesMap)) ? valuesMap : {};

    const seen = {};
    const out = [];

    // schema-ordered
    for (let i = 0; i < fields.length; i++) {
      const f = fields[i] || {};
      const key = _norm_(f.key);
      const label = _norm_(f.label) || key;
      if (!key) continue;
      seen[key] = true;
      out.push({ key, label, value: _norm_(vals[key]) });
    }

    // extras (not in schema)
    Object.keys(vals).forEach(k => {
      const key = _norm_(k);
      if (!key || seen[key]) return;
      out.push({ key, label: key, value: _norm_(vals[key]) });
    });

    return out;
  }

  // quiz_meta (keep existing keys; extra keys are safe additions)
  const quiz_meta = {
    teacher_quiz_id: _norm_(quiz.teacher_quiz_id),
    title: _norm_(quiz.title),
    subject: _norm_(quiz.subject),
    preset: _norm_(quiz.preset).toUpperCase(),

    // helpful extras (optional for UI)
    mode: _norm_(quiz.mode || 'TIMED').toUpperCase(),
    duration_minutes: _norm_(quiz.duration_minutes),
    results_release_policy: _normalizeResultsPolicy_(quiz.results_release_policy),
    show_review: _toBoolDefault_(quiz.show_review, false),
    show_results: _getShowResultsBool_(quiz)
  };

  // attempt_meta (blank-safe)
  const attempt_meta = {
    attempt_id: _norm_(attempt.attempt_id),
    attempt_no: _norm_(attempt.attempt_no),
    status: _norm_(attempt.status).toUpperCase(),
    started_at: _norm_(attempt.started_at),
    submitted_at: _norm_(attempt.submitted_at),
    updated_at: _norm_(attempt.updated_at),
    time_taken_s: _norm_(attempt.time_taken_s),
    due_at: _norm_(attempt.due_at)
  };

  // Class profile (current): teacher_class_members + teacher_classes schema
  let class_profile = null;
  try {
    const mem = _getMembershipByClassUser_(ss, class_id, user_id);

    const clsSh = ss.getSheetByName(SH_CLASSES);
    const clsHeaders = _getHeaders_(clsSh);
    const clsRow = _findRowIndexBy_(clsSh, clsHeaders, 'class_id', class_id);
    const clsObj = (clsRow > 0) ? _readObjAtRow_(clsSh, clsHeaders, clsRow) : null;

    const classSchemaStr = _norm_(clsObj && clsObj.custom_fields_json) || JSON.stringify({ fields: [] });
    const classSchemaFields = _schemaToFields_(classSchemaStr);

    const mfJson = _norm_(mem && mem.obj && mem.obj.member_fields_json);
    const mfMap = _fieldsMapFromAnyJson_(mfJson);

    class_profile = {
      display_name: _norm_(mem && mem.obj && mem.obj.display_name),
      entries: _entriesFromSchema_(classSchemaFields, mfMap)
    };
  } catch (_) {
    class_profile = null;
  }

  // Attempt details (submitted): teacher_attempts candidate_fields_json (fallback custom_fields_json) + quiz schema
  let attempt_submitted = null;
  try {
    const quizSchemaStr = _norm_(quiz.custom_fields_json) || JSON.stringify({ fields: [] });
    const quizSchemaFields = _schemaToFields_(quizSchemaStr);

    const candJson = _norm_(attempt.candidate_fields_json) || _norm_(attempt.custom_fields_json);
    const candMap = _fieldsMapFromAnyJson_(candJson);

    attempt_submitted = { entries: _entriesFromSchema_(quizSchemaFields, candMap) };
  } catch (_) {
    attempt_submitted = { entries: [] };
  }

  const my_details = {
    class_profile,
    attempt_submitted
  };

  return { quiz_meta, attempt_meta, my_details };
}

function _handleCandidateAttemptReviewGet_({ token, body, p }) {
  const gate = _requireUser_({ token });
  if (!gate.ok) return _json(gate.payload, gate.code);

  const user_id = gate.user_id;
  const getS = (k) => String(((p && p[k]) || (body && body[k]) || '')).trim();

  const class_id = getS('class_id');
  const teacher_quiz_id = getS('teacher_quiz_id');
  let attempt_id = getS('attempt_id'); // OPTIONAL now

  if (!class_id || !teacher_quiz_id) {
    return _json({ ok:false, error:'missing_class_id_or_teacher_quiz_id' }, 400);
  }

  const ss = SpreadsheetApp.openById(DB_ID);

  if (!_isMemberActive_(ss, class_id, user_id)) {
    return _json({ ok:false, error:'forbidden_not_class_member' }, 403);
  }
  if (!_isQuizLinkedToClassActive_(ss, teacher_quiz_id, class_id)) {
    return _json({ ok:false, error:'forbidden_quiz_not_linked_to_class' }, 403);
  }

  const q = _getTeacherQuizById_(teacher_quiz_id);
  if (!q.found) return _json({ ok:false, error:'quiz_not_found' }, 404);
  const quiz = q.obj;

  // candidates should only see published quizzes
  if (String(quiz.status || '').trim().toUpperCase() !== 'PUBLISHED') {
    return _json({ ok:false, error:'quiz_not_published' }, 400);
  }

  const nowMs = Date.now();
  const policy = _normalizeResultsPolicy_(quiz.results_release_policy);
  const gateRes = _computeResultsGatePolicy_(quiz, nowMs);

  const showResults = _getShowResultsBool_(quiz);
  const showReview  = _toBoolDefault_(quiz.show_review, false);

  // grading config (for optional score panel)
  const gc = _normalizeGradingConfig_(quiz);
  const pass_threshold_pct = _passThresholdStrict_(quiz);

  // ---- Load attempt (attempt_id optional)
  let found = null;
  let a = null;
  let rowIndex = 0;

  if (attempt_id) {
    found = _attemptGetById_(ss, attempt_id);
    if (!found.found) {
      // Return ok:true with a friendly block (lets UI still show quiz meta)
      const bundle0 = _buildCandidateAttemptBundle_(ss, quiz, null, class_id, user_id);
      return _json({
        ok: true,
        ...bundle0,
        attempt_id: attempt_id,
        status: '',
        results_release_policy: policy,
        gate_met: !!gateRes.met,
        gate_reason: String(gateRes.reason || ''),
        available_at: String(gateRes.available_at || ''),
        show_results: !!showResults,
        show_review: !!showReview,

        review_allowed: false,
        review_block_reason: { code:'ATTEMPT_NOT_FOUND', message:'Attempt not found.' },

        score_display_policy: gc.score_display_policy,
        pass_threshold_pct: String(pass_threshold_pct),
        pass_status: null,
        passed: null,
        grade_label: null,
        score: null,
        display_score: null,
        review_items: []
      });
    }

    a = found.obj;
    rowIndex = found.rowIndex;

    // ownership + scope gate
    if (String(a.user_id || '').trim() !== user_id) return _json({ ok:false, error:'forbidden' }, 403);
    if (String(a.class_id || '').trim() !== String(class_id).trim()) return _json({ ok:false, error:'forbidden' }, 403);
    if (String(a.teacher_quiz_id || '').trim() !== String(teacher_quiz_id).trim()) return _json({ ok:false, error:'forbidden' }, 403);

  } else {
    // latest ended attempt
    const ended = _findLatestEndedAttempt_(ss, teacher_quiz_id, class_id, user_id);
    if (ended.found) {
      a = ended.attempt;
      rowIndex = ended.rowIndex || 0;
      attempt_id = String(a.attempt_id || '').trim();
    }
  }

  // Build bundle (even if no attempt -> UI can still show quiz + class profile)
  const bundle = _buildCandidateAttemptBundle_(ss, quiz, a, class_id, user_id);

  // Base response
  const res = {
    ok: true,
    quiz_meta: bundle.quiz_meta,
    attempt_meta: bundle.attempt_meta,
    my_details: bundle.my_details,

    attempt_id: String(attempt_id || '').trim(),
    status: a ? String(a.status || '').trim().toUpperCase() : '',

    results_release_policy: policy,
    gate_met: !!gateRes.met,
    gate_reason: String(gateRes.reason || ''),
    available_at: String(gateRes.available_at || ''),

    show_results: !!showResults,
    show_review: !!showReview,

    review_allowed: false,
    review_block_reason: { code:'', message:'' },

    // optional score panel (respects score_display_policy)
    score_display_policy: gc.score_display_policy,
    pass_threshold_pct: String(pass_threshold_pct),
    pass_status: null,
    passed: null,
    grade_label: null,
    score: null,
    display_score: null,

    review_items: []
  };

  // ---- No attempt
  if (!a) {
    res.review_block_reason = { code:'NO_ATTEMPT', message:'No submitted attempt found for this quiz.' };
    return _json(res);
  }

  const stU = String(a.status || '').trim().toUpperCase();
  if (stU === 'IN_PROGRESS') {
    res.review_block_reason = { code:'ATTEMPT_IN_PROGRESS', message:'This attempt is still in progress. Submit first to review.' };
    return _json(res);
  }
  if (stU === 'ABANDONED') {
    res.review_block_reason = { code:'ATTEMPT_ABANDONED', message:'This attempt was abandoned and cannot be reviewed.' };
    return _json(res);
  }

  // ---- Review setting gate
  if (!showReview) {
    res.review_block_reason = { code:'REVIEW_DISABLED', message:'Review is disabled for this quiz.' };
    return _json(res);
  }

  // ---- Results-policy gate (review follows the same gate)
  if (!gateRes.met) {
    res.review_block_reason = {
      code: 'REVIEW_LOCKED',
      message: _candidateResultsPendingMessage_(policy, gateRes, quiz),
      available_at: String(gateRes.available_at || '')
    };
    return _json(res);
  }

  // ---- Allowed
  res.review_allowed = true;
  res.review_block_reason = { code:'OK', message:'' };

  // Ensure score exists (used for score panel; review does NOT depend on numeric score)
  const ensured = _ensureAttemptScored_(ss, a, rowIndex);
  const finalAttempt = ensured.attempt || a;
  const scoreObj = ensured.score || null;

  // Apply score visibility rules
  if (showResults && scoreObj && typeof scoreObj === 'object') {
    const sdp = String(gc.score_display_policy || 'PCT_ONLY').trim().toUpperCase();

    const pct = (scoreObj && scoreObj.percent != null) ? Number(scoreObj.percent) : null;
    const raw = (scoreObj && scoreObj.score_marks != null) ? Number(scoreObj.score_marks) : null;
    const total = (scoreObj && scoreObj.total_marks != null) ? Number(scoreObj.total_marks) : null;

    if (pct != null && isFinite(pct)) {
      res.pass_status = (pct >= pass_threshold_pct) ? 'PASS' : 'FAIL';
      res.passed = (res.pass_status === 'PASS');
      res.grade_label = _gradeLabelFromBands_(gc.grade_bands, pct);
    }

    if (sdp !== 'HIDE') {
      res.score = scoreObj;

      if (sdp === 'PCT_ONLY') {
        res.display_score = { percent: (pct == null || !isFinite(pct)) ? null : pct };
      } else if (sdp === 'RAW_ONLY') {
        res.display_score = {
          score_marks: (raw == null || !isFinite(raw)) ? null : raw,
          total_marks: (total == null || !isFinite(total)) ? null : total
        };
      } else {
        res.display_score = {
          score_marks: (raw == null || !isFinite(raw)) ? null : raw,
          total_marks: (total == null || !isFinite(total)) ? null : total,
          percent: (pct == null || !isFinite(pct)) ? null : pct
        };
      }
    }
  }

  // Build REVIEW items (include meta + feedback + rationale safely here)
  const payload = _buildAttemptPayload_(ss, finalAttempt, null, {
    include_meta: true,
    include_feedback: true,
    include_rationale: true
  });

  // chosen/correct come from grading
  const grade = _gradeAttempt_(ss, finalAttempt);
  const byId = {};
  (grade.review_items || []).forEach(x => {
    byId[String(x.quiz_item_id || '').trim()] = x;
  });

  const items = Array.isArray(payload.items) ? payload.items : [];
  res.review_items = items.map(it => {
    const rid = String(it.quiz_item_id || '').trim();
    const g = byId[rid] || {};
    const chosen = String(g.chosen || '').trim();
    const correct = String(g.correct || '').trim();

    // Prefer snapshot rationale if present; fallback to grade rationale
    const rationale = String(it.rationale || '').trim() || String(g.rationale || '').trim();

    return Object.assign({}, it, {
      chosen,
      correct,
      is_correct: (!!chosen && !!correct && chosen === correct),
      rationale
    });
  });

  return _json(res);
}

/* =========================
 * Teacher: attempts.list
 * ========================= */
function _handleTeacherAttemptsList_({ token, body, p }) {
  const gate = _requireTeacher_({ token });
  if (!gate.ok) return _json(gate.payload, gate.code);

  const teacher_id = gate.teacher_id;
  const getS = (k) => String(((p && p[k]) || (body && body[k]) || '')).trim();

  const teacher_quiz_id = getS('teacher_quiz_id');
  const class_id = getS('class_id');
  const status = (getS('status') || 'ANY').toUpperCase();
  const limit = Math.min(Math.max(_toIntDefault_(getS('limit'), 50), 1), 300);

  if (!teacher_quiz_id) return _json({ ok:false, error:'missing_teacher_quiz_id' }, 400);

  const ss = SpreadsheetApp.openById(DB_ID);
  const sh = ss.getSheetByName(SH_ATTEMPTS);
  const headers = _getHeaders_(sh);

  const idx = _indexMap_(headers, [
    'attempt_id','teacher_quiz_id','class_id','user_id','attempt_no',
    'status','started_at','submitted_at','updated_at','score_json','teacher_id'
  ]);

  const lastRow = sh.getLastRow();
  if (lastRow < 2) return _json({ ok: true, count: 0, items: [] });

  const values = sh.getRange(2, 1, lastRow - 1, sh.getLastColumn()).getValues();
  let out = [];

  for (let i = values.length - 1; i >= 0; i--) {
    const r = values[i];

    if (String(r[idx.teacher_quiz_id] || '').trim() !== teacher_quiz_id) continue;
    if (String(r[idx.teacher_id] || '').trim() !== teacher_id) continue;
    if (class_id && String(r[idx.class_id] || '').trim() !== class_id) continue;

    const st = String(r[idx.status] || '').trim().toUpperCase();
    if (status !== 'ANY' && st !== status) continue;

    let score = null;
    try { score = JSON.parse(String(r[idx.score_json] || '') || 'null'); } catch (_) {}

    out.push({
      attempt_id: String(r[idx.attempt_id] || '').trim(),
      teacher_quiz_id: String(r[idx.teacher_quiz_id] || '').trim(),
      class_id: String(r[idx.class_id] || '').trim(),
      user_id: String(r[idx.user_id] || '').trim(),
      attempt_no: String(r[idx.attempt_no] || '').trim(),
      status: st,
      started_at: String(r[idx.started_at] || '').trim(),
      submitted_at: String(r[idx.submitted_at] || '').trim(),
      updated_at: String(r[idx.updated_at] || '').trim(),
      score
    });

    if (out.length >= limit) break;
  }

  return _json({ ok: true, count: out.length, items: out });
}

