  const payload = _buildAttemptPayload_(ss, finalAttempt);
  const grade = _gradeAttempt_(ss, finalAttempt);

  payload.score = scoreObj || grade.score;
  payload.review_items = grade.review_items;

  return _json({ ok: true, ...payload });
}

/* ============================================================
 * Helpers (runner-local)
 * ============================================================ */

function _ta_shuffle_(arr) {
  const a = (arr || []).slice();
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    const tmp = a[i]; a[i] = a[j]; a[j] = tmp;
  }
  return a;
}

function _buildOptionMap_(snap, shuffleOptions) {
  const letters = ['A','B','C','D','E','F'];
  const has = [];
  letters.forEach(L => {
    const v = String(snap['snap_option_' + L.toLowerCase()] || '').trim();
    if (v) has.push(L);
  });

  const display = ['A','B','C','D','E','F'].slice(0, has.length);
  const order = shuffleOptions ? _ta_shuffle_(has) : has.slice();

  const map = {};
  for (let i = 0; i < display.length; i++) map[display[i]] = order[i];
  return map;
}

function _renderItemsForClient_(snapById, attemptItems, opts) {
  const out = [];
  const o = opts || {};
  const include_meta = !!o.include_meta;           // topic, difficulty
  const include_feedback = !!o.include_feedback;   // fb per option
  const include_rationale = !!o.include_rationale; // rationale + rationale_img

  (attemptItems || []).forEach(ai => {
    const snap = snapById[ai.quiz_item_id];
    if (!snap) return;

    const opt_map = ai.opt_map || {};
    const optsArr = [];

    ['A','B','C','D','E','F'].forEach(dk => {
      const ok = opt_map[dk]; // original letter (A-F)
      if (!ok) return;

      const text = String(snap['snap_option_' + ok.toLowerCase()] || '').trim();
      if (!text) return;

      const opt = { key: dk, orig: ok, text };

      if (include_feedback) {
        opt.feedback = String(snap['snap_fb_' + ok.toLowerCase()] || '').trim();
      }

      optsArr.push(opt);
    });

    const item = {
      quiz_item_id: ai.quiz_item_id,
      position: ai.position,
      marks: ai.marks || 1,
      subject: snap.snap_subject || '',
      stem: snap.snap_stem || '',
      options: optsArr
    };

    if (include_meta) {
      item.topic = String(snap.snap_topic || '').trim();
      item.difficulty = String(snap.snap_difficulty || '').trim();
    }

    if (include_rationale) {
      item.rationale = String(snap.snap_rationale || '').trim();
      item.rationale_img = String(snap.snap_rationale_img || '').trim();
    }

    out.push(item);
  });

  return out;
}

function _buildAttemptPayload_(ss, attempt, snapshotsOptional, opts) {
  const teacher_quiz_id = String(attempt.teacher_quiz_id || '').trim();

  const itemsArr = _parseJsonSafe_(attempt.items_json, []) || [];
  const answers = _parseJsonSafe_(attempt.answers_json, {}) || {};
  const flags = _parseJsonSafe_(attempt.flags_json, {}) || {};

  const snaps = snapshotsOptional || _getQuizItemsSnapshots_(ss, teacher_quiz_id);
  const snapById = {};
  snaps.forEach(s => snapById[s.quiz_item_id] = s);

  // Default remains runner-safe (no meta/feedback/rationale)
  const items = _renderItemsForClient_(snapById, itemsArr, opts);

  let due_ms = null;
  const due_at = String(attempt.due_at || '').trim();
  if (due_at) {
    const ms = Date.parse(due_at);
    if (!isNaN(ms)) due_ms = ms;
  }

  return { attempt, items, answers, flags, due_ms };
}

function _candidateResultsPendingMessage_(policy, gateRes, quizObj) {
  const pol = String(policy || 'IMMEDIATE').toUpperCase();

  if (pol === 'AFTER_CLOSE') {
    if (gateRes.reason === 'MISSING_CLOSE_AT' || gateRes.reason === 'INVALID_CLOSE_AT') {
      return "Results are not available because the quiz close time is missing.";
    }
    const closeAt = String((quizObj && quizObj.close_at) || gateRes.available_at || '').trim();
    return closeAt
      ? `Results will be available after the quiz closes (${closeAt}).`
      : "Results will be available after the quiz closes.";
  }

  if (pol === 'MANUAL') {
    return "Your attempt has been submitted. Your teacher will release results and feedback when ready.";
  }

  return "Your attempt has been submitted.";
}

/**
 * Runner-safe results metadata pack (NO score, NO review_items).
 */
function _candidateResultsMetaPack_(quizObj, nowMs) {
  const policy = _normalizeResultsPolicy_(quizObj && quizObj.results_release_policy);
  const gateRes = _computeResultsGatePolicy_(quizObj || {}, nowMs);

  const showResults = _getShowResultsBool_(quizObj || {});
  const showReview  = _toBoolDefault_(quizObj && quizObj.show_review, false);

  const anyOutput = (showResults || showReview);

  const out = {
    policy,
    gate_met: !!gateRes.met,
    gate_reason: String(gateRes.reason || ''),
    available_at: String(gateRes.available_at || ''),
    show_results: !!showResults,
    show_review: !!showReview,
    any_output: !!anyOutput,
    results_pending: false,
    message: ''
  };

  if (!gateRes.met) {
    out.results_pending = true;
    out.message = _candidateResultsPendingMessage_(policy, gateRes, quizObj || {});
    return out;
  }

  if (!anyOutput) {
    out.results_pending = true;
    out.message = "Results and review are hidden for this quiz.";
    return out;
  }

  out.results_pending = false;
  out.message = "Results available.";
  return out;
}

function _gradeLabelFromBands_(gradeBandsObj, percent) {
  const p0 = Number(percent);
  const p = isFinite(p0) ? Math.max(0, Math.min(100, p0)) : 0;

  const bands = (gradeBandsObj && Array.isArray(gradeBandsObj.bands)) ? gradeBandsObj.bands : [];
  if (!bands.length) return '';

  // bands are expected sorted ascending by min_pct already (from _normalizeGradingConfig_)
  let label = String(bands[0].label || '').trim();

  for (let i = 0; i < bands.length; i++) {
    const b = bands[i] || {};
    const min = Number(b.min_pct);
    const lab = String(b.label || '').trim();
    if (!lab) continue;
    if (!isFinite(min)) continue;
    if (p >= min) label = lab;
    else break; // because sorted ascending
  }

  return label;
}

function _passThresholdStrict_(quizObj) {
  // Use stored pass_threshold_pct ONLY. Do not derive from bands here.
  // Falls back to 50 if missing/invalid.
  let n = null;

  // Prefer global _parsePct_ if available (defined in File 1)
  if (typeof _parsePct_ === 'function') {
    n = _parsePct_(quizObj && quizObj.pass_threshold_pct);
  } else {
    // local fallback parsing
    const s = String((quizObj && quizObj.pass_threshold_pct) ?? '').trim();
    if (s) {
      const x = Number(s);
      if (isFinite(x)) n = Math.max(0, Math.min(100, Math.round(x * 100) / 100));
    }
  }

  if (n == null) {
    if (typeof PASS_THRESHOLD_DEFAULT !== 'undefined') return PASS_THRESHOLD_DEFAULT; // from File 1 (50)
    return 50;
  }
  return n;
}

function _ensureAttemptScored_(ss, attempt, rowIndexMaybe) {
  let scoreObj = _parseJsonSafe_(attempt.score_json, null);
  if (scoreObj && typeof scoreObj === 'object') {
    return { attempt, score: scoreObj, updated: false };
  }

  let rowIndex = rowIndexMaybe;
  if (!rowIndex) {
    const found = _attemptGetById_(ss, String(attempt.attempt_id || '').trim());
    if (!found.found) return { attempt, score: null, updated: false };
    rowIndex = found.rowIndex;
    attempt = found.obj;

    scoreObj = _parseJsonSafe_(attempt.score_json, null);
    if (scoreObj && typeof scoreObj === 'object') return { attempt, score: scoreObj, updated: false };
  }

  const grade = _gradeAttempt_(ss, attempt);
  const headers = _attemptHeaders_(_attemptSheet_(ss));

  const patch = Object.assign({
    updated_at: _iso(new Date())
  }, _setScorePatch_(headers, grade.score));

  _attemptUpdateByRow_(ss, rowIndex, patch);

  const refreshed = _attemptGetById_(ss, String(attempt.attempt_id || '').trim());
  const fixed = refreshed.found ? refreshed.obj : attempt;

  return { attempt: fixed, score: grade.score, updated: true };
}

/* =========================
 * Time tracking helper
 * ========================= */
function _ta_activeTimePatch_(attempt, nowMs) {
  if (String(attempt.status || '').toUpperCase() !== 'IN_PROGRESS') {
    return { changed: false, patch: {} };
  }

  const lastMs = _parseIsoMs_(attempt.updated_at) || null;
  if (!lastMs) return { changed: false, patch: {} };

  const deltaSec = Math.floor((nowMs - lastMs) / 1000);
  if (deltaSec <= 0) return { changed: false, patch: {} };

  const currentTaken = _toIntDefault_(attempt.time_taken_s, 0);
  const durationSec = _toIntDefault_(attempt.duration_minutes, 0) * 60;

  const cap = (durationSec > 0) ? durationSec : Number.POSITIVE_INFINITY;
  const newTaken = Math.min(currentTaken + deltaSec, cap);

  return {
    changed: (newTaken !== currentTaken),
    patch: {
      time_taken_s: String(newTaken),
      updated_at: _iso(new Date(nowMs))
    }
  };
}

/* =========================
 * Attempts sheet IO
 * ========================= */
function _attemptSheet_(ss) {
  return ss.getSheetByName(SH_ATTEMPTS);
}
function _attemptHeaders_(sh) {
  return _getHeaders_(sh);
}

function _attemptAppend_(ss, obj) {
  const sh = _attemptSheet_(ss);
  const headers = _attemptHeaders_(sh);

  // candidate fields: prefer candidate_fields_json, fallback to custom_fields_json
  const hasCandidate = headers.indexOf('candidate_fields_json') !== -1;
  const hasCustom    = headers.indexOf('custom_fields_json') !== -1;

  if (hasCandidate && !('candidate_fields_json' in obj) && ('custom_fields_json' in obj)) {
    obj.candidate_fields_json = obj.custom_fields_json;
  }
  if (hasCustom && !('custom_fields_json' in obj) && ('candidate_fields_json' in obj)) {
    obj.custom_fields_json = obj.candidate_fields_json;
  }

  const row = headers.map(h => (h in obj) ? obj[h] : '');
  sh.appendRow(row);
}

function _attemptGetById_(ss, attempt_id) {
  const sh = _attemptSheet_(ss);
  const headers = _attemptHeaders_(sh);

  const idx = headers.indexOf('attempt_id');
  if (idx === -1) throw new Error('Missing header: attempt_id');

  const lastRow = sh.getLastRow();
  if (lastRow < 2) return { found: false };

  const vals = sh.getRange(2, idx + 1, lastRow - 1, 1).getValues();
  for (let i = 0; i < vals.length; i++) {
    if (String(vals[i][0] || '').trim() === attempt_id) {
      const rowIndex = i + 2;
      const row = sh.getRange(rowIndex, 1, 1, headers.length).getValues()[0];
      return { found: true, rowIndex, obj: _rowToObj_(headers, row) };
    }
  }
  return { found: false };
}

function _attemptUpdateByRow_(ss, rowIndex, patch) {
  const sh = _attemptSheet_(ss);
  const headers = _attemptHeaders_(sh);
  const row = sh.getRange(rowIndex, 1, 1, headers.length).getValues()[0];
  const obj = _rowToObj_(headers, row);
  Object.keys(patch || {}).forEach(k => obj[k] = patch[k]);
  const outRow = headers.map(h => (h in obj) ? obj[h] : '');
  sh.getRange(rowIndex, 1, 1, headers.length).setValues([outRow]);
}

function _findInProgressAttempt_(ss, teacher_quiz_id, class_id, user_id) {
  const sh = _attemptSheet_(ss);
  const headers = _attemptHeaders_(sh);

  const idx = _indexMap_(headers, ['attempt_id','teacher_quiz_id','class_id','user_id','status','updated_at']);

  const lastRow = sh.getLastRow();
  if (lastRow < 2) return { found: false };

  const values = sh.getRange(2, 1, lastRow - 1, sh.getLastColumn()).getValues();

  let best = null, bestRow = -1, bestMs = -1;

  for (let i = 0; i < values.length; i++) {
    const r = values[i];

    if (String(r[idx.teacher_quiz_id] || '').trim() !== String(teacher_quiz_id).trim()) continue;
    if (String(r[idx.class_id] || '').trim() !== String(class_id).trim()) continue;
    if (String(r[idx.user_id] || '').trim() !== String(user_id).trim()) continue;

    const st = String(r[idx.status] || '').trim().toUpperCase();
    if (st !== 'IN_PROGRESS') continue;

    const ms = _parseIsoMs_(String(r[idx.updated_at] || '').trim()) || 0;
    if (ms > bestMs) {
      bestMs = ms;
      bestRow = i + 2;
      best = _rowToObj_(headers, r);
    }
  }

  if (!best) return { found: false };
  best._rowIndex = bestRow;
  return { found: true, rowIndex: bestRow, attempt: best };
}

function _findLatestEndedAttempt_(ss, teacher_quiz_id, class_id, user_id) {
  const sh = _attemptSheet_(ss);
