  let best = null, bestRow = -1, bestMs = -1;

  for (let i = 0; i < values.length; i++) {
    const r = values[i];

    if (String(r[idx.teacher_quiz_id] || '').trim() !== String(teacher_quiz_id).trim()) continue;
    if (String(r[idx.class_id] || '').trim() !== String(class_id).trim()) continue;
    if (String(r[idx.user_id] || '').trim() !== String(user_id).trim()) continue;

    const st = String(r[idx.status] || '').trim().toUpperCase();
    if (!st || st === 'IN_PROGRESS' || st === 'ABANDONED') continue;

    const ms =
      _parseIsoMs_(String(r[idx.submitted_at] || '').trim()) ||
      _parseIsoMs_(String(r[idx.updated_at] || '').trim()) ||
      _parseIsoMs_(String(r[idx.started_at] || '').trim()) ||
      0;

    if (ms > bestMs) {
      bestMs = ms;
      bestRow = i + 2;
      best = _rowToObj_(headers, r);
    }
  }

  if (!best) return { found:false };
  best._rowIndex = bestRow;
  return { found:true, rowIndex: bestRow, attempt: best };
}

function _countUserAttempts_(ss, teacher_quiz_id, class_id, user_id) {
  const sh = _attemptSheet_(ss);
  const headers = _attemptHeaders_(sh);

  const idx = _indexMap_(headers, ['teacher_quiz_id','class_id','user_id','status']);

  const lastRow = sh.getLastRow();
  if (lastRow < 2) return 0;

  const values = sh.getRange(2, 1, lastRow - 1, sh.getLastColumn()).getValues();
  let n = 0;

  for (let i = 0; i < values.length; i++) {
    const r = values[i];

    if (String(r[idx.teacher_quiz_id] || '').trim() !== String(teacher_quiz_id).trim()) continue;
    if (String(r[idx.class_id] || '').trim() !== String(class_id).trim()) continue;
    if (String(r[idx.user_id] || '').trim() !== String(user_id).trim()) continue;

    const st = String(r[idx.status] || '').trim().toUpperCase();
    if (st === 'ABANDONED') continue;

    n++;
  }

  return n;
}

// =========================
// Expiry helper (due_at OR close_at)
// - Ends IN_PROGRESS if now > min(due_at, close_at)
// - Caps time_taken_s patch to the stop moment (prevents huge jumps)
// - Status: TIMED_OUT (due) or CLOSED (close)
// =========================
function _maybeExpireAttempt_(ss, attempt, quizObj, nowMs, rowIndexMaybe) {
  const st = String(attempt && attempt.status || '').trim().toUpperCase();
  if (st !== 'IN_PROGRESS') return { changed:false, attempt };

  const dueMs   = _parseIsoMs_(String(attempt.due_at || '').trim());                  // may be null
  const closeMs = _parseIsoMs_(String((quizObj && quizObj.close_at) || '').trim());   // may be null

  // No stop condition
  if (dueMs == null && closeMs == null) return { changed:false, attempt };

  const stopMs =
    (dueMs != null && closeMs != null) ? Math.min(dueMs, closeMs) :
    (dueMs != null) ? dueMs : closeMs;

  if (stopMs == null || nowMs <= stopMs) return { changed:false, attempt };

  // Decide why we expired
  const reason = (dueMs != null && stopMs === dueMs) ? 'DUE' : 'CLOSE';
  const statusOut = (reason === 'DUE') ? 'TIMED_OUT' : 'CLOSED';

  // Read fresh row (avoid scan if rowIndex provided)
  let rowIndex = rowIndexMaybe || 0;
  let fresh = attempt;

  try {
    if (rowIndex > 0) {
      const sh = _attemptSheet_(ss);
      const headers = _attemptHeaders_(sh);
      const row = sh.getRange(rowIndex, 1, 1, headers.length).getValues()[0];
      fresh = _rowToObj_(headers, row);
    } else {
      const found = _attemptGetById_(ss, String(attempt.attempt_id || '').trim());
      if (!found.found) return { changed:false, attempt };
      rowIndex = found.rowIndex;
      fresh = found.obj;
    }
  } catch (_) {}

  // Cap elapsed-time patch to stop moment (prevents “hours added after close”)
  const effectiveMs = stopMs;
  const timePatch = _ta_activeTimePatch_(fresh, effectiveMs);
  if (timePatch.changed) {
    _attemptUpdateByRow_(ss, rowIndex, timePatch.patch);
    const again = _attemptGetById_(ss, String(fresh.attempt_id || '').trim());
    if (again.found) fresh = again.obj;
  }

  // Grade + finalize
  const grade = _gradeAttempt_(ss, fresh);
  const headers2 = _attemptHeaders_(_attemptSheet_(ss));
  const stopIso = _iso(new Date(effectiveMs));

  const patch = Object.assign({
    status: statusOut,
    submitted_at: stopIso,
    updated_at: stopIso,
    time_taken_s: String(_toIntDefault_(fresh.time_taken_s, 0))
  }, _setScorePatch_(headers2, grade.score));

  _attemptUpdateByRow_(ss, rowIndex, patch);

  const refreshed = _attemptGetById_(ss, String(fresh.attempt_id || '').trim());
  return {
    changed:true,
    attempt: refreshed.found ? refreshed.obj : fresh,
    status: statusOut,
    reason
  };
}

function _maybeTimeoutAttempt_(ss, attempt) {
  const st = String(attempt.status || '').trim().toUpperCase();
  if (st !== 'IN_PROGRESS') return { changed:false, attempt };

  const due_at = String(attempt.due_at || '').trim();
  if (!due_at) return { changed:false, attempt };

  const dueMs = Date.parse(due_at);
  if (isNaN(dueMs)) return { changed:false, attempt };

  if (Date.now() <= dueMs) return { changed:false, attempt };

  // refresh from sheet (answers might have changed)
  const found = _attemptGetById_(ss, String(attempt.attempt_id || '').trim());
  if (!found.found) return { changed:false, attempt };

  let fresh = found.obj;

  // apply elapsed patch before grading
  const nowMs = Date.now();
  const timePatch = _ta_activeTimePatch_(fresh, nowMs);
  if (timePatch.changed) {
    _attemptUpdateByRow_(ss, found.rowIndex, timePatch.patch);
    const fresh2 = _attemptGetById_(ss, fresh.attempt_id);
    fresh = fresh2.found ? fresh2.obj : fresh;
  }

  const grade = _gradeAttempt_(ss, fresh);
  const headers = _attemptHeaders_(_attemptSheet_(ss));
  const nowIso = _iso(new Date(nowMs));

  const patch = Object.assign({
    status: 'TIMED_OUT',
    submitted_at: nowIso,
    updated_at: nowIso
  }, _setScorePatch_(headers, grade.score));

  _attemptUpdateByRow_(ss, found.rowIndex, patch);

  const fresh3 = _attemptGetById_(ss, String(fresh.attempt_id || '').trim());
  return { changed:true, attempt: fresh3.found ? fresh3.obj : fresh, grade };
}

/* =========================
 * Grading
 * ========================= */
function _gradeAttempt_(ss, attempt) {
  const teacher_quiz_id = String(attempt.teacher_quiz_id || '').trim();

  const snaps = _getQuizItemsSnapshots_(ss, teacher_quiz_id);
  const snapById = {};
  snaps.forEach(s => snapById[s.quiz_item_id] = s);

  const itemsArr = _parseJsonSafe_(attempt.items_json, []) || [];
  const answers = _parseJsonSafe_(attempt.answers_json, {}) || {};

  let total = 0;
  let score = 0;

  const review_items = [];

  for (let i = 0; i < itemsArr.length; i++) {
    const ai = itemsArr[i];
    const snap = snapById[ai.quiz_item_id];
    if (!snap) continue;

    const marks = _toIntDefault_(ai.marks, _toIntDefault_(snap.snap_marks, 1));
    total += marks;

    const opt_map = ai.opt_map || {};
    const chosenDisplay = String(answers[ai.quiz_item_id] || '').trim().toUpperCase();
    const chosenOrig = chosenDisplay ? String(opt_map[chosenDisplay] || '').trim().toUpperCase() : '';

    const correctOrig = String(snap.snap_correct || '').trim().toUpperCase();
    const correctDisplay = _invertMapFindKey_(opt_map, correctOrig);

    const correct = (chosenOrig && chosenOrig === correctOrig);
    if (correct) score += marks;

    review_items.push({
      quiz_item_id: ai.quiz_item_id,
      chosen: chosenDisplay || '',
      correct: correctDisplay || '',
      stem: String(snap.snap_stem || ''),
      rationale: String(snap.snap_rationale || '')
    });
  }

  const percent = total ? Math.round((score / total) * 100) : 0;

  let timed_out = false;
  const due_at = String(attempt.due_at || '').trim();
  if (due_at) {
    const dueMs = Date.parse(due_at);
    if (!isNaN(dueMs) && Date.now() > dueMs) timed_out = true;
  }

  return {
    timed_out,
    score: { total_marks: total, score_marks: score, percent },
    review_items
  };
}

function _setScorePatch_(headers, gradeScore) {
  const patch = { score_json: JSON.stringify(gradeScore || {}) };

  if (headers.indexOf('score_raw') !== -1)   patch.score_raw = String(gradeScore.score_marks ?? '');
  if (headers.indexOf('score_total') !== -1) patch.score_total = String(gradeScore.total_marks ?? '');
  if (headers.indexOf('score_pct') !== -1)   patch.score_pct = String(gradeScore.percent ?? '');

  return patch;
}

function _invertMapFindKey_(map, orig) {
  const want = String(orig || '').trim().toUpperCase();
  const keys = ['A','B','C','D','E','F'];
  for (let i = 0; i < keys.length; i++) {
    const k = keys[i];
    const v = String(map[k] || '').trim().toUpperCase();
    if (v === want) return k;
  }
  return '';
}

