// Drive template file IDs (EDIT: these are your saved HTML files in Drive)
const TA_EMAIL_TPL_REQUEST_RECEIVED = '1CaQHHgarRr_z0_8jfpI2kgKD0VD-WW4G';
const TA_EMAIL_TPL_APPROVED         = '1vW2Iwabw50IGJKiUCR7SKXAByDmTzFNo';
const TA_EMAIL_TPL_DISABLED         = '16L5oyz5T0jFB3qpN-m3Oy-wy7f39p-3j';

// ====== Shared renderer (copied from Auth, unchanged) ======
function _renderEmailFromDrive_(fileId, data){
  if (!fileId || String(fileId).indexOf('REPLACE_WITH') !== -1) {
    throw new Error('missing_template_id');
  }

  var file = DriveApp.getFileById(fileId);

  // Force UTF-8 decode so emojis and non-ASCII characters render correctly
  var html = file.getBlob().getDataAsString('UTF-8');

  // Ensure template declares UTF-8 (defensive)
  if (!/<meta\s+charset=/i.test(html)) {
    if (/<head(\s[^>]*)?>/i.test(html)) {
      html = html.replace(/<head(\s[^>]*)?>/i, function(m){
        return m + '\n<meta charset="UTF-8">';
      });
    } else {
      html = '<meta charset="UTF-8">\n' + html;
    }
  }

  if (!data) return html;

  Object.keys(data).forEach(function(key){
    var val = (data[key] == null ? '' : String(data[key]));
    var pattern = new RegExp('{{\\s*' + key + '\\s*}}', 'g');
    html = html.replace(pattern, val);
  });

  // remove any unreplaced placeholders
  html = html.replace(/{{\s*[\w.]+\s*}}/g, '');

  return html;
}

// ====== Shared sender wrapper (same pattern as Auth) ======
function _qaSendEmail_(args){
  try{
    var to       = String(args.to || '').trim();
    var subject  = String(args.subject || '').trim();
    var body     = String(args.body || '');
    var htmlBody = args.htmlBody;
    var name     = String(args.name || TA_BRAND_NAME || '').trim();

    if(!to || !subject) return;

    var replyTo  = String(args.replyTo || TA_SUPPORT_EMAIL || '').trim();

    // Optional alias “from” only if verified
    var fromWanted = String(args.from || TA_FROM_EMAIL || '').trim();
    var fromSafe = '';

    if (fromWanted) {
      try{
        var aliases = GmailApp.getAliases() || [];
       var ok = aliases.map(String).map(function(s){ return String(s).toLowerCase(); })
  .indexOf(fromWanted.toLowerCase()) >= 0;
        if (ok) fromSafe = fromWanted;
        else Logger.log('Alias not verified; skipping from=' + fromWanted);
      } catch(e){
        Logger.log('Could not read Gmail aliases; skipping from. Err=' + e);
      }
    }

    var opts = {};
    if (name) opts.name = name;
    if (replyTo) opts.replyTo = replyTo;
    if (fromSafe) opts.from = fromSafe;
    if (htmlBody) opts.htmlBody = String(htmlBody);

    GmailApp.sendEmail(to, subject, body, opts);
    return { ok:true };

  } catch(e){
    Logger.log('_qaSendEmail_ failed: ' + e);
    return { ok:false, error:String(e) };
  }
}

function _escapeHtml_(s){
  s = String(s == null ? '' : s);
  return s
    .replace(/&/g,'&amp;')
    .replace(/</g,'&lt;')
    .replace(/>/g,'&gt;')
    .replace(/"/g,'&quot;')
    .replace(/'/g,'&#39;');
}

